export enum Gender {
  MALE = 'MALE',
  FEMALE = 'FEMALE',
  OTHER = 'OTHER'
}

export interface PayoutMethods {
  solana?: string;
  ethereum?: string;
  monad?: string;
  base?: string;
  sui?: string;
  polygon?: string;
  bitcoin?: string;
  paypal?: string;
}

export interface User {
  id: string;
  fullName: string;
  username: string;
  email: string;
  avatar?: string;
  gender: Gender;
  birthDate: string;
  location?: { lat: number; lng: number; address: string };
  status: string;
  points: number;
  listingsCount: number;
  walletBalance: number;
  currencyPreference: string;
  trustScore: number;
  badges: string[];
  subscription?: {
    tier: string;
    expiresAt: string;
  };
  payoutMethods: PayoutMethods;
  blockedUsers: string[];
  isVerified?: boolean;
}

export interface SubscriptionPlan {
  id: string;
  name: string;
  description: string;
  isSpecial?: boolean;
  pricing: {
    daily: number;
    monthly: number;
    yearly: number;
  };
  features: string[];
}

export enum ListingType {
  RENT = 'RENT'
}

export enum CurrencyType {
  CRYPTO = 'CRYPTO',
  LOCAL = 'LOCAL'
}

export enum RentalPeriod {
  DAY = 'DAY',
  WEEK = 'WEEK',
  MONTH = 'MONTH',
  YEAR = 'YEAR'
}

export interface Listing {
  id: string;
  ownerId: string;
  ownerName: string;
  ownerUsername: string;
  ownerAvatar?: string;
  title: string;
  description: string;
  type: ListingType;
  price: number;
  currency: string;
  currencyType: CurrencyType;
  payoutMethod: 'PAYPAL' | 'CRYPTO';
  payoutAddress: string;
  cryptoCurrency?: string;
  category: string;
  location: { lat: number; lng: number; address: string };
  images: string[];
  video?: string;
  createdAt: string;
  rentalPeriod: RentalPeriod;
  views: number;
  likes: number;
  rating: number;
  isAiApproved: boolean;
  unavailableDates: string[];
  status: 'DRAFT' | 'AI_REVIEW' | 'PUBLISHED' | 'REJECTED';
  visibility: 'PUBLIC' | 'PRIVATE';
  review_state: 'PENDING' | 'APPROVED' | 'REJECTED';
  published_at: string | null;
  updated_at: string;
  is_deleted: boolean;
}

export interface GroupChat {
  id: string;
  name: string;
  description: string;
  image: string;
  adminId: string;
  members: string[];
}

import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent, estimateRentalPrice } from '../services/geminiService';
import { Camera, Compass, MapPinned, Award, Sparkles, Loader2, CheckCircle, ShieldCheck, Zap, Wallet, CreditCard, ChevronRight, AlertTriangle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CRYPTO_CURRENCIES = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | undefined>(undefined);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [payoutMethod, setPayoutMethod] = useState<'CRYPTO' | 'PAYPAL'>('PAYPAL');
  const [selectedCrypto, setSelectedCrypto] = useState(CRYPTO_CURRENCIES[0]);
  const [payoutAddress, setPayoutAddress] = useState('');

  const handleEstimate = async () => {
    if (!title || !description) return;
    setEstimating(true);
    const est = await estimateRentalPrice(title, description, user.currencyPreference || 'USD');
    setPrice(est.toString());
    setEstimating(false);
  };

  const handlePublish = async () => {
    if (images.length < 2) {
      alert(lang === 'ar' ? 'يجب رفع صورتين على الأقل' : 'Please upload at least 2 images');
      return;
    }
    setLoading(true);
    const moderation = await checkListingContent(title, description);
    if (moderation.status === 'REJECTED') {
      alert(moderation.reason);
      setLoading(false);
      return;
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: payoutMethod === 'CRYPTO' ? CurrencyType.CRYPTO : CurrencyType.LOCAL,
      payoutMethod,
      cryptoCurrency: payoutMethod === 'CRYPTO' ? selectedCrypto : undefined,
      payoutAddress,
      category,
      location: user.location || { address: 'Local', lat: 0, lng: 0 },
      images,
      video,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: true,
      unavailableDates: [],
      status: 'PUBLISHED',
      visibility: 'PUBLIC',
      review_state: 'APPROVED',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(6);
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto p-10 bg-white dark:bg-gray-900 rounded-[4.5rem] my-10 border dark:border-gray-800 shadow-2xl animate-in zoom-in-95">
      <div className="flex gap-2 mb-12">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      <div className="mb-8 p-4 bg-red-50 dark:bg-red-900/10 border-2 border-red-100 dark:border-red-900/20 rounded-3xl flex items-center gap-3">
        <AlertTriangle className="text-red-600 shrink-0" size={24} />
        <p className="text-xs font-black text-red-700 dark:text-red-400 uppercase tracking-tighter">
          {t.rentalsOnly}
        </p>
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase italic">{t.step} 1: {lang === 'ar' ? 'الصور والفيديو' : 'Visuals'}</h2>
            <p className="text-xs text-gray-400 mt-2">{lang === 'ar' ? 'ارفع من 2 إلى 5 صور' : 'Upload 2-5 high quality photos'}</p>
          </div>
          <div className="grid grid-cols-3 gap-4">
            {images.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-[2rem] overflow-hidden group">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-2 right-2 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">×</button>
              </div>
            ))}
            {images.length < 5 && (
              <button onClick={() => imageInputRef.current?.click()} className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[2rem] border-4 border-dashed border-gray-200 dark:border-gray-700 flex flex-col items-center justify-center text-gray-400 hover:text-brand transition-all">
                <Camera size={32} />
                <span className="text-[10px] font-black uppercase mt-1">{images.length}/5</span>
                <input type="file" ref={imageInputRef} multiple className="hidden" accept="image/*" onChange={e => {
                  const files = Array.from(e.target.files || []);
                  files.slice(0, 5 - images.length).forEach((f: File) => {
                    const r = new FileReader();
                    r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
                    r.readAsDataURL(f);
                  });
                }} />
              </button>
            )}
          </div>
          <div className="bg-gray-50 dark:bg-gray-800 p-6 rounded-3xl">
             <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">{lang === 'ar' ? 'فيديو (اختياري)' : 'Video (Optional)'}</h3>
             <input type="file" accept="video/*" className="text-xs text-gray-400 font-bold" onChange={e => {
               const file = e.target.files?.[0];
               if (file) {
                 const r = new FileReader();
                 r.onload = (ev) => setVideo(ev.target?.result as string);
                 r.readAsDataURL(file);
               }
             }} />
          </div>
          <button onClick={() => setStep(2)} disabled={images.length < 2} className={`w-full py-6 rounded-[2.5rem] font-black uppercase shadow-xl transition-all ${images.length >= 2 ? 'bg-brand text-white' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}>Next Step</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">{t.step} 2: {lang === 'ar' ? 'المواصفات' : 'Details'}</h2>
          <input type="text" placeholder={lang === 'ar' ? 'عنوان المنتج' : 'Item Title'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none font-bold focus:ring-2 focus:ring-brand" />
          <textarea placeholder={t.description} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none h-40 font-medium focus:ring-2 focus:ring-brand" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none font-bold focus:ring-2 focus:ring-brand appearance-none">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 rounded-[2rem] font-bold text-gray-400">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-lg">Continue</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">{t.step} 3: {t.payoutMethod}</h2>
          <div className="grid grid-cols-2 gap-4">
             <button onClick={() => setPayoutMethod('PAYPAL')} className={`p-8 rounded-[3rem] border-4 flex flex-col items-center gap-4 transition-all ${payoutMethod === 'PAYPAL' ? 'border-brand bg-brand/5' : 'border-gray-50 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-800/50'}`}>
                <CreditCard size={32} className={payoutMethod === 'PAYPAL' ? 'text-brand' : 'text-gray-400'} />
                <span className={`text-xs font-black uppercase ${payoutMethod === 'PAYPAL' ? 'text-brand' : 'text-gray-400'}`}>PayPal</span>
             </button>
             <button onClick={() => setPayoutMethod('CRYPTO')} className={`p-8 rounded-[3rem] border-4 flex flex-col items-center gap-4 transition-all ${payoutMethod === 'CRYPTO' ? 'border-brand bg-brand/5' : 'border-gray-50 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-800/50'}`}>
                <Wallet size={32} className={payoutMethod === 'CRYPTO' ? 'text-brand' : 'text-gray-400'} />
                <span className={`text-xs font-black uppercase ${payoutMethod === 'CRYPTO' ? 'text-brand' : 'text-gray-400'}`}>{t.crypto}</span>
             </button>
          </div>

          {payoutMethod === 'CRYPTO' && (
            <div className="space-y-4 animate-in fade-in">
               <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                  {CRYPTO_CURRENCIES.map(c => (
                    <button key={c} onClick={() => setSelectedCrypto(c)} className={`px-5 py-2 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all ${selectedCrypto === c ? 'bg-brand text-white' : 'bg-gray-100 dark:bg-gray-800 text-gray-400'}`}>{c}</button>
                  ))}
               </div>
            </div>
          )}

          <div className="space-y-2">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">{t.payoutAddress}</h3>
            <input type="text" value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} placeholder={payoutMethod === 'PAYPAL' ? 'email@example.com' : '0x... or Address'} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none font-bold border-2 border-transparent focus:border-brand transition-all" />
          </div>

          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 rounded-[2rem] font-bold text-gray-400">Back</button>
            <button onClick={() => setStep(4)} disabled={!payoutAddress} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-lg">Next</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">{t.step} 4: {lang === 'ar' ? 'السعر والمدة' : 'Pricing'}</h2>
          <div className="bg-gray-50 dark:bg-gray-800 p-10 rounded-[4rem] text-center border dark:border-gray-700">
             <div className="flex items-center justify-center gap-2 mb-8">
                <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-40 bg-transparent border-b-4 border-brand text-center text-5xl font-black dark:text-white outline-none" placeholder="0.00" />
                <span className="font-black text-brand text-xl">{user.currencyPreference || 'USD'}</span>
             </div>
             <button onClick={handleEstimate} disabled={estimating} className="px-10 py-4 bg-brand/10 text-brand rounded-full font-black text-xs uppercase flex items-center gap-2 mx-auto hover:bg-brand hover:text-white transition-all shadow-sm">
                {estimating ? <Loader2 className="animate-spin" size={16} /> : <Zap size={16} />} 
                {t.aiPriceEstimate}
             </button>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
             {Object.values(RentalPeriod).map(p => (
               <button key={p} onClick={() => setPeriod(p)} className={`py-4 rounded-2xl font-black text-[10px] uppercase transition-all ${period === p ? 'bg-brand text-white shadow-xl scale-105' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>{t.periods[p]}</button>
             ))}
          </div>
          <div className="flex gap-4">
            <button onClick={() => setStep(3)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 rounded-[2rem] font-bold text-gray-400">Back</button>
            <button onClick={() => setStep(5)} disabled={!price} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-lg">Final Review</button>
          </div>
        </div>
      )}

      {step === 5 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-brand/10 text-brand rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl shadow-brand/10">
            <ShieldCheck size={48} />
          </div>
          <h2 className="text-3xl font-black dark:text-white uppercase italic">{t.finalizeAndSeal}</h2>
          <div className="bg-gray-50 dark:bg-gray-800 p-8 rounded-[3rem] text-left space-y-4">
             <div className="flex justify-between border-b dark:border-gray-700 pb-2">
                <span className="text-[10px] font-black text-gray-400 uppercase">{lang === 'ar' ? 'السلعة' : 'Item'}</span>
                <span className="text-xs font-black dark:text-white">{title}</span>
             </div>
             <div className="flex justify-between border-b dark:border-gray-700 pb-2">
                <span className="text-[10px] font-black text-gray-400 uppercase">{lang === 'ar' ? 'السعر' : 'Price'}</span>
                <span className="text-xs font-black text-brand">{price} {user.currencyPreference} / {t.periods[period]}</span>
             </div>
             <div className="flex justify-between border-b dark:border-gray-700 pb-2">
                <span className="text-[10px] font-black text-gray-400 uppercase">{lang === 'ar' ? 'الاستلام عبر' : 'Payout'}</span>
                <span className="text-xs font-black dark:text-white">{payoutMethod === 'CRYPTO' ? selectedCrypto : 'PayPal'}</span>
             </div>
          </div>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-4 hover:scale-[1.02] active:scale-95 transition-all">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} {t.securePublish}
          </button>
          <button onClick={() => setStep(4)} className="text-[10px] font-black text-gray-400 uppercase hover:underline">Edit Details</button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center space-y-8 py-10 animate-in fade-in">
          <div className="w-32 h-32 bg-green-500 text-white rounded-[3rem] flex items-center justify-center mx-auto shadow-2xl shadow-green-500/30">
            <CheckCircle size={64} />
          </div>
          <h2 className="text-5xl font-black dark:text-white uppercase italic tracking-tighter">{lang === 'ar' ? 'تم النشر بنجاح!' : 'Item Is Live!'}</h2>
          <p className="text-gray-500 font-bold max-w-sm mx-auto">{lang === 'ar' ? 'منتجك الآن متاح لآلاف المستخدمين في منطقتك.' : 'Your item is now visible to thousands of users in your area.'}</p>
          <button onClick={() => navigate('/')} className="px-16 py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl hover:scale-105 active:scale-95 transition-all">
             {lang === 'ar' ? 'الذهاب للسوق' : 'Open Marketplace'}
          </button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useParams } from 'react-router-dom';
import { User, Gender, Listing } from './types';
import Navbar from './components/Navbar';
import ListingCard from './components/ListingCard';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import SubscriptionPage from './pages/SubscriptionPage';
import { translations } from './i18n';
import { POINTS_SYSTEM, CURRENCIES } from './constants';
import { Camera, MapPinned, Compass, Box, Star, ChevronRight, Coins, Sparkles, Loader2, MapPin, ShieldCheck, Award, Lock, Mail, User as UserIcon, Check } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>(() => localStorage.getItem('my_rents_lang') || 'ar');
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('my_rents_theme') === 'dark');

  const [user, setUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('my_rents_user');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  });

  const [allListings, setAllListings] = useState<Listing[]>(() => {
    try {
      const saved = localStorage.getItem('my_rents_listings');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('my_rents_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('my_rents_theme', isDarkMode ? 'dark' : 'light');
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => {
    if (user) localStorage.setItem('my_rents_user', JSON.stringify(user));
    else localStorage.removeItem('my_rents_user');
  }, [user]);

  useEffect(() => {
    localStorage.setItem('my_rents_listings', JSON.stringify(allListings));
  }, [allListings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    setUser(prev => prev ? { ...prev, points: prev.points + amount } : null);
  };

  const handleCurrencyChange = (code: string) => {
    setUser(prev => prev ? { ...prev, currencyPreference: code } : null);
  };

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    if (!data.avatar || !data.fullName || !data.username || !data.email || !data.password || !data.agreed) {
      alert(lang === 'ar' ? 'يرجى إكمال جميع الحقول' : 'Please complete all fields');
      return;
    }

    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location || { address: 'Riyadh, SA', lat: 24.7136, lng: 46.6753 },
      status: 'Member',
      points: 100,
      listingsCount: 0,
      walletBalance: 0,
      currencyPreference: 'USD',
      trustScore: 75,
      badges: ['NEW_MEMBER'],
      payoutMethods: {},
      blockedUsers: [],
      isVerified: true
    };
    setUser(newUser);
  };

  const ProfileView = () => {
    const { username } = useParams<{ username?: string }>();
    const isSelf = !username || (user && username === user.username);
    const displayUser = isSelf ? user : null; 
    const userSpecificListings = allListings.filter(l => l.ownerUsername === (username || user?.username));

    return (
      <div className="p-8 text-center max-w-4xl mx-auto animate-in fade-in">
        <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-sm border dark:border-gray-800">
          <div className="relative inline-block mb-6">
            <img src={displayUser?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${username || user?.username}`} className="w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl bg-gray-100 dark:bg-gray-800" />
            <div className="absolute -bottom-2 -right-2 bg-brand text-white p-2 rounded-xl shadow-lg">
              <ShieldCheck size={18} fill="currentColor" />
            </div>
          </div>

          <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{displayUser?.fullName || username || user?.fullName}</h1>
          <p className="text-[#CCCCCC] mb-4 font-bold">@{username || user?.username}</p>

          <div className="flex justify-center gap-2 mb-8">
             {(displayUser?.badges || ['VERIFIED']).map(b => (
               <span key={b} className="px-3 py-1 bg-brand/5 text-brand rounded-full text-[8px] font-black uppercase tracking-widest border border-brand/10 flex items-center gap-1">
                 <Award size={10} /> {b.replace('_', ' ')}
               </span>
             ))}
          </div>

          <div className="grid grid-cols-2 gap-4 mb-10">
             <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
