            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              {userSpecificListings.length > 0 ? userSpecificListings.map(l => (
                <ListingCard key={l.id} listing={l} lang={lang} isOwner={l.ownerId === user?.id} onDelete={(id) => setAllListings(prev => prev.filter(item => item.id !== id))} onAddPoints={addPoints} />
              )) : (
                <div className="col-span-2 py-10 text-center opacity-20">
                   <Box size={48} className="mx-auto mb-2" />
                   <p className="text-xs font-black uppercase">No items found</p>
                </div>
              )}
            </div>
          </div>

          {isSelf && (
            <div className="flex flex-col gap-2">
              <button onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="w-full py-4 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-2xl font-black uppercase text-[10px] tracking-widest">
                Switch Language: {lang === 'ar' ? 'English' : 'العربية'}
              </button>
              <button onClick={() => { setUser(null); localStorage.clear(); window.location.reload(); }} className="w-full mt-2 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline transition-all">
                {t.logout}
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  const SignUpPage = () => {
    const [step, setStep] = useState(1);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: 'Riyadh, Saudi Arabia', lat: 24.7136, lng: 46.6753 },
      email: '', password: '', agreed: false
    });

    const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (ev) => setSignupData({ ...signupData, avatar: ev.target?.result as string });
        reader.readAsDataURL(file);
      }
    };

    return (
      <div className="w-full max-w-xl px-6 py-12 mx-auto animate-in fade-in">
        <div className="text-center mb-10">
          <div className="inline-block px-5 py-2.5 bg-brand text-white rounded-2xl shadow-xl font-black text-3xl mb-4 italic tracking-tighter">my rents</div>
          <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter">{t.signUp}</h1>
          <p className="text-xs text-gray-400 mt-2 font-bold uppercase tracking-widest">{t.step} {step} of 2</p>
        </div>

        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          {step === 1 && (
            <div className="space-y-6 animate-in slide-in-from-right">
              <div className="flex flex-col items-center gap-4">
                <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-dashed border-gray-200 dark:border-gray-700 overflow-hidden flex items-center justify-center cursor-pointer group transition-all hover:border-brand">
                  {signupData.avatar ? (
                    <img src={signupData.avatar} className="w-full h-full object-cover" />
                  ) : (
                    <Camera size={32} className="text-gray-300 group-hover:text-brand" />
                  )}
                  <input type="file" className="hidden" accept="image/*" onChange={handleAvatarUpload} />
                </label>
                <p className="text-[10px] font-black uppercase text-gray-400">Upload Profile Image (Required)</p>
              </div>

              <div className="space-y-4">
                <div className="relative">
                  <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                  <input type="text" placeholder={t.fullName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand" />
                </div>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">@</span>
                  <input type="text" placeholder={t.username} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full pl-10 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand" />
                </div>
                <div className="p-4 bg-brand/5 rounded-2xl flex items-center gap-3 border border-brand/10">
                   <MapPin className="text-brand shrink-0" size={18} />
                   <p className="text-xs font-black dark:text-white truncate uppercase">{signupData.location.address}</p>
                   <button type="button" onClick={() => alert('GPS Logic Triggered')} className="ml-auto text-[10px] font-black text-brand uppercase underline">Change</button>
                </div>
              </div>
              <button type="button" onClick={() => setStep(2)} disabled={!signupData.avatar || !signupData.fullName || !signupData.username} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-50">Continue</button>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-6 animate-in slide-in-from-right">
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input type="email" placeholder={t.email} value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand" />
              </div>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input type="password" placeholder={t.password} value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand" />
              </div>

              <div className="space-y-3 p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
                <div className="flex items-start gap-3">
                  <input type="checkbox" id="agree" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="mt-1 w-5 h-5 accent-brand" />
                  <label htmlFor="agree" className="text-[10px] font-bold text-gray-500 leading-relaxed uppercase">
                    {t.acceptTerms}
                  </label>
                </div>
                <div className="flex gap-4 px-8">
                  <Link to="/privacy" className="text-[9px] font-black text-brand uppercase underline">{t.privacyPolicy}</Link>
                  <Link to="/terms" className="text-[9px] font-black text-brand uppercase underline">{t.termsOfUse}</Link>
                </div>
              </div>

              <div className="flex gap-4">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-[2rem] font-black uppercase">Back</button>
                <button type="submit" disabled={!signupData.email || !signupData.password || !signupData.agreed} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-50">Create Account</button>
              </div>
            </div>
          )}
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} onCurrencyChange={handleCurrencyChange} />}
        <main className={user ? 'pb-20' : ''}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={allListings} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setAllListings(prev => [...prev, l])} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} onForcePublish={() => {}} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
                <Route path="/chat/:otherId?" element={<ChatPage lang={lang} onAddPoints={addPoints} listings={allListings} />} />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
              </>
            )}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Heart, MapPin, Eye, Share2, MessageCircle, Trash2, MessageSquare, ShieldCheck } from 'lucide-react';
