              src={listing.ownerAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${listing.ownerUsername}`} 
              className="w-11 h-11 rounded-full border-2 border-brand/20 object-cover" 
            />
            <div className="absolute -bottom-1 -right-1 bg-brand text-white p-0.5 rounded-full border-2 border-white dark:border-gray-900">
              <ShieldCheck size={8} fill="currentColor" />
            </div>
          </div>
          <div className="flex flex-col">
            <span className="text-xs font-black dark:text-white uppercase leading-tight">{listing.ownerName}</span>
            <span className="text-[10px] font-bold text-[#CCCCCC]">@{listing.ownerUsername}</span>
          </div>
        </div>
        {isOwner && (
          <button onClick={() => onDelete?.(listing.id)} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-all">
            <Trash2 size={16} />
          </button>
        )}
      </div>

      <Link to={`/item/${listing.id}`} className="block px-3 pt-3">
        <div className="aspect-square overflow-hidden rounded-[2.5rem] relative">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
          <div className="absolute top-4 right-4 bg-white/90 dark:bg-gray-900/90 backdrop-blur-sm px-3 py-1.5 rounded-2xl shadow-xl">
             <span className="text-xs font-black text-brand">{listing.price} {listing.currency}</span>
             <span className="text-[8px] font-black text-gray-400 block uppercase">{t.periods[listing.rentalPeriod]}</span>
          </div>
          {listing.video && (
             <div className="absolute bottom-4 left-4 bg-brand/80 backdrop-blur-sm text-white px-3 py-1 rounded-xl text-[8px] font-black uppercase flex items-center gap-1">
                VIDEO
             </div>
          )}
        </div>
      </Link>

      <div className="p-5 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-2">
          <h3 className="font-black dark:text-white uppercase truncate flex-1 tracking-tighter text-sm">{listing.title}</h3>
          <span className="text-[9px] font-black text-gray-400 bg-gray-50 dark:bg-gray-800 px-2 py-1 rounded-lg ml-2">{listing.category}</span>
        </div>

        <div className="flex items-center gap-1 text-gray-400 text-[10px] font-bold uppercase mb-4">
          <MapPin size={10} className="text-brand" /> {listing.location.address}
