import React, { useState } from 'react';
import { translations } from '../i18n';
import { PLANS, WALLETS } from '../constants';
import { SubscriptionPlan } from '../types';
import { CheckCircle, Coins, Sparkles, ChevronLeft, Wallet, Copy, ShieldCheck, Zap, ArrowRight, CreditCard, Key } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface SubscriptionPageProps {
  lang: string;
  user: any;
  onUpdateUser: (userData: any) => void;
}

const SubscriptionPage: React.FC<SubscriptionPageProps> = ({ lang, user, onUpdateUser }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();

  const [step, setStep] = useState(1);
  const [selectedPlan, setSelectedPlan] = useState<any>(null);
  const [selectedPeriod, setSelectedPeriod] = useState<'daily' | 'monthly' | 'yearly'>('monthly');
  const [selectedWallet, setSelectedWallet] = useState<string>('SOLANA');
  const [userWallet, setUserWallet] = useState('');
  const [txHash, setTxHash] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const subSteps = t.subSteps;

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    alert(lang === 'ar' ? 'تم نسخ العنوان!' : 'Address Copied!');
  };

  const handleFinalize = () => {
    if (!txHash.trim()) return;
    setIsLoading(true);

    // Simulate verification
    setTimeout(() => {
      const updatedUser = {
        ...user,
        subscription: {
          tier: selectedPlan.name,
          expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
        }
      };
      onUpdateUser(updatedUser);
      setStep(5);
      setIsLoading(false);
    }, 2000);
  };

  const currentPrice = selectedPlan ? selectedPlan.pricing[selectedPeriod] : 0;

  return (
    <div className="max-w-6xl mx-auto p-4 pt-10 pb-24 animate-in fade-in duration-500">
      {/* Header & Steps Indicator */}
      <div className="flex flex-col md:flex-row items-center justify-between mb-12 gap-8">
        <div className="flex items-center gap-4">
          <button onClick={() => step > 1 ? setStep(step - 1) : navigate(-1)} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm dark:text-white">
            <ChevronLeft className={lang === 'ar' ? 'rotate-180' : ''} />
          </button>
          <div>
            <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'باقات الاشتراك' : 'Premium Plans'}</h1>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{subSteps[step-1]}</p>
          </div>
        </div>

        <div className="flex gap-2">
          {[1, 2, 3, 4, 5].map(s => (
            <div key={s} className={`w-8 h-1.5 rounded-full transition-all ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />
          ))}
        </div>
      </div>

      {/* STEP 1: Plan Selection */}
      {step === 1 && (
        <div className="space-y-10 animate-in slide-in-from-right">
          <div className="flex justify-center p-1 bg-gray-50 dark:bg-gray-800 rounded-3xl w-fit mx-auto mb-10">
            {['daily', 'monthly', 'yearly'].map(p => (
              <button key={p} onClick={() => setSelectedPeriod(p as any)} className={`px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedPeriod === p ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>
                {p}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {PLANS.map(plan => (
              <div key={plan.id} className={`p-8 rounded-[3rem] border-4 flex flex-col transition-all group relative ${selectedPlan?.id === plan.id ? 'border-brand bg-white dark:bg-gray-900 scale-[1.05] z-10 shadow-2xl' : 'border-transparent bg-white dark:bg-gray-900 shadow-sm'}`}>
                <div className="text-center mb-6">
                  <h3 className="text-xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{plan.name}</h3>
                  <p className="text-[9px] font-bold text-gray-400 uppercase leading-tight">{plan.description}</p>
                </div>

                <div className="flex flex-col items-center mb-8">
                   <div className="flex items-baseline gap-1">
                      <span className="text-3xl font-black text-brand">${plan.pricing[selectedPeriod]}</span>
                      <span className="text-[10px] font-black text-gray-300 uppercase">/{selectedPeriod.slice(0, 3)}</span>
                   </div>
                </div>

                <div className="flex-1 space-y-4 mb-8">
                  {plan.features.map((f, i) => (
                    <div key={i} className="flex items-start gap-2">
                      <CheckCircle size={12} className="text-brand shrink-0 mt-0.5" />
                      <span className="text-[10px] font-bold dark:text-gray-300 leading-tight uppercase">{f}</span>
                    </div>
                  ))}
                </div>

                <button 
                  onClick={() => { setSelectedPlan(plan); setStep(2); }}
                  className="w-full py-4 bg-brand text-white rounded-[1.5rem] font-black uppercase tracking-widest text-[10px] shadow-lg shadow-brand/20 active:scale-95 transition-all"
                >
                  {lang === 'ar' ? 'إختيار الباقة' : 'Select Plan'}
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* STEP 2: Choose Payment Wallet */}
      {step === 2 && (
        <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center mb-10">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2rem] flex items-center justify-center mx-auto mb-4 shadow-xl shadow-brand/5">
                <Wallet size={32} />
             </div>
             <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'اختر محفظة الدفع' : 'Select Deposit Wallet'}</h2>
             <p className="text-xs text-gray-400 font-bold uppercase">{lang === 'ar' ? 'قم بإرسال المبلغ المحدد إلى أحد عناويننا التالية' : 'Send the exact amount to one of our official addresses'}</p>
          </div>

          <div className="space-y-4">
             {Object.entries(WALLETS).map(([key, addr]) => (
               <button 
                 key={key} 
                 onClick={() => setSelectedWallet(key)}
                 className={`w-full p-6 rounded-[2rem] border-4 transition-all flex items-center justify-between ${selectedWallet === key ? 'border-brand bg-brand/5 shadow-xl' : 'border-gray-50 dark:border-gray-800 bg-white dark:bg-gray-900'}`}
               >
                  <div className="flex items-center gap-4">
                     <div className="p-3 bg-gray-50 dark:bg-gray-800 rounded-xl text-brand font-black text-xs">{key.slice(0, 3)}</div>
                     <div className="text-left">
                        <p className="text-xs font-black dark:text-white">{key}</p>
                        <p className="text-[10px] text-gray-400 truncate w-40 sm:w-80 font-mono">{addr}</p>
                     </div>
                  </div>
                  <Copy size={20} className="text-gray-300 hover:text-brand" onClick={(e) => { e.stopPropagation(); handleCopy(addr); }} />
               </button>
             ))}
          </div>

          <div className="bg-yellow-400/10 border border-yellow-400/20 p-6 rounded-[2rem] text-center">
             <p className="text-[10px] font-black text-yellow-600 uppercase tracking-widest leading-relaxed">
                {lang === 'ar' ? 'تأكد من إرسال القيمة الصحيحة: ' : 'Make sure to send the exact amount: '}
                <span className="text-lg underline">${currentPrice}</span>
             </p>
          </div>

          <button onClick={() => setStep(3)} className="w-full py-6 bg-brand text-white rounded-[2rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-all">
             {lang === 'ar' ? 'تم التحويل، التالي' : 'I have sent, Next'} <ArrowRight size={20} />
          </button>
        </div>
      )}

      {/* STEP 3: User Wallet Address */}
      {step === 3 && (
        <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center mb-10">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2rem] flex items-center justify-center mx-auto mb-4">
                <ShieldCheck size={32} />
             </div>
             <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'عنوان محفظتك' : 'Your Wallet Address'}</h2>
             <p className="text-xs text-gray-400 font-bold uppercase">{lang === 'ar' ? 'أدخل عنوان المحفظة التي قمت بالإرسال منها للتحقق' : 'Enter the wallet address you sent from for verification'}</p>
          </div>

          <div className="relative">
             <CreditCard className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
             <input 
               type="text" 
               value={userWallet}
               onChange={e => setUserWallet(e.target.value)}
               placeholder={lang === 'ar' ? 'الصق عنوان محفظتك هنا...' : 'Paste your wallet address here...'}
               className="w-full pl-16 pr-6 py-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold text-sm border-2 border-transparent focus:border-brand shadow-inner"
             />
          </div>

          <button onClick={() => setStep(4)} disabled={!userWallet.trim()} className="w-full py-6 bg-brand text-white rounded-[2rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-50">
             {lang === 'ar' ? 'متابعة' : 'Continue'} <ArrowRight size={20} />
          </button>
        </div>
      )}

      {/* STEP 4: Transaction Verification */}
      {step === 4 && (
        <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center mb-10">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2rem] flex items-center justify-center mx-auto mb-4">
                <Key size={32} />
             </div>
             <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'رمز التحقق من العملية' : 'Transaction Verification'}</h2>
             <p className="text-xs text-gray-400 font-bold uppercase">{lang === 'ar' ? 'الصق رمز العملية (TXID/Hash) لتأكيد الدفع' : 'Paste the Transaction ID or Hash to confirm payment'}</p>
          </div>

          <div className="relative">
             <Zap className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
             <input 
               type="text" 
               value={txHash}
               onChange={e => setTxHash(e.target.value)}
               placeholder={lang === 'ar' ? 'الصق رمز العملية هنا...' : 'Paste TXID / Hash here...'}
               className="w-full pl-16 pr-6 py-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold text-sm border-2 border-transparent focus:border-brand shadow-inner"
             />
          </div>

          <div className="p-6 bg-emerald-500/5 border border-emerald-500/20 rounded-[2rem] flex items-start gap-4">
             <ShieldCheck size={24} className="text-emerald-500 shrink-0" />
             <p className="text-[10px] font-bold text-emerald-600 uppercase leading-relaxed">
               {lang === 'ar' 
                 ? 'سيقوم فريق الدعم أو النظام الذكي بالتحقق من العملية خلال دقائق. بمجرد التأكيد، سيتم تفعيل حسابك تلقائياً.' 
                 : 'Support or AI system will verify the transaction within minutes. Once confirmed, your account will be activated automatically.'}
             </p>
          </div>

          <button 
            onClick={handleFinalize} 
            disabled={!txHash.trim() || isLoading} 
            className="w-full py-6 bg-brand text-white rounded-[2rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-50"
          >
             {isLoading ? <span className="animate-pulse">VERIFYING...</span> : (lang === 'ar' ? 'تأكيد الإشتراك' : 'Confirm Subscription')}
          </button>
        </div>
      )}

      {/* STEP 5: Success */}
      {step === 5 && (
        <div className="max-w-xl mx-auto py-20 px-6 text-center animate-in zoom-in-95 duration-500">
          <div className="w-24 h-24 bg-green-500 text-white rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl shadow-green-500/30 mb-8">
            <CheckCircle size={48} />
          </div>
          <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-4 italic">
            {lang === 'ar' ? 'تم الإشتراك بنجاح!' : 'Subscription Active!'}
          </h2>
          <p className="text-gray-500 font-medium mb-10 leading-relaxed uppercase text-xs tracking-widest">
            {lang === 'ar' 
              ? `تهانينا! أنت الآن عضو في فئة ${selectedPlan?.name}. تم استلام طلبك وبدأ التفعيل.` 
              : `Congratulations! You are now a member of ${selectedPlan?.name}. Your request has been received.`}
          </p>
          <button 
            onClick={() => navigate('/')} 
            className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all"
          >
            {lang === 'ar' ? 'الذهاب إلى المنصة' : 'Start Renting'}
          </button>
        </div>
      )}
    </div>
  );
};

