import React, { useState } from 'react';
import { translations } from '../i18n';
import { PLANS, WALLETS } from '../constants';
import { SubscriptionPlan } from '../types';
import { CheckCircle, Coins, Sparkles, ChevronLeft, Wallet, Copy, ShieldCheck, Zap, ArrowRight, CreditCard, Key, AlertCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface SubscriptionPageProps {
  lang: string;
  user: any;
  onUpdateUser: (userData: any) => void;
}

const SubscriptionPage: React.FC<SubscriptionPageProps> = ({ lang, user, onUpdateUser }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();

  const [step, setStep] = useState(1);
  const [selectedPlan, setSelectedPlan] = useState<any>(null);
  const [selectedPeriod, setSelectedPeriod] = useState<'daily' | 'monthly' | 'yearly'>('monthly');
  const [selectedWallet, setSelectedWallet] = useState<string>('');
  const [userWallet, setUserWallet] = useState('');
  const [txHash, setTxHash] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const subSteps = t.subSteps;

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    alert(lang === 'ar' ? 'تم نسخ العنوان!' : 'Address Copied!');
  };

  const handleStepValidation = (currentStep: number) => {
    if (currentStep === 1 && !selectedPlan) {
      alert(lang === 'ar' ? 'يرجى اختيار باقة أولاً' : 'Please select a plan first');
      return false;
    }
    if (currentStep === 2 && !selectedWallet) {
      alert(lang === 'ar' ? 'يرجى اختيار محفظة الدفع' : 'Please select a payment wallet');
      return false;
    }
    if (currentStep === 3 && !userWallet.trim()) {
      alert(lang === 'ar' ? 'يرجى إدخال عنوان محفظتك' : 'Please enter your wallet address');
      return false;
    }
    if (currentStep === 4 && !txHash.trim()) {
      alert(lang === 'ar' ? 'يرجى إدخال رمز التحقق' : 'Please enter the verification code');
      return false;
    }
    return true;
  };

  const nextStep = () => {
    if (handleStepValidation(step)) {
      setStep(step + 1);
    }
  };

  const handleFinalize = () => {
    if (!txHash.trim()) {
      alert(lang === 'ar' ? 'رمز التحقق مطلوب!' : 'Verification code is required!');
      return;
    }
    setIsLoading(true);

    // Simulate back-end verification delay
    setTimeout(() => {
      const updatedUser = {
        ...user,
        subscription: {
          tier: selectedPlan.name,
          expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
        }
      };
      onUpdateUser(updatedUser);
      setStep(5);
      setIsLoading(false);
    }, 2500);
  };

  const currentPrice = selectedPlan ? selectedPlan.pricing[selectedPeriod] : 0;

  return (
    <div className="max-w-6xl mx-auto p-4 pt-10 pb-24 animate-in fade-in duration-500">
      {/* Header & Steps Indicator */}
      <div className="flex flex-col md:flex-row items-center justify-between mb-12 gap-8">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => step > 1 ? setStep(step - 1) : navigate(-1)} 
            className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm dark:text-white hover:scale-105 transition-all"
          >
            <ChevronLeft className={lang === 'ar' ? 'rotate-180' : ''} />
          </button>
          <div>
            <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'ترقية الحساب' : 'Upgrade Account'}</h1>
            <p className="text-[10px] font-bold text-brand uppercase tracking-widest flex items-center gap-1">
              <Sparkles size={12} /> {subSteps[step-1]}
            </p>
          </div>
        </div>

        <div className="flex gap-2">
          {[1, 2, 3, 4, 5].map(s => (
            <div key={s} className={`w-10 h-2 rounded-full transition-all duration-500 ${step >= s ? 'bg-brand shadow-lg shadow-brand/20' : 'bg-gray-100 dark:bg-gray-800'}`} />
          ))}
        </div>
      </div>

      {/* STEP 1: Select Plan */}
      {step === 1 && (
        <div className="space-y-10 animate-in slide-in-from-right">
          <div className="flex justify-center p-1 bg-gray-50 dark:bg-gray-800 rounded-3xl w-fit mx-auto mb-10 shadow-inner">
            {['daily', 'monthly', 'yearly'].map(p => (
              <button 
                key={p} 
                onClick={() => setSelectedPeriod(p as any)} 
                className={`px-10 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedPeriod === p ? 'bg-white dark:bg-gray-900 text-brand shadow-md' : 'text-gray-400'}`}
              >
                {t.periods[p.toUpperCase()]}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {PLANS.map(plan => {
              const price = plan.pricing[selectedPeriod];
              if (price === 0 && selectedPeriod !== 'daily' && plan.id === 'trial') return null;

              return (
                <div 
                  key={plan.id} 
                  onClick={() => setSelectedPlan(plan)}
                  className={`p-8 rounded-[3.5rem] border-4 flex flex-col transition-all cursor-pointer group relative ${selectedPlan?.id === plan.id ? 'border-brand bg-white dark:bg-gray-900 scale-[1.05] z-10 shadow-2xl' : 'border-transparent bg-white dark:bg-gray-900 shadow-sm opacity-80'}`}
                >
                  <div className="text-center mb-6">
                    <h3 className="text-xl font-black dark:text-white uppercase tracking-tighter mb-1 italic group-hover:text-brand transition-colors">{plan.name}</h3>
                    <p className="text-[9px] font-bold text-gray-400 uppercase leading-tight h-8">{plan.description}</p>
                  </div>

                  <div className="flex flex-col items-center mb-8 bg-brand/5 p-4 rounded-3xl">
                     <div className="flex items-baseline gap-1">
                        <span className="text-4xl font-black text-brand">${price}</span>
                        <span className="text-[10px] font-black text-gray-300 uppercase">/{selectedPeriod.slice(0, 3)}</span>
                     </div>
                  </div>

                  <div className="flex-1 space-y-4 mb-8">
                    {plan.features.map((f, i) => (
                      <div key={i} className="flex items-start gap-2">
                        <CheckCircle size={14} className="text-brand shrink-0 mt-0.5" />
                        <span className="text-[10px] font-bold dark:text-gray-300 leading-tight uppercase">{f}</span>
                      </div>
                    ))}
                  </div>

                  <div className={`w-full py-4 rounded-[1.5rem] font-black uppercase tracking-widest text-[10px] text-center transition-all ${selectedPlan?.id === plan.id ? 'bg-brand text-white shadow-xl' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>
                    {selectedPlan?.id === plan.id ? (lang === 'ar' ? 'مختارة' : 'Selected') : (lang === 'ar' ? 'إختيار' : 'Choose')}
                  </div>
                </div>
              );
            })}
          </div>

          <div className="flex justify-center mt-12">
            <button 
              onClick={nextStep} 
              disabled={!selectedPlan}
              className="px-20 py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all disabled:opacity-30"
            >
              {lang === 'ar' ? 'المتابعة للدفع' : 'Proceed to Payment'} <ArrowRight size={20} />
            </button>
          </div>
        </div>
      )}

      {/* STEP 2: Choose Payment Wallet (Mandatory) */}
      {step === 2 && (
        <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center mb-10">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2.5rem] flex items-center justify-center mx-auto mb-4 shadow-xl">
                <Wallet size={32} />
             </div>
             <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'إختر محفظة الإيداع' : 'Select Deposit Wallet'}</h2>
             <p className="text-xs text-gray-400 font-bold uppercase">{lang === 'ar' ? 'يرجى الإرسال إلى أحد عناويننا الرسمية التالية' : 'Please send to one of our official addresses below'}</p>
          </div>

          <div className="space-y-4">
             {Object.entries(WALLETS).map(([key, addr]) => (
               <button 
                 key={key} 
                 onClick={() => setSelectedWallet(key)}
                 className={`w-full p-6 rounded-[2.5rem] border-4 transition-all flex items-center justify-between ${selectedWallet === key ? 'border-brand bg-brand/5 shadow-xl' : 'border-gray-50 dark:border-gray-800 bg-white dark:bg-gray-900'}`}
               >
                  <div className="flex items-center gap-4">
                     <div className={`p-3 rounded-xl font-black text-xs ${selectedWallet === key ? 'bg-brand text-white' : 'bg-gray-100 dark:bg-gray-800 text-gray-400'}`}>{key.slice(0, 3)}</div>
                     <div className="text-left">
                        <p className="text-xs font-black dark:text-white uppercase tracking-tighter">{key} Network</p>
                        <p className="text-[10px] text-gray-400 truncate w-40 sm:w-80 font-mono tracking-tighter">{addr}</p>
                     </div>
                  </div>
                  <Copy 
                    size={20} 
                    className="text-gray-300 hover:text-brand transition-colors" 
                    onClick={(e) => { e.stopPropagation(); handleCopy(addr); }} 
                  />
               </button>
             ))}
          </div>

          <div className="bg-brand/5 border border-brand/10 p-6 rounded-[2.5rem] flex items-center justify-between">
             <p className="text-[10px] font-black text-brand uppercase tracking-widest leading-relaxed">
                {lang === 'ar' ? 'المبلغ المطلوب إرساله: ' : 'Exact amount to send: '}
             </p>
             <span className="text-2xl font-black text-brand underline decoration-brand/20">${currentPrice}</span>
          </div>

          <button onClick={nextStep} disabled={!selectedWallet} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-30">
             {lang === 'ar' ? 'تم التحويل، المتابعة' : 'Transferred, Continue'} <ArrowRight size={20} />
          </button>
        </div>
      )}

      {/* STEP 3: User's Wallet Address (Mandatory) */}
      {step === 3 && (
        <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center mb-10">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2.5rem] flex items-center justify-center mx-auto mb-4">
                <CreditCard size={32} />
             </div>
             <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'عنوان محفظتك الخاصة' : 'Your Wallet Address'}</h2>
             <p className="text-xs text-gray-400 font-bold uppercase">{lang === 'ar' ? 'أدخل العنوان الذي قمت بالإرسال منه للتحقق (مطلوب)' : 'Enter the address you sent from for validation (Required)'}</p>
          </div>

          <div className="relative group">
             <div className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-brand transition-colors">
                <ShieldCheck size={20} />
             </div>
             <input 
               type="text" 
               value={userWallet}
               onChange={e => setUserWallet(e.target.value)}
               placeholder={lang === 'ar' ? 'الصق عنوان محفظتك هنا (مثل: 0x...)' : 'Paste your wallet address (e.g., 0x...)'}
               className="w-full pl-16 pr-6 py-6 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold text-sm border-2 border-transparent focus:border-brand shadow-inner transition-all"
             />
          </div>

          <div className="p-5 bg-yellow-500/5 rounded-3xl border border-yellow-500/10 flex items-start gap-3">
             <AlertCircle size={20} className="text-yellow-600 shrink-0" />
             <p className="text-[10px] font-bold text-yellow-700 uppercase leading-relaxed">
               {lang === 'ar' 
                 ? 'هذا العنوان مطلوب لنتمكن من مطابقة دفعتك يدوياً أو آلياً. يرجى التأكد من دقته.' 
                 : 'This address is mandatory to match your payment manually or via AI. Please ensure accuracy.'}
             </p>
          </div>

          <button onClick={nextStep} disabled={!userWallet.trim()} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-30">
             {lang === 'ar' ? 'التالي: رمز التحقق' : 'Next: Verification Code'} <ArrowRight size={20} />
          </button>
        </div>
      )}

      {/* STEP 4: Payment Verification Code (Mandatory) */}
      {step === 4 && (
        <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center mb-10">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2.5rem] flex items-center justify-center mx-auto mb-4">
                <Key size={32} />
             </div>
             <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'رمز إثبات الدفع' : 'Payment Proof Code'}</h2>
             <p className="text-xs text-gray-400 font-bold uppercase">{lang === 'ar' ? 'الصق رمز المعاملة (TXID) من محفظتك (مطلوب)' : 'Paste the Transaction ID (TXID) from your wallet (Required)'}</p>
          </div>

          <div className="relative group">
             <div className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-brand transition-colors">
                <Zap size={20} />
             </div>
             <input 
               type="text" 
               value={txHash}
               onChange={e => setTxHash(e.target.value)}
               placeholder={lang === 'ar' ? 'الصق رمز TXID أو هاش المعاملة هنا...' : 'Paste TXID / Transaction Hash here...'}
               className="w-full pl-16 pr-6 py-6 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold text-sm border-2 border-transparent focus:border-brand shadow-inner transition-all"
             />
          </div>

          <div className="p-6 bg-brand/5 border border-brand/10 rounded-[2.5rem]">
             <h4 className="text-[10px] font-black text-brand uppercase mb-2 flex items-center gap-2">
               <ShieldCheck size={14} /> AI Verification System
             </h4>
             <p className="text-[10px] font-bold text-gray-500 uppercase leading-relaxed">
               {lang === 'ar' 
                 ? 'سيقوم نظام AI my rents بالتحقق من صحة الرمز المرفق ومطابقته مع عنوان محفظتك لإتمام التفعيل.' 
                 : 'AI my rents system will validate the provided code and match it with your wallet to complete activation.'}
             </p>
          </div>

          <button 
            onClick={handleFinalize} 
            disabled={!txHash.trim() || isLoading} 
            className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-30"
          >
             {isLoading ? (
               <div className="flex items-center gap-3">
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  <span>VERIFYING PAYMENT...</span>
               </div>
             ) : (
               <span className="flex items-center gap-2">{lang === 'ar' ? 'تأكيد الإشتراك النهائي' : 'Confirm Final Subscription'} <ArrowRight size={20} /></span>
             )}
          </button>
        </div>
      )}

      {/* STEP 5: Success (Automatic after validation) */}
      {step === 5 && (
        <div className="max-w-xl mx-auto py-20 px-6 text-center animate-in zoom-in-95 duration-700">
          <div className="w-32 h-32 bg-green-500 text-white rounded-[3.5rem] flex items-center justify-center mx-auto shadow-2xl shadow-green-500/40 mb-10 rotate-3">
            <CheckCircle size={64} />
          </div>
          <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-4 italic italic leading-none">
            {lang === 'ar' ? 'تم تفعيل اشتراكك بنجاح!' : 'Subscription Activated!'}
          </h2>
          <p className="text-gray-400 font-bold mb-12 leading-relaxed uppercase text-[10px] tracking-[0.2em] max-w-xs mx-auto">
            {lang === 'ar' 
              ? `أهلاً بك في فئة ${selectedPlan?.name}. تم استلام معلومات الدفع وبدأ التفعيل الفوري.` 
              : `Welcome to ${selectedPlan?.name}. Your payment data has been verified and active immediately.`}
          </p>
          <div className="grid grid-cols-2 gap-4 mb-8">
             <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl text-left border dark:border-gray-700">
                <p className="text-[8px] font-black text-gray-400 uppercase">{lang === 'ar' ? 'الباقة' : 'Plan'}</p>
                <p className="text-xs font-black dark:text-white uppercase">{selectedPlan?.name}</p>
             </div>
             <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl text-left border dark:border-gray-700">
                <p className="text-[8px] font-black text-gray-400 uppercase">{lang === 'ar' ? 'الحالة' : 'Status'}</p>
                <p className="text-xs font-black text-green-500 uppercase">{lang === 'ar' ? 'نشط' : 'Active'}</p>
             </div>
          </div>
          <button 
            onClick={() => navigate('/')} 
            className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase tracking-widest text-[11px] shadow-2xl shadow-brand/20 active:scale-95 transition-all"
          >
            {lang === 'ar' ? 'العودة للمنصة وبدء التأجير' : 'Go to Marketplace'}
          </button>
        </div>
      )}
    </div>
  );
};

