import React, { useState } from 'react';
import { translations } from '../i18n';
import { PLANS, WALLETS } from '../constants';
import { ChevronLeft, Wallet, Copy, ShieldCheck, Zap, ArrowRight, CreditCard, Key, CheckCircle, Info } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface SubscriptionPageProps {
  lang: string;
  user: any;
  onUpdateUser: (userData: any) => void;
}

const SubscriptionPage: React.FC<SubscriptionPageProps> = ({ lang, user, onUpdateUser }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();

  const [step, setStep] = useState(1);
  const [selectedPlan, setSelectedPlan] = useState<any>(null);
  const [selectedPeriod, setSelectedPeriod] = useState<'daily' | 'monthly' | 'yearly'>('monthly');
  const [selectedWallet, setSelectedWallet] = useState<string>('');
  const [userWallet, setUserWallet] = useState('');
  const [txHash, setTxHash] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const subSteps = t.subSteps;

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    alert(lang === 'ar' ? 'تم نسخ العنوان!' : 'Address Copied!');
  };

  const validateStep = () => {
    if (step === 1 && !selectedPlan) return false;
    if (step === 2 && !selectedWallet) return false;
    if (step === 3 && !userWallet.trim()) return false;
    if (step === 4 && !txHash.trim()) return false;
    return true;
  };

  const handleFinalize = () => {
    if (!txHash.trim()) return;
    setIsLoading(true);
    setTimeout(() => {
      const updatedUser = {
        ...user,
        subscription: {
          tier: selectedPlan.name,
          expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
        }
      };
      onUpdateUser(updatedUser);
      setStep(5);
      setIsLoading(false);
    }, 2000);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 pt-10 pb-24 animate-in fade-in duration-500">
      {/* Step Header */}
      <div className="flex flex-col items-center mb-12">
        <div className="flex gap-2 mb-6">
          {[1, 2, 3, 4, 5].map(s => (
            <div key={s} className={`h-2 rounded-full transition-all duration-500 ${step >= s ? 'w-12 bg-brand' : 'w-8 bg-gray-100 dark:bg-gray-800'}`} />
          ))}
        </div>
        <h1 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{subSteps[step-1]}</h1>
      </div>

      {/* STEP 1: Plan Selection */}
      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="flex justify-center p-1 bg-gray-50 dark:bg-gray-800 rounded-3xl w-fit mx-auto mb-6">
            {['daily', 'monthly', 'yearly'].map(p => (
              <button key={p} onClick={() => setSelectedPeriod(p as any)} className={`px-8 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedPeriod === p ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>
                {t.periods[p.toUpperCase()]}
              </button>
            ))}
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {PLANS.map(plan => {
              const price = plan.pricing[selectedPeriod];
              if (price === 0 && plan.id === 'trial' && selectedPeriod !== 'daily') return null;
              return (
                <div key={plan.id} onClick={() => setSelectedPlan(plan)} className={`p-8 rounded-[3rem] border-4 transition-all cursor-pointer ${selectedPlan?.id === plan.id ? 'border-brand bg-white dark:bg-gray-900 shadow-xl' : 'border-transparent bg-gray-50 dark:bg-gray-800 opacity-60'}`}>
                  <h3 className="text-lg font-black dark:text-white uppercase mb-2">{plan.name}</h3>
                  <div className="flex items-baseline gap-1 mb-6">
                    <span className="text-3xl font-black text-brand">${price}</span>
                    <span className="text-[10px] font-bold text-gray-400">/{selectedPeriod.slice(0, 3)}</span>
                  </div>
                  <ul className="space-y-2">
                    {plan.features.map((f, i) => (
                      <li key={i} className="text-[9px] font-black uppercase text-gray-500 flex items-center gap-2">
                        <CheckCircle size={12} className="text-brand" /> {f}
                      </li>
                    ))}
                  </ul>
                </div>
              );
            })}
          </div>
          <button onClick={() => validateStep() && setStep(2)} disabled={!selectedPlan} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30">
            {lang === 'ar' ? 'التالي: اختيار المحفظة' : 'Next: Choose Wallet'}
          </button>
        </div>
      )}

      {/* STEP 2: Platform Wallet (Required) */}
      {step === 2 && (
        <div className="max-w-xl mx-auto space-y-6 animate-in slide-in-from-right">
          <div className="bg-brand/5 border border-brand/10 p-6 rounded-[2.5rem] text-center mb-6">
             <p className="text-[10px] font-black text-brand uppercase mb-2">Total Due</p>
             <h2 className="text-4xl font-black text-brand italic">${selectedPlan.pricing[selectedPeriod]}</h2>
          </div>
          <div className="space-y-3">
             {Object.entries(WALLETS).map(([name, addr]) => (
               <div key={name} onClick={() => setSelectedWallet(name)} className={`p-6 rounded-[2rem] border-4 transition-all cursor-pointer flex items-center justify-between ${selectedWallet === name ? 'border-brand bg-white dark:bg-gray-900 shadow-xl' : 'border-transparent bg-gray-50 dark:bg-gray-800'}`}>
                  <div className="flex items-center gap-4">
                     <div className="w-10 h-10 bg-brand text-white rounded-xl flex items-center justify-center font-black text-[10px] italic">{name.slice(0,1)}</div>
                     <div className="text-left">
                        <p className="text-xs font-black dark:text-white uppercase">{name}</p>
                        <p className="text-[9px] text-gray-400 font-mono truncate w-40 sm:w-64">{addr}</p>
                     </div>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); handleCopy(addr); }} className="p-2 text-gray-400 hover:text-brand"><Copy size={18} /></button>
               </div>
             ))}
          </div>
          <button onClick={() => validateStep() && setStep(3)} disabled={!selectedWallet} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30">
            {lang === 'ar' ? 'التالي: إدخال محفظتي' : 'Next: My Wallet Address'}
          </button>
        </div>
      )}

      {/* STEP 3: User Wallet (Required) */}
      {step === 3 && (
        <div className="max-w-xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2rem] flex items-center justify-center mx-auto mb-6 shadow-xl"><Wallet size={32} /></div>
             <p className="text-xs text-gray-400 font-bold uppercase mb-2">{lang === 'ar' ? 'لأغراض التحقق، الصق عنوان محفظتك التي أرسلت منها' : 'For verification, paste the address you sent from'}</p>
          </div>
          <div className="relative">
             <CreditCard className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
             <input type="text" value={userWallet} onChange={e => setUserWallet(e.target.value)} placeholder={lang === 'ar' ? 'لصق عنوان محفظتك هنا (مطلوب)' : 'Paste your wallet address (Required)'} className="w-full pl-16 pr-6 py-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold text-sm border-2 border-transparent focus:border-brand shadow-inner" />
          </div>
          <button onClick={() => validateStep() && setStep(4)} disabled={!userWallet.trim()} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30">
            {lang === 'ar' ? 'التالي: رمز التحقق' : 'Next: Verification Code'}
          </button>
        </div>
      )}

      {/* STEP 4: Transaction Hash (Required) */}
      {step === 4 && (
        <div className="max-w-xl mx-auto space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
             <div className="w-20 h-20 bg-brand/10 text-brand rounded-[2rem] flex items-center justify-center mx-auto mb-6 shadow-xl"><Key size={32} /></div>
             <p className="text-xs text-gray-400 font-bold uppercase mb-2">{lang === 'ar' ? 'الصق رمز تأكيد العملية (TXID) المكون من أرقام وحروف' : 'Paste the Transaction ID / Hash (TXID) from your wallet'}</p>
          </div>
          <div className="relative">
             <Zap className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
             <input type="text" value={txHash} onChange={e => setTxHash(e.target.value)} placeholder={lang === 'ar' ? 'لصق رمز التحقق من المدفوعات (مطلوب)' : 'Paste Payment Verification Code (Required)'} className="w-full pl-16 pr-6 py-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold text-sm border-2 border-transparent focus:border-brand shadow-inner" />
          </div>
          <button onClick={handleFinalize} disabled={!txHash.trim() || isLoading} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30">
            {isLoading ? <span className="animate-pulse">Verifying...</span> : (lang === 'ar' ? 'تأكيد الإشتراك النهائي' : 'Confirm Final Subscription')}
          </button>
        </div>
      )}

      {/* STEP 5: Success */}
      {step === 5 && (
        <div className="max-w-xl mx-auto py-20 px-6 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-green-500 text-white rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl mb-8 rotate-3"><CheckCircle size={48} /></div>
          <h2 className="text-3xl font-black dark:text-white uppercase italic mb-4">{lang === 'ar' ? 'تم الإشتراك بنجاح!' : 'Subscription Active!'}</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mb-10">{lang === 'ar' ? `أنت الآن عضو في فئة ${selectedPlan.name}` : `You are now a ${selectedPlan.name} member`}</p>
          <button onClick={() => navigate('/')} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl active:scale-95 transition-all">
            {lang === 'ar' ? 'بدء الاستخدام' : 'Start Using'}
          </button>
        </div>
      )}
    </div>
  );
};

