                {user?.subscription?.tier ? 'Manage Subscription' : 'Unlock Premium'}
              </Link>
              <button onClick={() => { setUser(null); localStorage.clear(); window.location.reload(); }} className="w-full mt-2 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline">
                {t.logout}
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  const SignUpPage = () => {
    const [step, setStep] = useState(1);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: 'Riyadh, Saudi Arabia', lat: 24.7136, lng: 46.6753 },
      email: '', password: '', agreed: false
    });

    const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (ev) => setSignupData({ ...signupData, avatar: ev.target?.result as string });
        reader.readAsDataURL(file);
      }
    };

    return (
      <div className="w-full max-w-xl px-6 py-12 mx-auto animate-in fade-in">
        <div className="text-center mb-10">
          <div className="inline-block px-5 py-2.5 bg-brand text-white rounded-2xl shadow-xl font-black text-3xl mb-4 italic tracking-tighter">my rents</div>
          <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter">{t.signUp}</h1>
          <p className="text-xs text-gray-400 mt-2 font-bold uppercase tracking-widest">{t.step} {step} of 2</p>
        </div>

        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          {step === 1 && (
            <div className="space-y-6">
              <div className="flex flex-col items-center gap-4">
                <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-dashed border-gray-200 dark:border-gray-700 overflow-hidden flex items-center justify-center cursor-pointer group transition-all hover:border-brand">
                  {signupData.avatar ? (
                    <img src={signupData.avatar} className="w-full h-full object-cover" />
                  ) : (
                    <Camera size={32} className="text-gray-300 group-hover:text-brand" />
                  )}
                  <input type="file" className="hidden" accept="image/*" onChange={handleAvatarUpload} />
                </label>
              </div>
              <div className="space-y-4">
                <input type="text" placeholder={t.fullName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
                <input type="text" placeholder={t.username} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
              </div>
              <button type="button" onClick={() => setStep(2)} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase">Next</button>
            </div>
          )}
          {step === 2 && (
            <div className="space-y-6">
              <input type="email" placeholder={t.email} value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
              <input type="password" placeholder={t.password} value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
              <div className="flex items-center gap-3">
                <input type="checkbox" id="agree" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-5 h-5 accent-brand" />
                <label htmlFor="agree" className="text-[10px] font-bold text-gray-500 leading-relaxed uppercase">{t.acceptTerms}</label>
              </div>
              <div className="flex gap-4">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 rounded-2xl font-black">Back</button>
                <button type="submit" className="flex-[2] py-5 bg-brand text-white rounded-2xl font-black shadow-xl shadow-brand/20">Sign Up</button>
              </div>
            </div>
          )}
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200 flex flex-col`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} onLangChange={setLang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} onCurrencyChange={handleCurrencyChange} />}
        <main className={`flex-1 ${user ? 'pb-20' : ''}`}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={allListings} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setAllListings(prev => [...prev, l])} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} onForcePublish={() => {}} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
                <Route path="/chat/:otherId?" element={<ChatPage lang={lang} onAddPoints={addPoints} listings={allListings} />} />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/pro-dashboard" element={user?.subscription?.tier ? <ProfessionalDashboardPage lang={lang} user={user} /> : <Navigate to="/subscription" />} />
              </>
            )}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
        <Footer lang={lang} />
      </div>
    </HashRouter>
  );
};

export default App;

export enum Gender {
  MALE = 'MALE',
  FEMALE = 'FEMALE',
  OTHER = 'OTHER'
}

export interface PayoutMethods {
  solana?: string;
  ethereum?: string;
  monad?: string;
  base?: string;
  sui?: string;
  polygon?: string;
  bitcoin?: string;
  paypal?: string;
}

export interface User {
  id: string;
  fullName: string;
  username: string;
  email: string;
  avatar: string; // Required
  gender: Gender;
  birthDate: string;
  location: { lat: number; lng: number; address: string }; // Required
  status: string;
  points: number;
  listingsCount: number;
  walletBalance: number;
  currencyPreference: string;
  trustScore: number;
  badges: string[];
  subscription?: {
    tier: string;
    expiresAt: string;
  };
  payoutMethods: PayoutMethods;
  blockedUsers: string[]; // For Blocked List feature
  isVerified?: boolean;
}

export interface SubscriptionPlan {
  id: string;
  name: string;
  description: string;
  isSpecial?: boolean;
  pricing: {
    daily: number;
    monthly: number;
    yearly: number;
  };
  features: string[];
}

export enum ListingType {
  RENT = 'RENT'
}

export enum CurrencyType {
  CRYPTO = 'CRYPTO',
  LOCAL = 'LOCAL'
}

export enum RentalPeriod {
  DAY = 'DAY',
  WEEK = 'WEEK',
  MONTH = 'MONTH',
  YEAR = 'YEAR'
}

export interface Listing {
  id: string;
  ownerId: string;
  ownerName: string;
  ownerUsername: string;
  ownerAvatar: string;
  title: string;
  description: string;
  type: ListingType;
  price: number;
  currency: string;
  currencyType: CurrencyType;
  payoutMethod: 'PAYPAL' | 'CRYPTO';
  payoutAddress: string;
  cryptoCurrency?: string;
  category: string;
  location: { lat: number; lng: number; address: string };
  images: string[];
  video?: string;
  createdAt: string;
  rentalPeriod: RentalPeriod;
  views: number;
  likes: number;
  rating: number;
  isAiApproved: boolean;
  unavailableDates: string[];
  status: 'DRAFT' | 'AI_REVIEW' | 'PUBLISHED' | 'REJECTED';
  visibility: 'PUBLIC' | 'PRIVATE';
  review_state: 'PENDING' | 'APPROVED' | 'REJECTED';
  published_at: string | null;
  updated_at: string;
  is_deleted: boolean;
}

export interface GroupChat {
  id: string;
  name: string;
  description: string;
  image: string;
  adminId: string; // Admin is the creator
  members: string[];
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useParams } from 'react-router-dom';
import { User, Gender, Listing, PayoutMethods } from './types';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import ListingCard from './components/ListingCard';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import SubscriptionPage from './pages/SubscriptionPage';
import ProfessionalDashboardPage from './pages/ProfessionalDashboardPage';
import BlockedUsersPage from './pages/BlockedUsersPage';
import { translations } from './i18n';
import { POINTS_SYSTEM, CURRENCIES, CONTACT_EMAIL } from './constants';
import { 
  Camera, 
  MapPin, 
  ShieldCheck, 
  User as UserIcon, 
  Settings,
  ShieldBan,
  Wallet
} from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>(() => localStorage.getItem('my_rents_lang') || 'ar');
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('my_rents_theme') === 'dark');

  const [user, setUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('my_rents_user');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  });

  const [allListings, setAllListings] = useState<Listing[]>(() => {
    try {
      const saved = localStorage.getItem('my_rents_listings');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('my_rents_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('my_rents_theme', isDarkMode ? 'dark' : 'light');
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => {
    if (user) localStorage.setItem('my_rents_user', JSON.stringify(user));
    else localStorage.removeItem('my_rents_user');
  }, [user]);

  useEffect(() => {
    localStorage.setItem('my_rents_listings', JSON.stringify(allListings));
  }, [allListings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    setUser(prev => prev ? { ...prev, points: prev.points + amount } : null);
  };

  const handleCurrencyChange = (code: string) => {
    setUser(prev => prev ? { ...prev, currencyPreference: code } : null);
  };

  const handleUpdatePayout = (data: Partial<PayoutMethods>) => {
    setUser(prev => prev ? { ...prev, payoutMethods: { ...prev.payoutMethods, ...data } } : null);
  };

  const handleBlockUser = (otherId: string) => {
    if (!user) return;
    setUser(prev => prev ? { ...prev, blockedUsers: [...(prev.blockedUsers || []), otherId] } : null);
  };

  const handleUnblockUser = (otherId: string) => {
    if (!user) return;
    setUser(prev => prev ? { ...prev, blockedUsers: (prev.blockedUsers || []).filter(id => id !== otherId) } : null);
  };

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    if (!data.avatar || !data.fullName || !data.username || !data.email || !data.password || !data.agreed || !data.location) {
      alert(lang === 'ar' ? 'يرجى إكمال جميع الحقول المطلوبة والموافقة على الشروط' : 'Please complete all required fields and accept terms');
      return;
    }

    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
      status: 'Member',
      points: 100,
      listingsCount: 0,
      walletBalance: 0,
      currencyPreference: 'USD',
      trustScore: 75,
      badges: ['NEW_MEMBER'],
      payoutMethods: {},
      blockedUsers: [],
      isVerified: true
    };
    setUser(newUser);
  };

  const ProfileView = () => {
    const { username } = useParams<{ username?: string }>();
    const isSelf = !username || (user && username === user.username);
    const displayUser = isSelf ? user : null; 
    const userSpecificListings = allListings.filter(l => l.ownerUsername === (username || user?.username));

    const [isEditingPayout, setIsEditingPayout] = useState(false);

    return (
      <div className="p-4 sm:p-8 text-center max-w-4xl mx-auto animate-in fade-in">
        <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-6 sm:p-10 shadow-sm border dark:border-gray-800 relative overflow-hidden">

          <div className="relative inline-block mb-6">
            <img src={displayUser?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${username || user?.username}`} className="w-24 h-24 sm:w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl" />
            <div className="absolute -bottom-1 -right-1 bg-brand text-white p-1.5 rounded-xl shadow-lg border-2 border-white dark:border-gray-900">
              <ShieldCheck size={16} fill="currentColor" />
            </div>
          </div>

          <h1 className="text-2xl sm:text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{displayUser?.fullName || username || user?.fullName}</h1>
          <p className="text-[#CCCCCC] mb-6 font-bold text-sm">@{username || user?.username}</p>

          {isSelf && (
            <div className="mb-8 space-y-4">
               <div className="flex gap-2">
                 <button onClick={() => setIsEditingPayout(!isEditingPayout)} className="flex-1 py-4 bg-gray-50 dark:bg-gray-800 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2">
                   <Wallet size={16} /> {lang === 'ar' ? 'إعدادات الدفع' : 'Payout Settings'}
                 </button>
                 <Link to="/blocked-users" className="py-4 px-6 bg-red-50 dark:bg-red-900/10 text-red-500 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2">
                   <ShieldBan size={16} /> {t.blockedUsers}
                 </Link>
               </div>

               {isEditingPayout && (
                 <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] text-left space-y-4 animate-in slide-in-from-top-4">
                    <p className="text-[9px] font-black text-brand uppercase tracking-widest mb-2 italic">Set your payout addresses:</p>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                       {['solana', 'ethereum', 'monad', 'base', 'sui', 'polygon', 'bitcoin', 'paypal'].map(key => (
                         <div key={key}>
                           <label className="text-[8px] font-black uppercase text-gray-400 ml-2">{key}</label>
                           <input 
                             type="text" 
                             placeholder={key === 'paypal' ? 'PayPal Email...' : `${key} address...`} 
                             value={(user?.payoutMethods as any)?.[key] || ''} 
                             onChange={e => handleUpdatePayout({ [key]: e.target.value })}
                             className="w-full p-3 bg-white dark:bg-gray-900 rounded-xl text-[10px] outline-none border border-transparent focus:border-brand"
                           />
                         </div>
                       ))}
                    </div>
                 </div>
               )}
            </div>
          )}

          <div className="grid grid-cols-2 gap-3 mb-10">
             <div className="p-4 sm:p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[9px] text-gray-400 font-black uppercase block mb-1">Trust Score</span>
                <span className="text-2xl font-black text-brand">{isSelf ? user?.trustScore : '88'}%</span>
             </div>
             <div className="p-4 sm:p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[9px] text-gray-400 font-black uppercase block mb-1">Points</span>
                <span className="text-2xl font-black text-brand">{isSelf ? user?.points : '1.2k'}</span>
             </div>
          </div>

          <div className="mb-10 text-left">
            <h2 className="text-lg font-black dark:text-white uppercase tracking-tighter mb-4 px-2">Listings</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {userSpecificListings.length > 0 ? userSpecificListings.map(l => (
                <ListingCard key={l.id} listing={l} lang={lang} isOwner={l.ownerId === user?.id} onDelete={(id) => setAllListings(prev => prev.filter(item => item.id !== id))} onAddPoints={addPoints} />
              )) : (
                <div className="col-span-2 py-10 text-center opacity-20">
                   <p className="text-[9px] font-black uppercase">No Listings</p>
                </div>
              )}
            </div>
          </div>

          {isSelf && (
            <div className="flex flex-col gap-2">
              <Link to="/subscription" className="w-full py-4 bg-brand text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-brand/20">
                Premium Subscription
              </Link>
              <button onClick={() => { setUser(null); localStorage.clear(); window.location.reload(); }} className="w-full mt-2 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline">
                {t.logout}
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  const SignUpPage = () => {
    const [step, setStep] = useState(1);
    const [isLocating, setIsLocating] = useState(false);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', 
      location: null as any,
      email: '', password: '', agreed: false
    });

    const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (ev) => setSignupData({ ...signupData, avatar: ev.target?.result as string });
        reader.readAsDataURL(file);
      }
    };

    const handleGetLocation = () => {
      setIsLocating(true);
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(
          (pos) => {
            setSignupData({
              ...signupData,
              location: { address: 'Local User Location', lat: pos.coords.latitude, lng: pos.coords.longitude }
            });
            setIsLocating(false);
          },
          () => {
            alert(lang === 'ar' ? 'فشل جلب الموقع' : 'Location access denied');
            setIsLocating(false);
          }
        );
      }
    };

    return (
      <div className="w-full max-w-xl px-6 py-12 mx-auto animate-in fade-in">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-black text-brand italic mb-2 tracking-tighter uppercase">my rents</h1>
          <h2 className="text-xl font-bold dark:text-white uppercase tracking-tighter">{t.signUp}</h2>
          <p className="text-[10px] text-gray-400 mt-2 font-black uppercase tracking-widest">{t.step} {step} of 2</p>
        </div>

        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          {step === 1 && (
            <div className="space-y-6">
              <div className="flex flex-col items-center gap-4">
                <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-dashed border-gray-200 dark:border-gray-700 overflow-hidden flex items-center justify-center cursor-pointer group transition-all hover:border-brand">
                  {signupData.avatar ? (
                    <img src={signupData.avatar} className="w-full h-full object-cover" />
                  ) : (
                    <Camera size={32} className="text-gray-300 group-hover:text-brand" />
                  )}
                  <input type="file" required className="hidden" accept="image/*" onChange={handleAvatarUpload} />
                </label>
                <p className="text-[9px] font-black uppercase text-gray-400 italic">Profile Picture Required</p>
              </div>
              <div className="space-y-4">
                <input type="text" placeholder={t.fullName + ' *'} required value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
                <input type="text" placeholder={t.username + ' *'} required value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />

                <button 
                  type="button" 
                  onClick={handleGetLocation}
                  className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-[10px] transition-all ${signupData.location ? 'bg-green-500 text-white' : 'bg-gray-50 dark:bg-gray-800 text-gray-400 border border-transparent active:border-brand'}`}
                >
                  {isLocating ? '📍 Locating...' : signupData.location ? '📍 Location Verified' : '📍 Set My Location (Required)'}
                </button>
              </div>
              <button 
                type="button" 
                onClick={() => setStep(2)} 
                disabled={!signupData.avatar || !signupData.fullName || !signupData.username || !signupData.location}
                className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30"
              >
                Next Step
              </button>
            </div>
          )}
          {step === 2 && (
            <div className="space-y-6">
              <input type="email" placeholder={t.email + ' *'} required value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
              <input type="password" placeholder={t.password + ' *'} required value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
              <div className="flex items-start gap-3 p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
                <input type="checkbox" id="agree" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-5 h-5 accent-brand mt-1" />
                <label htmlFor="agree" className="text-[10px] font-bold text-gray-500 leading-relaxed uppercase">
                  {t.acceptTerms}
                  <div className="mt-2 flex gap-4">
                     <Link to="/privacy" className="text-brand underline">{t.privacyPolicy}</Link>
                     <Link to="/terms" className="text-brand underline">{t.termsOfUse}</Link>
                  </div>
                </label>
              </div>
              <div className="flex gap-4">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 rounded-[2rem] font-black text-[10px] uppercase">Back</button>
                <button type="submit" disabled={!signupData.email || !signupData.password || !signupData.agreed} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30">Finish Sign Up</button>
              </div>
            </div>
          )}
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200 flex flex-col`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} onLangChange={setLang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} onCurrencyChange={handleCurrencyChange} />}
        <main className={`flex-1 ${user ? 'pb-20' : ''}`}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={allListings} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setAllListings(prev => [...prev, l])} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} onForcePublish={() => {}} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
                <Route path="/chat/:otherId?" element={<ChatPage lang={lang} onAddPoints={addPoints} listings={allListings} user={user} onBlock={handleBlockUser} />} />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/blocked-users" element={<BlockedUsersPage lang={lang} user={user} onUnblock={handleUnblockUser} />} />
                <Route path="/pro-dashboard" element={user?.subscription?.tier ? <ProfessionalDashboardPage lang={lang} user={user} /> : <Navigate to="/subscription" />} />
              </>
            )}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
        <Footer lang={lang} />
      </div>
    </HashRouter>
  );
};

export default App;

