  const discussedItem = useMemo(() => {
    return itemId ? listings.find(l => l.id === itemId) : null;
  }, [itemId, listings]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = (type: ChatMessage['type'] = 'text', data?: string) => {
    if (type === 'text' && !input.trim()) return;

    const newMessage: ChatMessage = {
      id: Date.now(),
      text: type === 'text' ? input : undefined,
      data: data,
      sender: 'me',
      type,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    if (type === 'text') setInput('');
    onAddPoints?.(type === 'text' ? POINTS_SYSTEM.MESSAGE : POINTS_SYSTEM.ATTACHMENT);
  };

  const shareLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          handleSend('location', `${pos.coords.latitude},${pos.coords.longitude}`);
          setIsLocating(false);
        },
        () => { setIsLocating(false); alert('Location access denied'); }
      );
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      handleSend('voice', 'MOCKED_VOICE_DATA');
      setIsRecording(false);
    } else {
      setIsRecording(true);
    }
  };

  const handleBlockAction = () => {
    if (otherId) {
      onBlock(otherId);
      alert(t.userBlocked);
      navigate('/');
    }
  };

  const handleCreateGroup = () => {
    if (groupData.name && groupData.image) {
      alert(lang === 'ar' ? `تم إطلاق مجتمع ${groupData.name}! أنت الآن المشرف.` : `${groupData.name} launched! You are the Admin.`);
      setShowGroupCreate(false);
    }
  };

  const renderContent = (m: ChatMessage) => {
    switch (m.type) {
      case 'location':
        return (
          <div className="space-y-2 p-2 min-w-[150px]">
             <div className="h-20 bg-gray-100 dark:bg-gray-700 rounded-xl flex items-center justify-center">
                <MapPin className="text-brand animate-bounce" />
             </div>
             <a href={`https://www.google.com/maps?q=${m.data}`} target="_blank" className="block text-[8px] font-black text-brand text-center uppercase underline">{t.location}</a>
          </div>
        );
      case 'image': return <img src={m.data} className="rounded-xl max-w-full" />;
      case 'video': return <video src={m.data} controls className="rounded-xl max-w-full" />;
      case 'voice': return <div className="flex items-center gap-2 p-2"><Mic size={14} className="text-brand" /><div className="h-1 flex-1 bg-brand/20 rounded-full overflow-hidden"><div className="w-1/2 h-full bg-brand"></div></div><span className="text-[8px] font-bold">0:05</span></div>;
      default: return <p className="whitespace-pre-wrap">{m.text}</p>;
    }
  };

  return (
    <div className="max-w-7xl mx-auto flex h-[calc(100vh-140px)] mt-2 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 animate-in fade-in duration-500">
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => {
        const file = e.target.files?.[0];
        if (file) {
          const r = new FileReader();
          r.onload = (ev) => handleSend('image', ev.target?.result as string);
          r.readAsDataURL(file);
        }
      }} />
      <input type="file" ref={videoInputRef} className="hidden" accept="video/*" onChange={e => {
        const file = e.target.files?.[0];
        if (file) {
          const r = new FileReader();
          r.onload = (ev) => handleSend('video', ev.target?.result as string);
          r.readAsDataURL(file);
        }
      }} />

      {/* Sidebar */}
      <div className="w-80 border-r dark:border-gray-800 flex flex-col bg-gray-50/20 dark:bg-gray-950/20 shrink-0">
        <div className="p-6">
          <h1 className="text-xl font-black text-brand uppercase italic tracking-tighter mb-6">my rents chat</h1>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>Private</button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>{t.groups}</button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-4 pb-10">
          {activeTab === 'GROUPS' && (
            <button onClick={() => setShowGroupCreate(true)} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl flex items-center justify-center gap-2 text-gray-400 font-bold text-[10px] uppercase hover:text-brand hover:border-brand transition-all mb-4">
               <UserPlus size={16} /> {t.createGroup}
            </button>
          )}
          <div className="py-20 text-center opacity-10 flex flex-col items-center">
            <MessageSquareOff size={48} className="text-brand mb-2" />
            <p className="text-[9px] font-black uppercase tracking-widest">{lang === 'ar' ? 'لا توجد محادثات' : 'No chats found'}</p>
          </div>
        </div>
