                    <textarea placeholder={t.groupDescription + ' *'} required value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-100 dark:bg-gray-800 dark:text-white h-24 outline-none font-bold" />
                 </div>
                 <div className="p-4 bg-brand/5 border border-brand/10 rounded-2xl flex items-center gap-3">
                    <Settings className="text-brand" size={18} />
                    <p className="text-[9px] font-black text-brand uppercase">{lang === 'ar' ? 'أنت المشرف التلقائي لهذه المجموعة' : 'You are the automatic admin of this community'}</p>
