                 <button onClick={handleCreateGroup} disabled={!groupData.name || !groupData.image} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30 active:scale-95 transition-all">{t.launchGroup}</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default ChatPage;

