          ))}

          <div className="p-6 bg-brand/5 border border-brand/10 rounded-3xl flex items-center gap-4">
             <ShieldCheck className="text-brand shrink-0" size={24} />
             <p className="text-[10px] font-bold text-gray-500 uppercase leading-relaxed">{lang === 'ar' ? 'نحن ملتزمون بتشفير كافة بياناتك المالية ولا نشاركها مع أي طرف ثالث تحت أي ظرف.' : 'We are committed to encrypting all your financial data and do not share it with third parties.'}</p>
          </div>
        </div>

        <button onClick={() => navigate(-1)} className="mt-12 w-full py-5 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-[2rem] font-black uppercase tracking-widest text-xs hover:bg-gray-200 transition-all">{t.back}</button>
      </div>
    </div>
  );
};

