import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing } from '../types';
import { MapPin, Star, Share2, Heart, MessageCircle, ArrowLeft, Flag, Eye, ShieldCheck, Trash2, Box, Info, Zap, Clock, CreditCard } from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ItemDetailPageProps {
  lang: string;
  user?: any;
  listings: Listing[];
  onDelete?: (id: string) => void;
  onAddPoints: (a: number) => void;
  onForcePublish: (id: string, updates: Partial<Listing>) => void;
}

const ItemDetailPage: React.FC<ItemDetailPageProps> = ({ lang, user, listings, onDelete, onAddPoints, onForcePublish }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [isLiked, setIsLiked] = useState(false);

  const item = listings.find(l => l.id === id);

  if (!item) {
    return (
      <div className="max-w-4xl mx-auto py-20 text-center">
        <Box size={64} className="mx-auto text-gray-200 mb-4" />
        <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{lang === 'ar' ? 'المنتج غير موجود' : 'Item Not Found'}</h2>
        <button onClick={() => navigate('/')} className="mt-6 px-8 py-3 bg-brand text-white rounded-2xl font-bold">{t.back}</button>
      </div>
    );
  }

  const isOwner = user?.id === item.ownerId;

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `my rents: ${item.title}`,
          text: item.description,
          url: window.location.href,
        });
        onAddPoints(POINTS_SYSTEM.SHARE);
      } catch (err) {}
    } else {
      navigator.clipboard.writeText(window.location.href);
      alert(lang === 'ar' ? 'رابط المشاركة منسوخ! +10 نقاط' : 'Share link copied! +10 Points');
      onAddPoints(POINTS_SYSTEM.SHARE);
    }
  };

  const handleReport = () => {
    alert(lang === 'ar' ? 'تم إرسال بلاغك. سيقوم نظام AI my rents بإعادة فحص المنتج.' : 'Report sent. AI my rents will re-examine this item.');
  };

  return (
    <div className="max-w-6xl mx-auto p-4 pt-8 animate-in fade-in">
      <div className="flex items-center justify-between mb-6">
        <button onClick={() => navigate(-1)} className="p-3 rounded-2xl bg-white dark:bg-gray-900 shadow-sm dark:text-white">
          <ArrowLeft className={lang === 'ar' ? 'rotate-180' : ''} />
        </button>
        <div className="flex gap-2">
          {isOwner && <button onClick={() => {onDelete?.(id!); navigate('/')}} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/20 rounded-2xl hover:scale-105 transition-all"><Trash2 size={20} /></button>}
          <button onClick={handleReport} className="p-3 text-red-500 bg-red-50 rounded-2xl" title={t.report}><Flag size={20} /></button>
          <button onClick={handleShare} className="p-3 bg-brand text-white rounded-2xl hover:scale-105 transition-all"><Share2 size={20} /></button>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 grid grid-cols-1 lg:grid-cols-2">
        <div className="bg-black space-y-1">
          {item.images.map((img, i) => <img key={i} src={img} className="w-full aspect-square object-cover" />)}
          {item.video && <video src={item.video} controls className="w-full aspect-video" />}
        </div>

        <div className="p-10 flex flex-col">
          <div className="flex items-center gap-3 mb-8 pb-8 border-b dark:border-gray-800">
            <img src={item.ownerAvatar} className="w-14 h-14 rounded-full border-2 border-brand object-cover" />
            <div>
              <h2 className="font-black dark:text-white uppercase leading-tight">{item.ownerName}</h2>
              <p className="text-sm font-bold text-[#CCCCCC]">@{item.ownerUsername}</p>
            </div>
            <div className={`ml-auto flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-black uppercase ${item.status === 'PUBLISHED' ? 'text-green-500 bg-green-50 dark:bg-green-900/20' : 'text-yellow-500 bg-yellow-50 dark:bg-yellow-900/20'}`}>
              <ShieldCheck size={12} /> {item.status === 'PUBLISHED' ? 'SECURE' : 'REVIEW'}
            </div>
          </div>

          <h1 className="text-3xl font-black dark:text-white mb-2 uppercase tracking-tighter leading-none">{item.title}</h1>
          <span className="text-[10px] font-black text-brand bg-brand/10 w-fit px-3 py-1 rounded-full uppercase tracking-widest mb-6">{item.category}</span>

          <div className="flex gap-4 mb-8 text-[10px] font-black text-gray-400 uppercase">
            <div className="flex items-center gap-1"><Eye size={14} className="text-brand" /> {item.views} {t.views}</div>
            <div className="flex items-center gap-1"><Star size={14} className="text-yellow-500" /> {item.rating}</div>
            <div className="flex items-center gap-1"><Clock size={14} className="text-brand" /> {t.periods[item.rentalPeriod]}</div>
          </div>

          <div className="space-y-6 flex-1 overflow-y-auto pr-2 scrollbar-hide mb-8">
            <div>
              <h3 className="text-xs font-black text-brand uppercase mb-2">{t.description}</h3>
              <p className="text-sm text-gray-500 dark:text-gray-400 leading-relaxed">{item.description}</p>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
                <span className="text-[10px] text-gray-400 font-black block mb-1 uppercase">{t.payoutMethod}</span>
                <span className="text-xs font-black dark:text-white uppercase">{item.payoutMethod === 'CRYPTO' ? item.cryptoCurrency : 'PayPal'}</span>
              </div>
              <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
                <span className="text-[10px] text-gray-400 font-black block mb-1 uppercase">{t.location}</span>
                <span className="text-xs font-black dark:text-white truncate block uppercase">{item.location.address}</span>
              </div>
            </div>
          </div>

          <div className="mt-auto pt-8 border-t dark:border-gray-800 flex items-center justify-between">
            <div className="flex flex-col">
              <div className="flex items-baseline gap-1">
                <span className="text-3xl font-black text-brand">{item.price}</span>
                <span className="text-xs font-bold text-gray-400">{item.currency}</span>
              </div>
              <span className="text-[10px] font-black text-gray-400 uppercase">Per {t.periods[item.rentalPeriod]}</span>
