import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useLocation as useRouteLocation, useParams, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing } from '../types';
import { 
  Trash2, 
  MapPin, 
  Flag, 
  Send, 
  UserPlus, 
  ShieldCheck, 
  Camera, 
  MoreVertical, 
  Loader2, 
  MessageSquareOff, 
  Mic, 
  ShieldBan,
  Settings,
  X,
  Play,
  Video,
  ChevronLeft
} from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ChatMessage {
  id: number;
  text?: string;
  sender: 'me' | 'other';
  type: 'text' | 'image' | 'video' | 'location' | 'voice';
  data?: string;
  timestamp: number;
}

const ChatPage: React.FC<{ lang: string; listings: Listing[]; user: any; onBlock: (id: string) => void; onAddPoints?: (a: number) => void }> = ({ lang, listings, user, onBlock, onAddPoints }) => {
  const t = translations[lang] || translations['en'];
  const { otherId } = useParams();
  const routeLocation = useRouteLocation();
  const navigate = useNavigate();
  const queryParams = new URLSearchParams(routeLocation.search);
  const itemId = queryParams.get('item');

  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [showGroupCreate, setShowGroupCreate] = useState(false);
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });
  const [isLocating, setIsLocating] = useState(false);

  const discussedItem = useMemo(() => itemId ? listings.find(l => l.id === itemId) : null, [itemId, listings]);

  const handleSend = (type: ChatMessage['type'] = 'text', data?: string) => {
    if (type === 'text' && !input.trim()) return;
    const msg: ChatMessage = { id: Date.now(), text: input, sender: 'me', type, data, timestamp: Date.now() };
    setMessages([...messages, msg]);
    if (type === 'text') setInput('');
    onAddPoints?.(POINTS_SYSTEM.MESSAGE);
  };

  const shareLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(pos => {
        handleSend('location', `${pos.coords.latitude},${pos.coords.longitude}`);
        setIsLocating(false);
      }, () => setIsLocating(false));
    }
  };

  const handleCreateGroup = () => {
    if (groupData.name && groupData.image) {
      alert(lang === 'ar' ? 'تم إنشاء المجموعة بنجاح! أنت المشرف التلقائي.' : 'Group created! You are the automatic admin.');
      setShowGroupCreate(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto flex h-[calc(100vh-140px)] mt-2 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 animate-in fade-in">
      {/* Sidebar */}
      <div className="w-80 border-r dark:border-gray-800 flex flex-col bg-gray-50/20 dark:bg-gray-950/20 shrink-0">
        <div className="p-6">
          <h1 className="text-xl font-black text-brand uppercase italic tracking-tighter mb-6">my rents chat</h1>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>Private</button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.groups}</button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto px-4 pb-10">
           {activeTab === 'GROUPS' && (
             <button onClick={() => setShowGroupCreate(true)} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl text-[10px] font-black uppercase text-gray-400 mb-4 hover:border-brand hover:text-brand transition-all flex items-center justify-center gap-2">
               <UserPlus size={16} /> {t.createGroup}
             </button>
           )}
           <div className="py-20 text-center opacity-10 flex flex-col items-center">
              <MessageSquareOff size={48} className="text-brand mb-2" />
              <p className="text-[9px] font-black uppercase tracking-widest">{lang === 'ar' ? 'لا توجد محادثات' : 'No chats found'}</p>
           </div>
        </div>
      </div>

      {/* Chat Container */}
      <div className="flex-1 flex flex-col bg-white dark:bg-gray-900 relative">
        <div className="p-4 border-b dark:border-gray-800 flex justify-between items-center bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm z-10">
           <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand"><ShieldCheck size={24} /></div>
              <div><h2 className="font-black dark:text-white text-xs uppercase tracking-tighter italic">AI SECURE CHANNEL</h2><span className="text-[8px] text-green-500 font-black uppercase">Active</span></div>
           </div>
           <div className="flex gap-1">
              <button onClick={() => setMessages([])} className="p-2 text-gray-400 hover:text-red-500" title={t.clearChat}><Trash2 size={18} /></button>
              <button onClick={() => { otherId && onBlock(otherId); navigate('/'); }} className="p-2 text-gray-400 hover:text-brand" title={t.blockUser}><ShieldBan size={18} /></button>
              <button onClick={() => alert('Report logged.')} className="p-2 text-gray-400 hover:text-brand" title={t.report}><Flag size={18} /></button>
           </div>
        </div>

        {discussedItem && (
          <div className="p-3 bg-brand/5 border-b border-brand/10 flex items-center justify-between animate-in slide-in-from-top">
             <div className="flex items-center gap-2">
                <img src={discussedItem.images[0]} className="w-10 h-10 rounded-lg object-cover border border-brand/20 shadow-sm" />
                <p className="text-[10px] font-black dark:text-white uppercase truncate max-w-[150px]">{discussedItem.title}</p>
             </div>
             <button onClick={() => alert(t.confirmRental)} className="px-5 py-2 bg-brand text-white rounded-xl text-[9px] font-black uppercase shadow-lg active:scale-95 transition-all">RENT NOW</button>
          </div>
        )}

        <div className="flex-1 p-6 overflow-y-auto space-y-4">
           {messages.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-20 text-center px-10">
                <ShieldCheck size={64} className="text-brand mb-4" />
                <p className="text-[10px] font-black dark:text-white uppercase tracking-widest leading-relaxed">
                  {lang === 'ar' ? 'ابدأ الحديث هنا. جميع الرسائل مشفرة ومحمية.' : 'Start talking here. All messages are encrypted and safe.'}
                </p>
             </div>
           ) : messages.map(m => (
             <div key={m.id} className={`flex ${m.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                <div className={`p-4 rounded-[1.8rem] shadow-sm text-xs font-bold ${m.sender === 'me' ? 'bg-brand text-white rounded-tr-none' : 'bg-gray-100 dark:bg-gray-800 dark:text-white rounded-tl-none'}`}>
                   {m.type === 'location' ? (
                     <a href={`https://maps.google.com?q=${m.data}`} target="_blank" className="flex items-center gap-2 underline uppercase text-[10px]">
                       <MapPin size={14} /> View Location
                     </a>
                   ) : m.text}
                </div>
             </div>
           ))}
        </div>

        {/* Input Controls */}
        <div className="p-6 border-t dark:border-gray-800 bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm">
           <div className="flex gap-2 mb-4 overflow-x-auto pb-1 scrollbar-hide">
              <button onClick={() => setIsRecording(!isRecording)} className={`flex items-center gap-2 px-4 py-2 rounded-2xl text-[9px] font-black uppercase transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>
                <Mic size={14} /> {isRecording ? 'Recording...' : t.voice}
              </button>
              <label className="flex items-center gap-2 px-4 py-2 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand">
                <Camera size={14} /> Images
                <input type="file" className="hidden" accept="image/*" onChange={e => handleSend('image', 'IMAGE_DATA')} />
              </label>
              <label className="flex items-center gap-2 px-4 py-2 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand">
                <Video size={14} /> Video
                <input type="file" className="hidden" accept="video/*" onChange={e => handleSend('video', 'VIDEO_DATA')} />
              </label>
              <button onClick={shareLocation} disabled={isLocating} className="flex items-center gap-2 px-4 py-2 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 hover:text-brand disabled:opacity-50">
                {isLocating ? <Loader2 size={14} className="animate-spin" /> : <MapPin size={14} />} {t.location}
              </button>
           </div>
           <div className="flex gap-2">
              <input 
                type="text" 
                value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyDown={e => e.key === 'Enter' && handleSend()} 
                className="flex-1 bg-gray-100 dark:bg-gray-800 dark:text-white px-8 py-5 rounded-[2.2rem] outline-none font-bold text-sm shadow-inner" 
                placeholder={lang === 'ar' ? 'اكتب هنا...' : 'Type message...'} 
              />
              <button onClick={() => handleSend()} className="w-16 h-16 bg-brand text-white rounded-[1.8rem] flex items-center justify-center shadow-xl shadow-brand/20 active:scale-95 transition-all"><Send size={24} /></button>
           </div>
        </div>
      </div>

      {/* Group Create Modal */}
      {showGroupCreate && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/60 backdrop-blur-md">
           <div className="bg-white dark:bg-gray-900 w-full max-w-sm rounded-[3rem] p-8 shadow-2xl animate-in zoom-in-95">
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-xl font-black dark:text-white uppercase italic tracking-tighter">New Community</h3>
                 <button onClick={() => setShowGroupCreate(false)}><X size={24} className="text-gray-400" /></button>
              </div>
              <div className="space-y-4">
                 <label className="w-24 h-24 rounded-[2rem] bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-dashed border-brand/20 cursor-pointer overflow-hidden group">
                    {groupData.image ? <img src={groupData.image} className="w-full h-full object-cover" /> : <Camera className="text-gray-300 group-hover:text-brand" size={32} />}
                    <input type="file" required className="hidden" accept="image/*" onChange={e => e.target.files && setGroupData({...groupData, image: URL.createObjectURL(e.target.files[0])})} />
                 </label>
                 <input type="text" placeholder={t.groupName + '*'} required value={groupData.name} onChange={e => setGroupData({...groupData, name: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-100 dark:bg-gray-800 dark:text-white outline-none font-bold text-xs" />
                 <textarea placeholder={t.groupDescription + '*'} required value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-100 dark:bg-gray-800 dark:text-white h-24 outline-none font-bold text-xs" />
                 <div className="p-4 bg-brand/5 border border-brand/10 rounded-2xl flex items-center gap-3">
                    <Settings className="text-brand" size={16} />
                    <p className="text-[9px] font-black text-brand uppercase">{lang === 'ar' ? 'أنت المشرف التلقائي لهذه المجموعة' : 'You are the automatic admin of this community'}</p>
                 </div>
                 <button onClick={handleCreateGroup} disabled={!groupData.name || !groupData.image} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 active:scale-95 transition-all">Launch Community</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

