import { useNavigate } from 'react-router-dom';

const CRYPTO_CURRENCIES = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | undefined>(undefined);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [payoutMethod, setPayoutMethod] = useState<'CRYPTO' | 'PAYPAL'>('PAYPAL');
  const [selectedCrypto, setSelectedCrypto] = useState(CRYPTO_CURRENCIES[0]);
  const [payoutAddress, setPayoutAddress] = useState('');

  const handleEstimate = async () => {
    if (!title || !description) return;
    setEstimating(true);
    const est = await estimateRentalPrice(title, description, user.currencyPreference || 'USD');
    setPrice(est.toString());
    setEstimating(false);
  };

  const handlePublish = async () => {
    if (images.length < 2) { alert(t.minImages); return; }
    setLoading(true);

    // Mandatory AI Check
    const moderation = await checkListingContent(title, description);
    if (moderation.status === 'REJECTED') { 
      alert(moderation.reason); 
      setLoading(false); 
      return; 
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: payoutMethod === 'CRYPTO' ? CurrencyType.CRYPTO : CurrencyType.LOCAL,
      payoutMethod,
      cryptoCurrency: payoutMethod === 'CRYPTO' ? selectedCrypto : undefined,
      payoutAddress,
      category,
      location: user.location,
      images,
      video,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: true,
      unavailableDates: [],
      status: 'PUBLISHED',
      visibility: 'PUBLIC',
      review_state: 'APPROVED',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(6);
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-8 shadow-2xl border dark:border-gray-800">
      <div className="flex gap-2 mb-8">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/10 border-2 border-red-100 rounded-[1.5rem] flex items-center gap-3">
        <AlertTriangle className="text-red-600" size={24} />
        <p className="text-[10px] font-black text-red-700 uppercase italic">{t.rentalsOnly}</p>
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-xl font-black dark:text-white uppercase italic text-center">{lang === 'ar' ? 'الصور والفيديو' : 'Media Assets'}</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-[1.5rem] overflow-hidden group">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-2 right-2 bg-red-500 text-white p-1 rounded-full">×</button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[1.5rem] border-4 border-dashed border-gray-200 dark:border-gray-700 flex flex-col items-center justify-center text-gray-400 cursor-pointer">
                <Camera size={32} />
                <span className="text-[9px] font-black uppercase mt-1">{images.length}/5</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={e => {
                  // Fix: Properly handle FileList and cast to File array to avoid 'unknown' type issues with readAsDataURL
                  const files = Array.from(e.target.files || []) as File[];
                  files.forEach((f: File) => {
                    const r = new FileReader();
                    r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
                    r.readAsDataURL(f);
                  });
                }} />
              </label>
            )}
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-center justify-between">
             <div className="flex items-center gap-2"><VideoIcon size={18} className="text-brand" /><span className="text-[10px] font-black uppercase text-gray-400">{lang === 'ar' ? 'فيديو المنتج (اختياري)' : 'Video (Optional)'}</span></div>
             <input type="file" accept="video/*" className="text-[10px]" onChange={e => {
               // Fix: Cast target files to ensure File type is available
               const f = (e.target.files?.[0]) as File | undefined;
               if (f) { const r = new FileReader(); r.onload = (ev) => setVideo(ev.target?.result as string); r.readAsDataURL(f); }
             }} />
          </div>
          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-4 bg-brand text-white rounded-[1.5rem] font-black uppercase disabled:opacity-30 transition-all shadow-xl shadow-brand/20">Continue</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-xl font-black dark:text-white uppercase italic text-center">{lang === 'ar' ? 'بيانات المنتج' : 'Item Info'}</h2>
          <input type="text" placeholder={lang === 'ar' ? 'اسم المنتج*' : 'Product Name*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none font-bold shadow-inner" />
          <textarea placeholder={t.description + '*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none h-32 font-bold shadow-inner" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none font-bold">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Continue</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-xl font-black dark:text-white uppercase italic text-center">{lang === 'ar' ? 'طريقة الربح' : 'Payout Preference'}</h2>
          <div className="grid grid-cols-2 gap-4">
             <button onClick={() => setPayoutMethod('PAYPAL')} className={`p-8 rounded-[2rem] border-4 flex flex-col items-center gap-2 ${payoutMethod === 'PAYPAL' ? 'border-brand bg-brand/5' : 'border-transparent bg-gray-50'}`}>
                <CreditCard size={32} className={payoutMethod === 'PAYPAL' ? 'text-brand' : 'text-gray-400'} />
                <span className="text-[10px] font-black uppercase">PayPal</span>
             </button>
             <button onClick={() => setPayoutMethod('CRYPTO')} className={`p-8 rounded-[2rem] border-4 flex flex-col items-center gap-2 ${payoutMethod === 'CRYPTO' ? 'border-brand bg-brand/5' : 'border-transparent bg-gray-50'}`}>
                <Wallet size={32} className={payoutMethod === 'CRYPTO' ? 'text-brand' : 'text-gray-400'} />
                <span className="text-[10px] font-black uppercase">Crypto</span>
             </button>
          </div>

          {payoutMethod === 'CRYPTO' && (
            <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide">
               {CRYPTO_CURRENCIES.map(c => (
                 <button key={c} onClick={() => setSelectedCrypto(c)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase whitespace-nowrap ${selectedCrypto === c ? 'bg-brand text-white shadow-md' : 'bg-gray-100 text-gray-400'}`}>{c}</button>
               ))}
            </div>
          )}

          <div className="space-y-2">
            <p className="text-[10px] font-black text-gray-400 uppercase ml-4">{lang === 'ar' ? 'بيانات الدفع (مطلوب)' : 'Payment Details (Required)'}</p>
            <input type="text" value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} placeholder={payoutMethod === 'PAYPAL' ? 'PayPal Email*' : `${selectedCrypto} Address*`} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none font-bold shadow-inner" />
          </div>

          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!payoutAddress} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Next</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 animate-in slide-in-from-right text-center">
          <h2 className="text-xl font-black dark:text-white uppercase italic">{lang === 'ar' ? 'السعر والمدة' : 'Price & Duration'}</h2>
          <div className="flex items-center justify-center gap-3">
            <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-4 border-brand text-4xl font-black text-center dark:text-white outline-none" placeholder="0" />
            <span className="text-xl font-black text-brand">{user.currencyPreference || 'USD'}</span>
          </div>
          <button onClick={handleEstimate} disabled={estimating} className="px-6 py-2 bg-brand/10 text-brand rounded-xl font-black text-[9px] uppercase flex items-center gap-2 mx-auto">
            {estimating ? <Loader2 className="animate-spin" size={14} /> : <Sparkles size={14} />} {t.aiPriceEstimate}
          </button>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
            {Object.values(RentalPeriod).map(p => (
              <button key={p} onClick={() => setPeriod(p)} className={`py-3 rounded-xl font-black text-[8px] uppercase ${period === p ? 'bg-brand text-white' : 'bg-gray-100 text-gray-400'}`}>{t.periods[p]}</button>
            ))}
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-center justify-center gap-2 text-[10px] font-black uppercase text-gray-400">
             <MapPin size={16} className="text-brand" /> {user.location.address}
          </div>
          <div className="flex gap-4">
            <button onClick={() => setStep(3)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(5)} disabled={!price} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Finalize</button>
          </div>
        </div>
      )}

      {step === 5 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <ShieldCheck size={64} className="text-brand mx-auto animate-bounce" />
          <h2 className="text-2xl font-black dark:text-white uppercase italic">AI Verification</h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase max-w-xs mx-auto">AI my rents is checking your listing for safety and rent-only policy compliance.</p>
          <button onClick={handlePublish} disabled={loading} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} {t.securePublish}
          </button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center py-12 animate-in fade-in">
           <div className="w-24 h-24 bg-green-500 text-white rounded-[2rem] flex items-center justify-center mx-auto shadow-xl mb-6"><ArrowRight size={40} /></div>
           <h2 className="text-3xl font-black dark:text-white uppercase italic">{lang === 'ar' ? 'تم النشر بنجاح!' : 'Published!'}</h2>
           <button onClick={() => navigate('/')} className="mt-8 px-12 py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl">Back Home</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Review listing content for safety and guidelines
export const checkListingContent = async (title: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Review this rental listing for safety and community guidelines. Is it safe to publish? Reply with ONLY 'APPROVED' or 'REJECTED' followed by a short reason.
      Title: ${title}
      Description: ${description}`,
      config: {
        systemInstruction: "You are AI my rents. You must ensure all items are for RENT only. No illegal items. No sales.",
      }
    });
    // Access .text property directly
    const resultText = response.text || '';
    return resultText.includes('APPROVED') ? { status: 'APPROVED' } : { status: 'REJECTED', reason: resultText };
  } catch (error) {
    return { status: 'APPROVED' };
  }
};

// Estimate rental price using AI
export const estimateRentalPrice = async (title: string, description: string, currency: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate a fair DAILY rental price for this item in ${currency}. Reply with ONLY the numeric value.
      Item: ${title}
      Details: ${description}`,
    });
    // Access .text property directly
    const text = response.text;
    const priceStr = text?.replace(/[^0-9.]/g, '') || "10";
    return parseFloat(priceStr);
  } catch (error) {
    return 10;
  }
};

// Get AI customer support response
export const getAISupportResponse = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: "You are the helpful AI support agent for 'my rents', a peer-to-peer rental marketplace. Assist users with questions about listing items, renting, and earning points.",
      },
    });
    // Access .text property directly
    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("AI Support Error:", error);
    return "Support is currently unavailable. Please try again later.";
  }
};

// Discovery insights using Maps Grounding (supported on 2.5 series)
export const getDiscoveryInsights = async (location: string, query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Find me good places or types of items available for rent near ${location} for ${query}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: { latLng: { latitude: 24.7136, longitude: 46.6753 } } // Riyadh as default if no location
        }
      }
    });
    // Access .text property and grounding chunks
    return {
      text: response.text,
      links: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    return { text: "Search failed. Please try again.", links: [] };
  }
};

import React, { useState } from 'react';
import { Camera, MapPin, Mail, Lock, User as UserIcon, ShieldCheck, Loader2 } from 'lucide-react';
import { Link } from 'react-router-dom';
import { translations } from '../i18n';
import { Gender, User } from '../types';

interface SignUpPageProps {
  lang: string;
  onSignUp: (user: User) => void;
}

const SignUpPage: React.FC<SignUpPageProps> = ({ lang, onSignUp }) => {
  const t = translations[lang] || translations['en'];
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);

  const [formData, setFormData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    email: '',
    password: '',
    location: null as { lat: number, lng: number, address: string } | null,
    agreed: false
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setFormData({
            ...formData,
            location: { 
              lat: pos.coords.latitude, 
              lng: pos.coords.longitude, 
              address: lang === 'ar' ? 'موقعي الحالي' : 'My Live Location' 
            }
          });
          setIsLocating(false);
        },
        () => {
          alert(lang === 'ar' ? 'يرجى تفعيل الوصول للموقع الجغرافي' : 'Please enable location access');
          setIsLocating(false);
        }
      );
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.avatar || !formData.location || !formData.agreed) {
      alert(lang === 'ar' ? 'يرجى إكمال جميع الحقول الإلزامية' : 'Please complete all mandatory fields');
      return;
    }

    setLoading(true);
    // المحاكاة
    setTimeout(() => {
      const newUser: User = {
        id: 'u_' + Date.now(),
        fullName: formData.fullName,
        username: formData.username,
        email: formData.email,
        avatar: formData.avatar,
        gender: Gender.OTHER,
        birthDate: '2000-01-01',
        location: formData.location!,
        status: 'Member',
        points: 100,
        listingsCount: 0,
        walletBalance: 0,
        currencyPreference: 'USD',
        trustScore: 80,
        badges: ['New Member'],
        payoutMethods: {},
        blockedUsers: [],
        isVerified: true
      };
      onSignUp(newUser);
      setLoading(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-white dark:bg-gray-950 flex flex-col items-center justify-center p-6 py-20">
      <div className="w-full max-w-lg bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-2xl border dark:border-gray-800 animate-in fade-in zoom-in-95 duration-500">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-black text-brand italic tracking-tighter uppercase mb-2">my rents</h1>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{lang === 'ar' ? 'أنشئ حسابك للبدء بالتأجير' : 'Create your account to start renting'}</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Avatar Upload */}
          <div className="flex flex-col items-center gap-4">
            <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-dashed border-gray-200 dark:border-gray-700 overflow-hidden flex items-center justify-center cursor-pointer group transition-all hover:border-brand relative">
              {formData.avatar ? (
                <img src={formData.avatar} className="w-full h-full object-cover" alt="Preview" />
              ) : (
                <Camera size={32} className="text-gray-300 group-hover:text-brand" />
              )}
              <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
              {!formData.avatar && <span className="absolute bottom-2 text-[8px] font-black text-gray-400 uppercase">Required</span>}
            </label>
          </div>

          <div className="space-y-4">
            <div className="relative">
              <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="text" required placeholder={t.fullName + '*'} value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-bold">@</span>
              <input type="text" required placeholder={t.username + '*'} value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            {/* Geolocation Button */}
            <button 
              type="button" 
              onClick={handleGetLocation}
              disabled={isLocating}
              className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-[10px] transition-all border-2 ${formData.location ? 'bg-green-50 text-green-600 border-green-200 shadow-lg' : 'bg-gray-50 dark:bg-gray-800 text-gray-400 border-transparent hover:border-brand'}`}
            >
              {isLocating ? <Loader2 className="animate-spin" /> : <MapPin size={18} />}
              {formData.location ? (lang === 'ar' ? 'تم تحديد الموقع بنجاح' : 'Location Set Successfully') : (lang === 'ar' ? 'تحديد موقعي الجغرافي 📍 (مطلوب)' : 'Set My Location 📍 (Required)')}
            </button>

            <div className="relative">
              <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="email" required placeholder={t.email + '*'} value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            <div className="relative">
              <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="password" required placeholder={t.password + '*'} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            {/* Terms and Policy */}
            <div className="flex items-start gap-3 p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
              <input type="checkbox" id="agreed" checked={formData.agreed} onChange={e => setFormData({...formData, agreed: e.target.checked})} className="w-5 h-5 accent-brand mt-1 shrink-0" />
              <label htmlFor="agreed" className="text-[10px] font-bold text-gray-500 uppercase leading-relaxed">
                {t.acceptTerms}
                <div className="mt-1 flex gap-3">
                  <Link to="/privacy" className="text-brand underline">{t.privacyPolicy}</Link>
                  <Link to="/terms" className="text-brand underline">{t.termsOfUse}</Link>
                </div>
              </label>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading || !formData.agreed || !formData.location || !formData.avatar}
            className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            {loading ? <Loader2 className="animate-spin" /> : <ShieldCheck />}
            {lang === 'ar' ? 'إنشاء حسابي' : 'Create My Account'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default SignUpPage;

import React, { useState, useMemo } from 'react';
import { translations } from '../i18n';
import ListingCard from '../components/ListingCard';
import { Listing, CurrencyType } from '../types';
import { Box, Search, Package, Users, ShoppingCart, Sparkles } from 'lucide-react';

interface HomePageProps {
  lang: string;
  user: any;
  userListings: Listing[];
  onDeleteListing: (id: string) => void;
  onAddPoints: (a: number) => void;
}

const HomePage: React.FC<HomePageProps> = ({ lang, user, userListings, onDeleteListing, onAddPoints }) => {
  const t = translations[lang] || translations['en'];
  const [filterType, setFilterType] = useState<'ALL' | CurrencyType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  const filteredItems = useMemo(() => {
    return userListings
      .filter(item => {
        const isValid = 
          item.status === 'PUBLISHED' && 
          item.visibility === 'PUBLIC' && 
          item.is_deleted === false;

        if (!isValid) return false;

        const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesType = filterType === 'ALL' || item.currencyType === filterType;

        return matchesSearch && matchesType;
      })
      .sort((a, b) => {
        const timeA = a.published_at ? new Date(a.published_at).getTime() : 0;
        const timeB = b.published_at ? new Date(b.published_at).getTime() : 0;
        return timeB - timeA;
      });
  }, [searchQuery, filterType, userListings]);

  return (
    <div className="pb-24 pt-8 px-4 max-w-7xl mx-auto animate-in fade-in duration-700">
      {/* Hero Header */}
      <div className="mb-12 text-center md:text-left">
         <div className="flex items-center justify-center md:justify-start gap-2 text-brand font-black uppercase text-[10px] tracking-[0.3em] mb-4">
            <Sparkles size={14} /> {lang === 'ar' ? 'أهلاً بك في my rents' : 'Welcome to my rents'}
         </div>
         <h1 className="text-4xl md:text-5xl font-black dark:text-white uppercase tracking-tighter italic leading-none">
            {lang === 'ar' ? 'استأجر أي شيء،' : 'Rent Anything,'} <br/>
            <span className="text-brand">{lang === 'ar' ? 'في أي مكان' : 'Anywhere'}</span>
         </h1>
      </div>

      {/* Stats Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
        {[
          { icon: <Package className="text-brand" />, label: lang === 'ar' ? 'الأغراض النشطة' : 'Active Items', value: userListings.filter(l => l.status === 'PUBLISHED').length },
          { icon: <Users className="text-blue-500" />, label: lang === 'ar' ? 'المجتمعات' : 'Communities', value: '12' },
          { icon: <ShoppingCart className="text-green-500" />, label: lang === 'ar' ? 'إيجارات مكتملة' : 'Deals Done', value: '450+' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-gray-900 p-8 rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-gray-800 flex items-center gap-6 hover:shadow-xl transition-all group">
            <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl group-hover:scale-110 transition-transform">{stat.icon}</div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mb-1">{stat.label}</p>
              <p className="text-3xl font-black dark:text-white">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Controls */}
      <div className="flex flex-col md:flex-row gap-4 mb-10">
        <div className="flex-1 relative">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text" 
            placeholder={t.searchPlaceholder} 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
            className="w-full pl-14 pr-6 py-5 bg-white dark:bg-gray-900 border-2 border-gray-100 dark:border-gray-800 rounded-[2rem] outline-none focus:border-brand font-bold shadow-sm transition-all" 
          />
        </div>
        <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-[2rem] w-fit">
          {['ALL', CurrencyType.CRYPTO, CurrencyType.LOCAL].map(f => (
            <button key={f} onClick={() => setFilterType(f as any)} className={`px-8 py-3 rounded-[1.8rem] text-[9px] font-black uppercase tracking-widest transition-all ${filterType === f ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>
              {f === 'ALL' ? (lang === 'ar' ? 'الكل' : 'All') : t[f.toLowerCase()]}
            </button>
          ))}
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {filteredItems.map(item => (
          <ListingCard key={item.id} listing={item} lang={lang} isOwner={item.ownerId === user?.id} onDelete={onDeleteListing} onAddPoints={onAddPoints} />
        ))}
      </div>

      {filteredItems.length === 0 && (
        <div className="py-32 text-center">
          <Box size={80} className="mx-auto mb-6 text-gray-100 dark:text-gray-800" />
          <h3 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter">{lang === 'ar' ? 'لا توجد سلع متاحة حالياً' : 'No items found'}</h3>
          <p className="text-[10px] text-gray-400 mt-2 font-bold uppercase tracking-widest">{lang === 'ar' ? 'جرب البحث عن شيء آخر' : 'Try searching for something else'}</p>
        </div>
      )}
    </div>
  );
};

export default HomePage;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useParams } from 'react-router-dom';
import { User, Gender, Listing, PayoutMethods } from './types';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import HomePage from './pages/HomePage';
import SignUpPage from './pages/SignUpPage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import SubscriptionPage from './pages/SubscriptionPage';
import ProfessionalDashboardPage from './pages/ProfessionalDashboardPage';
import BlockedUsersPage from './pages/BlockedUsersPage';
import { translations } from './i18n';
import { ShieldCheck, ShieldBan } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>(() => localStorage.getItem('my_rents_lang') || 'ar');
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('my_rents_theme') === 'dark');

  const [user, setUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('my_rents_user');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  });

  const [allListings, setAllListings] = useState<Listing[]>(() => {
    try {
      const saved = localStorage.getItem('my_rents_listings');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('my_rents_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('my_rents_theme', isDarkMode ? 'dark' : 'light');
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => {
    if (user) localStorage.setItem('my_rents_user', JSON.stringify(user));
    else localStorage.removeItem('my_rents_user');
  }, [user]);

  useEffect(() => {
    localStorage.setItem('my_rents_listings', JSON.stringify(allListings));
  }, [allListings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    setUser(prev => prev ? { ...prev, points: prev.points + amount } : null);
  };

  const handleCurrencyChange = (code: string) => {
    setUser(prev => prev ? { ...prev, currencyPreference: code } : null);
  };

  const handleBlockUser = (otherId: string) => {
    if (!user) return;
    setUser(prev => prev ? { ...prev, blockedUsers: [...(prev.blockedUsers || []), otherId] } : null);
  };

  const handleUnblockUser = (otherId: string) => {
    if (!user) return;
    setUser(prev => prev ? { ...prev, blockedUsers: (prev.blockedUsers || []).filter(id => id !== otherId) } : null);
  };

  const handleSignUp = (newUser: User) => {
    setUser(newUser);
  };

  const ProfileView = () => {
    const { username } = useParams<{ username?: string }>();
    const isSelf = !username || (user && username === user.username);
    const displayUser = isSelf ? user : null; 
    const userSpecificListings = allListings.filter(l => l.ownerUsername === (username || user?.username));

    return (
      <div className="p-4 sm:p-8 text-center max-w-4xl mx-auto animate-in fade-in">
        <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-6 sm:p-10 shadow-sm border dark:border-gray-800 relative overflow-hidden">
          <div className="relative inline-block mb-6">
            <img src={displayUser?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${username || user?.username}`} className="w-24 h-24 sm:w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl" />
            <div className="absolute -bottom-1 -right-1 bg-brand text-white p-1.5 rounded-xl shadow-lg border-2 border-white dark:border-gray-900">
              <ShieldCheck size={16} fill="currentColor" />
            </div>
          </div>

          <h1 className="text-2xl sm:text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{displayUser?.fullName || username || user?.fullName}</h1>
          <p className="text-[#CCCCCC] mb-6 font-bold text-sm">@{username || user?.username}</p>

          <div className="flex gap-2 justify-center mb-8">
            {isSelf && (
              <Link to="/blocked-users" className="py-3 px-6 bg-red-50 dark:bg-red-900/10 text-red-500 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2">
                <ShieldBan size={16} /> {t.blockedUsers}
              </Link>
            )}
          </div>

          <div className="grid grid-cols-2 gap-3 mb-10">
             <div className="p-4 sm:p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[9px] text-gray-400 font-black uppercase block mb-1">Trust Score</span>
                <span className="text-2xl font-black text-brand">{isSelf ? user?.trustScore : '88'}%</span>
             </div>
             <div className="p-4 sm:p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[9px] text-gray-400 font-black uppercase block mb-1">Points</span>
                <span className="text-2xl font-black text-brand">{isSelf ? user?.points : '0'}</span>
             </div>
          </div>

          <div className="mb-10 text-left">
            <h2 className="text-lg font-black dark:text-white uppercase tracking-tighter mb-4 px-2">Listings</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {userSpecificListings.length > 0 ? userSpecificListings.map(l => (
                <div key={l.id} className="relative group">
                   {/* Normal Card usage would go here */}
                   <Link to={`/item/${l.id}`} className="block p-4 bg-gray-50 dark:bg-gray-800 rounded-[2rem] border dark:border-gray-700">
                      <img src={l.images[0]} className="w-full aspect-square object-cover rounded-[1.5rem] mb-3" />
                      <h3 className="font-black text-xs uppercase dark:text-white truncate">{l.title}</h3>
                      <p className="text-brand font-black text-sm">{l.price} {l.currency}</p>
                   </Link>
                </div>
              )) : (
                <div className="col-span-2 py-10 text-center opacity-20">
                   <p className="text-[9px] font-black uppercase">No Listings</p>
                </div>
              )}
            </div>
          </div>

          {isSelf && (
            <button onClick={() => { setUser(null); localStorage.clear(); window.location.reload(); }} className="w-full mt-2 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline">
              {t.logout}
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200 flex flex-col`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} onLangChange={setLang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} onCurrencyChange={handleCurrencyChange} />}
        <main className={`flex-1 ${user ? 'pb-20' : ''}`}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage lang={lang} onSignUp={handleSignUp} /> : <HomePage lang={lang} user={user} userListings={allListings} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setAllListings(prev => [...prev, l])} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} onForcePublish={() => {}} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
                <Route path="/chat/:otherId?" element={<ChatPage lang={lang} onAddPoints={addPoints} listings={allListings} user={user} onBlock={handleBlockUser} />} />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/blocked-users" element={<BlockedUsersPage lang={lang} user={user} onUnblock={handleUnblockUser} />} />
                <Route path="/pro-dashboard" element={user?.subscription?.tier ? <ProfessionalDashboardPage lang={lang} user={user} /> : <Navigate to="/subscription" />} />
              </>
            )}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
        {user && <Footer lang={lang} />}
      </div>
    </HashRouter>
  );
};

export default App;

