import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useParams, useNavigate, useLocation as useRouteLocation } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing } from '../types';
import { 
  Trash2, MapPin, Flag, Send, UserPlus, ShieldCheck, Camera, 
  Loader2, MessageSquareOff, Mic, ShieldBan, Settings, X, Video, ChevronLeft 
} from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ChatMessage {
  id: number;
  text?: string;
  sender: 'me' | 'other';
  type: 'text' | 'image' | 'video' | 'location' | 'voice';
  data?: string;
  timestamp: number;
}

const ChatPage: React.FC<{ lang: string; listings: Listing[]; user: any; onBlock: (id: string) => void; onAddPoints?: (a: number) => void }> = ({ lang, listings, user, onBlock, onAddPoints }) => {
  const t = translations[lang] || translations['en'];
  const { otherId } = useParams();
  const routeLocation = useRouteLocation();
  const navigate = useNavigate();
  const queryParams = new URLSearchParams(routeLocation.search);
  const itemId = queryParams.get('item');

  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem(`chat_${user.id}_${otherId || 'global'}`);
    return saved ? JSON.parse(saved) : [];
  });
  const [input, setInput] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [showGroupCreate, setShowGroupCreate] = useState(false);
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });
  const [isLocating, setIsLocating] = useState(false);

  const discussedItem = useMemo(() => itemId ? listings.find(l => l.id === itemId) : null, [itemId, listings]);

  useEffect(() => {
    localStorage.setItem(`chat_${user.id}_${otherId || 'global'}`, JSON.stringify(messages));
  }, [messages, user.id, otherId]);

  const handleSend = (type: ChatMessage['type'] = 'text', data?: string) => {
    if (type === 'text' && !input.trim()) return;
    const msg: ChatMessage = { id: Date.now(), text: input, sender: 'me', type, data, timestamp: Date.now() };
    setMessages(prev => [...prev, msg]);
    if (type === 'text') setInput('');
    onAddPoints?.(POINTS_SYSTEM.MESSAGE);
  };

  const shareLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(pos => {
        handleSend('location', `${pos.coords.latitude},${pos.coords.longitude}`);
        setIsLocating(false);
      }, () => {
        alert(lang === 'ar' ? 'فشل جلب الموقع' : 'Location failed');
        setIsLocating(false);
      });
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'video') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => handleSend(type, ev.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  const toggleRecording = () => {
    if (!isRecording) {
      setIsRecording(true);
      // Simulate voice recording stop after 3s
      setTimeout(() => {
        setIsRecording(false);
        handleSend('voice', 'simulated_voice_blob');
      }, 3000);
    }
  };

  return (
    <div className="max-w-7xl mx-auto flex h-[calc(100vh-140px)] mt-2 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 animate-in fade-in">
      <div className="w-80 border-r dark:border-gray-800 flex flex-col bg-gray-50/20 dark:bg-gray-950/20 shrink-0 hidden md:flex">
        <div className="p-6">
          <h1 className="text-xl font-black text-brand lowercase italic tracking-tighter mb-6">my rents chat</h1>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>Private</button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.groups}</button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto px-4">
           {activeTab === 'GROUPS' && (
             <button onClick={() => setShowGroupCreate(true)} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl text-[10px] font-black uppercase text-gray-400 mb-4 hover:border-brand hover:text-brand transition-all flex items-center justify-center gap-2">
               <UserPlus size={16} /> {t.createGroup}
             </button>
           )}
           <div className="py-20 text-center opacity-10 flex flex-col items-center">
              <MessageSquareOff size={48} className="text-brand mb-2" />
              <p className="text-[9px] font-black uppercase tracking-widest">{lang === 'ar' ? 'لا يوجد سجل' : 'No history'}</p>
           </div>
        </div>
      </div>

      <div className="flex-1 flex flex-col bg-white dark:bg-gray-900 relative">
        <div className="p-4 border-b dark:border-gray-800 flex justify-between items-center bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm z-10">
           <div className="flex items-center gap-3">
              <button onClick={() => navigate(-1)} className="md:hidden p-2"><ChevronLeft /></button>
              <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand"><ShieldCheck size={24} /></div>
              <div><h2 className="font-black dark:text-white text-xs uppercase tracking-tighter italic">AI SECURE</h2><span className="text-[8px] text-green-500 font-black uppercase">Active</span></div>
           </div>
           <div className="flex gap-1">
              <button onClick={() => setMessages([])} className="p-2.5 text-gray-400 hover:text-red-500 rounded-xl transition-all" title="Clear Chat"><Trash2 size={20} /></button>
              <button onClick={() => alert('Reported')} className="p-2.5 text-gray-400 hover:text-brand rounded-xl" title="Report"><Flag size={20} /></button>
              <button onClick={() => { otherId && onBlock(otherId); navigate('/'); }} className="p-2.5 text-gray-400 hover:text-brand" title="Block"><ShieldBan size={20} /></button>
           </div>
        </div>

        {discussedItem && (
          <div className="p-3 bg-brand/5 border-b border-brand/10 flex items-center justify-between animate-in slide-in-from-top">
             <div className="flex items-center gap-2">
                <img src={discussedItem.images[0]} className="w-10 h-10 rounded-lg object-cover" />
                <p className="text-[10px] font-black dark:text-white uppercase truncate max-w-[150px]">{discussedItem.title}</p>
             </div>
             <button onClick={() => alert(t.confirmRental)} className="px-5 py-2 bg-brand text-white rounded-xl text-[9px] font-black uppercase">RENT NOW</button>
          </div>
        )}

        <div className="flex-1 p-6 overflow-y-auto space-y-4 bg-gray-50/30 dark:bg-transparent">
           {messages.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-20 text-center px-10">
                <ShieldCheck size={64} className="text-brand mb-4" />
                <p className="text-[10px] font-black dark:text-white uppercase tracking-widest leading-relaxed">
                  {lang === 'ar' ? 'ابدأ الحديث هنا. الدردشة محمية بواسطة الذكاء الاصطناعي.' : 'Start talking. Chat is AI protected.'}
                </p>
             </div>
           ) : messages.map(m => (
             <div key={m.id} className={`flex ${m.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                <div className={`p-4 rounded-[1.8rem] shadow-sm text-xs font-bold max-w-[80%] ${m.sender === 'me' ? 'bg-brand text-white rounded-tr-none' : 'bg-gray-100 dark:bg-gray-800 dark:text-white rounded-tl-none'}`}>
                   {m.type === 'image' && <img src={m.data} className="rounded-xl mb-2 max-w-full h-auto" />}
                   {m.type === 'video' && <video src={m.data} controls className="rounded-xl mb-2" />}
                   {m.type === 'location' ? (
                     <a href={`https://maps.google.com?q=${m.data}`} target="_blank" className="flex items-center gap-2 underline uppercase text-[10px]">
                       <MapPin size={14} /> {lang === 'ar' ? 'عرض الموقع' : 'View Location'}
                     </a>
                   ) : m.type === 'voice' ? (
                     <div className="flex items-center gap-2"><Mic size={14} /> {lang === 'ar' ? 'رسالة صوتية' : 'Voice Message'}</div>
                   ) : m.text}
                   <div className="text-[7px] mt-1 opacity-50 text-right">{new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                </div>
             </div>
           ))}
        </div>

        <div className="p-6 border-t dark:border-gray-800 bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm">
           <div className="flex gap-2 mb-4 overflow-x-auto pb-1 scrollbar-hide">
              <button onClick={toggleRecording} className={`flex items-center gap-2 px-4 py-2 rounded-2xl text-[9px] font-black uppercase transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>
                <Mic size={14} /> {isRecording ? 'Recording...' : t.voice}
              </button>
              <label className="flex items-center gap-2 px-4 py-2 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand">
                <Camera size={14} /> {lang === 'ar' ? 'صور' : 'Photos'}
                <input type="file" className="hidden" accept="image/*" onChange={e => handleFileUpload(e, 'image')} />
              </label>
              <label className="flex items-center gap-2 px-4 py-2 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand">
                <Video size={14} /> {lang === 'ar' ? 'فيديو' : 'Video'}
                <input type="file" className="hidden" accept="video/*" onChange={e => handleFileUpload(e, 'video')} />
              </label>
              <button onClick={shareLocation} disabled={isLocating} className="flex items-center gap-2 px-4 py-2 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 hover:text-brand">
                {isLocating ? <Loader2 size={14} className="animate-spin" /> : <MapPin size={14} />} {t.location}
              </button>
           </div>
           <div className="flex gap-2">
              <input 
                type="text" 
                value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyDown={e => e.key === 'Enter' && handleSend()} 
                className="flex-1 bg-gray-100 dark:bg-gray-800 dark:text-white px-8 py-5 rounded-[2.2rem] outline-none font-bold text-sm shadow-inner" 
                placeholder={lang === 'ar' ? 'اكتب هنا...' : 'Type message...'} 
              />
              <button onClick={() => handleSend()} className="w-16 h-16 bg-brand text-white rounded-[1.8rem] flex items-center justify-center shadow-xl active:scale-95 transition-all"><Send size={24} /></button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default ChatPage;

import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing } from '../types';
import { MapPin, Star, Share2, Heart, MessageCircle, ArrowLeft, Flag, Eye, ShieldCheck, Trash2, Box, Info, Zap, Clock, CreditCard } from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ItemDetailPageProps {
  lang: string;
  user?: any;
  listings: Listing[];
  onDelete?: (id: string) => void;
  onAddPoints: (a: number) => void;
  onForcePublish: (id: string, updates: Partial<Listing>) => void;
}

const ItemDetailPage: React.FC<ItemDetailPageProps> = ({ lang, user, listings, onDelete, onAddPoints, onForcePublish }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [isLiked, setIsLiked] = useState(false);

  const item = listings.find(l => l.id === id);

  if (!item) {
    return (
      <div className="max-w-4xl mx-auto py-20 text-center">
        <Box size={64} className="mx-auto text-gray-200 mb-4" />
        <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{lang === 'ar' ? 'المنتج غير موجود' : 'Item Not Found'}</h2>
        <button onClick={() => navigate('/')} className="mt-6 px-8 py-3 bg-brand text-white rounded-2xl font-bold">{t.back}</button>
      </div>
    );
  }

  const isOwner = user?.id === item.ownerId;

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `my rents: ${item.title}`,
          text: item.description,
          url: window.location.href,
        });
        onAddPoints(POINTS_SYSTEM.SHARE);
      } catch (err) {}
    } else {
      navigator.clipboard.writeText(window.location.href);
      alert(lang === 'ar' ? 'تم نسخ الرابط' : 'Link Copied');
    }
  };

  const handleLike = () => {
    setIsLiked(!isLiked);
    if (!isLiked) onAddPoints(POINTS_SYSTEM.LIKE);
  };

  const handleReport = () => {
    alert(lang === 'ar' ? 'تم إرسال بلاغك لنظام AI my rents للفحص.' : 'Report sent to AI my rents.');
  };

  return (
