import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useParams, useNavigate, useLocation as useRouteLocation } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing } from '../types';
import { 
  Trash2, MapPin, Flag, Send, UserPlus, ShieldCheck, Camera, 
  Loader2, MessageSquareOff, Mic, ShieldBan, Settings, X, Video, ChevronLeft, StopCircle, Play, Pause
} from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ChatMessage {
  id: number;
  text?: string;
  sender: 'me' | 'other';
  type: 'text' | 'image' | 'video' | 'location' | 'voice';
  data?: string; // Base64 data for media
  timestamp: number;
}

const ChatPage: React.FC<{ lang: string; listings: Listing[]; user: any; onBlock: (id: string) => void; onAddPoints?: (a: number) => void }> = ({ lang, listings, user, onBlock, onAddPoints }) => {
  const t = translations[lang] || translations['en'];
  const { otherId } = useParams();
  const routeLocation = useRouteLocation();
  const navigate = useNavigate();
  const queryParams = new URLSearchParams(routeLocation.search);
  const itemId = queryParams.get('item');

  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem(`chat_${user.id}_${otherId || 'global'}`);
    return saved ? JSON.parse(saved) : [];
  });
  const [input, setInput] = useState('');

  // Real Voice Recording States
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [showGroupCreate, setShowGroupCreate] = useState(false);
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });
  const [isLocating, setIsLocating] = useState(false);

  const discussedItem = useMemo(() => itemId ? listings.find(l => l.id === itemId) : null, [itemId, listings]);

  useEffect(() => {
    localStorage.setItem(`chat_${user.id}_${otherId || 'global'}`, JSON.stringify(messages));
  }, [messages, user.id, otherId]);

  const handleSend = (type: ChatMessage['type'] = 'text', data?: string) => {
    if (type === 'text' && !input.trim()) return;
    const msg: ChatMessage = { id: Date.now(), text: input, sender: 'me', type, data, timestamp: Date.now() };
    setMessages(prev => [...prev, msg]);
    if (type === 'text') setInput('');
    onAddPoints?.(POINTS_SYSTEM.MESSAGE);
  };

  // ACTUAL VOICE RECORDING LOGIC
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.onloadend = () => {
          handleSend('voice', reader.result as string);
        };
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      alert(lang === 'ar' ? 'يرجى السماح بالوصول للميكروفون' : 'Please allow microphone access');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  // ACTUAL GEOLOCATION LOGIC
  const shareLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(pos => {
        handleSend('location', `${pos.coords.latitude},${pos.coords.longitude}`);
        setIsLocating(false);
      }, () => {
        alert(lang === 'ar' ? 'فشل جلب الموقع' : 'Location access denied');
        setIsLocating(false);
      }, { enableHighAccuracy: true });
    }
  };

  // ACTUAL FILE UPLOAD LOGIC
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'video') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => handleSend(type, ev.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="max-w-7xl mx-auto flex h-[calc(100vh-140px)] mt-2 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 animate-in fade-in">
      {/* Sidebar */}
      <div className="w-80 border-r dark:border-gray-800 flex flex-col bg-gray-50/20 dark:bg-gray-950/20 shrink-0 hidden md:flex">
        <div className="p-6">
          <h1 className="text-xl font-black text-brand lowercase italic tracking-tighter mb-6">my rents chat</h1>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>Private</button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.groups}</button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto px-4">
           {activeTab === 'GROUPS' && (
             <button onClick={() => setShowGroupCreate(true)} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl text-[10px] font-black uppercase text-gray-400 mb-4 hover:border-brand hover:text-brand transition-all flex items-center justify-center gap-2">
               <UserPlus size={16} /> {t.createGroup}
             </button>
           )}
           <div className="py-20 text-center opacity-10 flex flex-col items-center">
              <MessageSquareOff size={48} className="text-brand mb-2" />
              <p className="text-[9px] font-black uppercase tracking-widest">{lang === 'ar' ? 'لا توجد محادثات' : 'No history'}</p>
           </div>
        </div>
      </div>

      {/* Main Chat View */}
      <div className="flex-1 flex flex-col bg-white dark:bg-gray-900 relative">
        <div className="p-4 border-b dark:border-gray-800 flex justify-between items-center bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm z-10">
           <div className="flex items-center gap-3">
              <button onClick={() => navigate(-1)} className="md:hidden p-2"><ChevronLeft /></button>
              <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand"><ShieldCheck size={24} /></div>
              <div><h2 className="font-black dark:text-white text-xs uppercase tracking-tighter italic">AI SECURE</h2><span className="text-[8px] text-green-500 font-black uppercase">Direct P2P Encryption</span></div>
           </div>
           <div className="flex gap-1">
              <button onClick={() => setMessages([])} className="p-2.5 text-gray-400 hover:text-red-500 rounded-xl transition-all" title="Clear Chat"><Trash2 size={20} /></button>
              <button onClick={() => alert('Report Submitted')} className="p-2.5 text-gray-400 hover:text-brand rounded-xl" title="Report"><Flag size={20} /></button>
              <button onClick={() => { otherId && onBlock(otherId); navigate('/'); }} className="p-2.5 text-gray-400 hover:text-brand" title="Block"><ShieldBan size={20} /></button>
           </div>
        </div>

        {discussedItem && (
          <div className="p-3 bg-brand/5 border-b border-brand/10 flex items-center justify-between animate-in slide-in-from-top">
             <div className="flex items-center gap-2">
                <img src={discussedItem.images[0]} className="w-10 h-10 rounded-lg object-cover" />
                <p className="text-[10px] font-black dark:text-white uppercase truncate max-w-[150px]">{discussedItem.title}</p>
             </div>
             <button onClick={() => alert(t.confirmRental)} className="px-5 py-2 bg-brand text-white rounded-xl text-[9px] font-black uppercase shadow-lg">RENT NOW</button>
          </div>
        )}

        <div className="flex-1 p-6 overflow-y-auto space-y-4 bg-gray-50/10 dark:bg-transparent">
           {messages.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-20 text-center px-10">
                <ShieldCheck size={64} className="text-brand mb-4" />
                <p className="text-[10px] font-black dark:text-white uppercase tracking-widest leading-relaxed">
                  {lang === 'ar' ? 'ابدأ الحديث بشكل آمن تماماً.' : 'End-to-end secured chat started.'}
                </p>
             </div>
           ) : messages.map(m => (
             <div key={m.id} className={`flex ${m.sender === 'me' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                <div className={`p-4 rounded-[1.8rem] shadow-sm text-xs font-bold max-w-[85%] ${m.sender === 'me' ? 'bg-brand text-white rounded-tr-none shadow-brand/10' : 'bg-gray-100 dark:bg-gray-800 dark:text-white rounded-tl-none'}`}>
                   {m.type === 'image' && <img src={m.data} className="rounded-2xl mb-2 max-w-full h-auto shadow-md" alt="Attachment" />}
                   {m.type === 'video' && <video src={m.data} controls className="rounded-2xl mb-2 max-w-full shadow-md" />}
                   {m.type === 'voice' && (
                     <div className="flex items-center gap-3 p-2 bg-black/5 dark:bg-white/5 rounded-2xl min-w-[200px]">
                        <audio src={m.data} controls className="h-8 w-full scale-90" />
                     </div>
                   )}
                   {m.type === 'location' ? (
                     <a href={`https://maps.google.com?q=${m.data}`} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 underline uppercase text-[10px] bg-white/10 p-2 rounded-xl">
                       <MapPin size={16} /> {lang === 'ar' ? 'عرض موقعي على الخريطة' : 'View Shared Location'}
                     </a>
                   ) : m.text}
                   <div className={`text-[7px] mt-2 font-black uppercase opacity-40 text-right ${m.sender === 'me' ? 'text-white' : 'text-gray-400'}`}>
                     {new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                   </div>
                </div>
             </div>
           ))}
        </div>

        {/* Input Controls */}
        <div className="p-6 border-t dark:border-gray-800 bg-white/95 dark:bg-gray-900/95 backdrop-blur-md">
           <div className="flex gap-2 mb-4 overflow-x-auto pb-1 scrollbar-hide">
              <button 
                onMouseDown={startRecording} 
                onMouseUp={stopRecording}
                onTouchStart={startRecording}
                onTouchEnd={stopRecording}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-2xl text-[9px] font-black uppercase transition-all shadow-sm ${isRecording ? 'bg-red-500 text-white animate-pulse scale-105' : 'bg-gray-50 dark:bg-gray-800 text-gray-400 hover:text-brand'}`}
              >
                {isRecording ? <StopCircle size={16} /> : <Mic size={16} />}
                {isRecording ? t.voiceRecording : t.voice}
              </button>
              <label className="flex items-center gap-2 px-5 py-2.5 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand transition-all shadow-sm">
                <Camera size={16} /> {lang === 'ar' ? 'صور' : 'Photos'}
                <input type="file" className="hidden" accept="image/*" onChange={e => handleFileUpload(e, 'image')} />
              </label>
              <label className="flex items-center gap-2 px-5 py-2.5 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand transition-all shadow-sm">
                <Video size={16} /> {lang === 'ar' ? 'فيديو' : 'Video'}
                <input type="file" className="hidden" accept="video/*" onChange={e => handleFileUpload(e, 'video')} />
              </label>
              <button onClick={shareLocation} disabled={isLocating} className="flex items-center gap-2 px-5 py-2.5 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 hover:text-brand transition-all shadow-sm">
                {isLocating ? <Loader2 size={16} className="animate-spin" /> : <MapPin size={16} />} {t.location}
              </button>
           </div>
           <div className="flex gap-3">
              <input 
                type="text" 
                value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyDown={e => e.key === 'Enter' && handleSend()} 
                className="flex-1 bg-gray-100 dark:bg-gray-800 dark:text-white px-8 py-5 rounded-[2.2rem] outline-none font-bold text-sm shadow-inner focus:ring-2 focus:ring-brand transition-all" 
                placeholder={lang === 'ar' ? 'اكتب رسالتك هنا...' : 'Type your message...'} 
              />
              <button onClick={() => handleSend()} className="w-16 h-16 bg-brand text-white rounded-[1.8rem] flex items-center justify-center shadow-xl shadow-brand/30 active:scale-90 hover:scale-105 transition-all"><Send size={28} /></button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default ChatPage;

import React, { useState } from 'react';
import { Camera, MapPin, Mail, Lock, User as UserIcon, ShieldCheck, Loader2, Edit3, Navigation } from 'lucide-react';
import { Link } from 'react-router-dom';
import { translations } from '../i18n';
import { Gender, User } from '../types';

interface SignUpPageProps {
  lang: string;
  onSignUp: (user: User) => void;
}

const SignUpPage: React.FC<SignUpPageProps> = ({ lang, onSignUp }) => {
  const t = translations[lang] || translations['en'];
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isManualLocation, setIsManualLocation] = useState(false);

  const [formData, setFormData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    email: '',
    password: '',
    location: null as { lat: number, lng: number, address: string } | null,
    manualAddress: '',
    agreed: false
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setFormData({
            ...formData,
            location: { 
              lat: pos.coords.latitude, 
              lng: pos.coords.longitude, 
              address: lang === 'ar' ? 'موقعي الحالي (GPS)' : 'My Live Location (GPS)' 
            }
          });
          setIsLocating(false);
          setIsManualLocation(false);
        },
        () => {
          alert(lang === 'ar' ? 'فشل جلب الموقع التلقائي، يرجى الإدخال يدوياً' : 'Auto-location failed, please enter manually');
          setIsLocating(false);
          setIsManualLocation(true);
        },
        { timeout: 10000 }
      );
    } else {
      setIsManualLocation(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalLocation = formData.location;
    if (isManualLocation) {
      if (!formData.manualAddress.trim()) {
        alert(lang === 'ar' ? 'يرجى إدخال العنوان يدوياً' : 'Please enter the address manually');
        return;
      }
      finalLocation = { lat: 0, lng: 0, address: formData.manualAddress };
    }

    if (!formData.avatar || !finalLocation || !formData.agreed) {
      alert(lang === 'ar' ? 'يرجى إكمال جميع الحقول الإلزامية' : 'Please complete all mandatory fields');
      return;
    }

    setLoading(true);
    setTimeout(() => {
      const newUser: User = {
        id: 'u_' + Date.now(),
        fullName: formData.fullName,
        username: formData.username,
        email: formData.email,
        avatar: formData.avatar,
        gender: Gender.OTHER,
        birthDate: '2000-01-01',
        location: finalLocation!,
        status: 'Member',
        points: 100,
        listingsCount: 0,
        walletBalance: 0,
        currencyPreference: 'USD',
        trustScore: 80,
        badges: ['New Member'],
        payoutMethods: {},
        blockedUsers: [],
        isVerified: true
      };
      onSignUp(newUser);
      setLoading(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-white dark:bg-gray-950 flex flex-col items-center justify-center p-6 py-20">
      <div className="w-full max-w-lg bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-2xl border dark:border-gray-800 animate-in fade-in zoom-in-95 duration-500">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-black text-brand italic tracking-tighter lowercase mb-2">my rents</h1>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{lang === 'ar' ? 'أنشئ حسابك للبدء بالتأجير' : 'Create your account to start renting'}</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="flex flex-col items-center gap-4">
            <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-dashed border-gray-200 dark:border-gray-700 overflow-hidden flex items-center justify-center cursor-pointer group transition-all hover:border-brand relative">
              {formData.avatar ? (
                <img src={formData.avatar} className="w-full h-full object-cover" alt="Preview" />
              ) : (
                <Camera size={32} className="text-gray-300 group-hover:text-brand" />
              )}
              <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
              {!formData.avatar && <span className="absolute bottom-2 text-[8px] font-black text-gray-400 uppercase">Required</span>}
            </label>
          </div>

          <div className="space-y-4">
            <div className="relative">
              <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="text" required placeholder={t.fullName + '*'} value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-bold">@</span>
              <input type="text" required placeholder={t.username + '*'} value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            {/* Location Section */}
            <div className="space-y-3">
              {!isManualLocation ? (
                <button 
                  type="button" 
                  onClick={handleGetLocation}
                  disabled={isLocating}
                  className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-[10px] transition-all border-2 ${formData.location ? 'bg-green-50 text-green-600 border-green-200 shadow-lg' : 'bg-gray-50 dark:bg-gray-800 text-gray-400 border-transparent hover:border-brand'}`}
                >
                  {isLocating ? <Loader2 className="animate-spin" /> : <Navigation size={18} />}
                  {formData.location ? (lang === 'ar' ? 'تم تحديد الموقع' : 'Location Set') : (lang === 'ar' ? 'تحديد موقعي (GPS)' : 'Set Location (GPS)')}
                </button>
              ) : (
                <div className="relative animate-in slide-in-from-top-2">
                  <MapPin className="absolute left-5 top-1/2 -translate-y-1/2 text-brand" size={18} />
                  <input 
                    type="text" 
                    placeholder={t.addressPlaceholder + '*'} 
                    value={formData.manualAddress} 
                    onChange={e => setFormData({...formData, manualAddress: e.target.value})} 
                    className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-brand shadow-inner" 
                  />
                </div>
              )}

              <button 
                type="button" 
                onClick={() => setIsManualLocation(!isManualLocation)}
                className="w-full text-center text-[9px] font-black text-brand uppercase tracking-widest hover:underline flex items-center justify-center gap-1"
              >
                {isManualLocation ? <Navigation size={12}/> : <Edit3 size={12}/>}
                {isManualLocation ? t.useGPS : t.enterManually}
              </button>
            </div>

            <div className="relative">
              <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="email" required placeholder={t.email + '*'} value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            <div className="relative">
              <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="password" required placeholder={t.password + '*'} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner" />
            </div>

            <div className="flex items-start gap-3 p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
              <input type="checkbox" id="agreed" checked={formData.agreed} onChange={e => setFormData({...formData, agreed: e.target.checked})} className="w-5 h-5 accent-brand mt-1 shrink-0" />
              <label htmlFor="agreed" className="text-[10px] font-bold text-gray-500 uppercase leading-relaxed">
                {t.acceptTerms}
                <div className="mt-1 flex gap-3">
                  <Link to="/privacy" className="text-brand underline">{t.privacyPolicy}</Link>
                  <Link to="/terms" className="text-brand underline">{t.termsOfUse}</Link>
                </div>
              </label>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading || !formData.agreed || (!formData.location && !formData.manualAddress) || !formData.avatar}
            className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            {loading ? <Loader2 className="animate-spin" /> : <ShieldCheck />}
            {lang === 'ar' ? 'إنشاء حسابي' : 'Create My Account'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default SignUpPage;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useParams } from 'react-router-dom';
import { User, Listing } from './types';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import HomePage from './pages/HomePage';
import SignUpPage from './pages/SignUpPage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import DiscoveryPage from './pages/DiscoveryPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import SubscriptionPage from './pages/SubscriptionPage';
import ProfessionalDashboardPage from './pages/ProfessionalDashboardPage';
import BlockedUsersPage from './pages/BlockedUsersPage';
import { translations } from './i18n';
import { ShieldCheck, ShieldBan } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>(() => localStorage.getItem('my_rents_lang') || 'ar');
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('my_rents_theme') === 'dark');

  const [user, setUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('my_rents_user');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  });

  const [allListings, setAllListings] = useState<Listing[]>(() => {
    try {
      const saved = localStorage.getItem('my_rents_listings');
      // No mock data - starts clean
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('my_rents_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('my_rents_theme', isDarkMode ? 'dark' : 'light');
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => {
    if (user) localStorage.setItem('my_rents_user', JSON.stringify(user));
    else localStorage.removeItem('my_rents_user');
  }, [user]);

  useEffect(() => {
    localStorage.setItem('my_rents_listings', JSON.stringify(allListings));
  }, [allListings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    setUser(prev => prev ? { ...prev, points: prev.points + amount } : null);
  };

  const handleCurrencyChange = (code: string) => {
    setUser(prev => prev ? { ...prev, currencyPreference: code } : null);
  };

  const handleBlockUser = (otherId: string) => {
    if (!user) return;
    setUser(prev => prev ? { ...prev, blockedUsers: [...(prev.blockedUsers || []), otherId] } : null);
  };

  const handleUnblockUser = (otherId: string) => {
    if (!user) return;
    setUser(prev => prev ? { ...prev, blockedUsers: (prev.blockedUsers || []).filter(id => id !== otherId) } : null);
  };

  const handleSignUp = (newUser: User) => {
    setUser(newUser);
  };

  const ProfileView = () => {
    const { username } = useParams<{ username?: string }>();
    const isSelf = !username || (user && username === user.username);
    const displayUser = isSelf ? user : null; 
    const userSpecificListings = allListings.filter(l => l.ownerUsername === (username || user?.username));

    return (
      <div className="p-4 sm:p-8 text-center max-w-4xl mx-auto animate-in fade-in">
        <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-6 sm:p-10 shadow-sm border dark:border-gray-800 relative overflow-hidden">
          <div className="relative inline-block mb-6">
            <img src={displayUser?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${username || user?.username}`} className="w-24 h-24 sm:w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl" />
            <div className="absolute -bottom-1 -right-1 bg-brand text-white p-1.5 rounded-xl shadow-lg border-2 border-white dark:border-gray-900">
              <ShieldCheck size={16} fill="currentColor" />
            </div>
          </div>

          <h1 className="text-2xl sm:text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{displayUser?.fullName || username || user?.fullName}</h1>
          <p className="text-[#CCCCCC] mb-6 font-bold text-sm">@{username || user?.username}</p>

          <div className="flex gap-2 justify-center mb-8">
            {isSelf && (
              <Link to="/blocked-users" className="py-3 px-6 bg-red-50 dark:bg-red-900/10 text-red-500 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2">
                <ShieldBan size={16} /> {t.blockedUsers}
              </Link>
            )}
          </div>

          <div className="grid grid-cols-2 gap-3 mb-10">
             <div className="p-4 sm:p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[9px] text-gray-400 font-black uppercase block mb-1">Trust Score</span>
                <span className="text-2xl font-black text-brand">{isSelf ? user?.trustScore : '0'}%</span>
             </div>
             <div className="p-4 sm:p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[9px] text-gray-400 font-black uppercase block mb-1">Points</span>
                <span className="text-2xl font-black text-brand">{isSelf ? user?.points : '0'}</span>
             </div>
          </div>

          <div className="mb-10 text-left">
            <h2 className="text-lg font-black dark:text-white uppercase tracking-tighter mb-4 px-2">Listings</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {userSpecificListings.length > 0 ? userSpecificListings.map(l => (
                <div key={l.id} className="relative group">
                   <Link to={`/item/${l.id}`} className="block p-4 bg-gray-50 dark:bg-gray-800 rounded-[2rem] border dark:border-gray-700">
                      <img src={l.images[0]} className="w-full aspect-square object-cover rounded-[1.5rem] mb-3" />
                      <h3 className="font-black text-xs uppercase dark:text-white truncate">{l.title}</h3>
                      <p className="text-brand font-black text-sm">{l.price} {l.currency}</p>
                   </Link>
                </div>
              )) : (
                <div className="col-span-2 py-10 text-center opacity-20">
                   <p className="text-[9px] font-black uppercase">No Listings</p>
                </div>
              )}
            </div>
          </div>

          {isSelf && (
            <button onClick={() => { setUser(null); localStorage.clear(); window.location.reload(); }} className="w-full mt-2 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline">
              {t.logout}
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200 flex flex-col`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} onLangChange={setLang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} onCurrencyChange={handleCurrencyChange} />}
        <main className={`flex-1 ${user ? 'pb-20' : ''}`}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage lang={lang} onSignUp={handleSignUp} /> : <HomePage lang={lang} user={user} userListings={allListings} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setAllListings(prev => [...prev, l])} />} />
                <Route path="/discovery" element={<DiscoveryPage lang={lang} user={user} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} onForcePublish={() => {}} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
                <Route path="/chat/:otherId?" element={<ChatPage lang={lang} onAddPoints={addPoints} listings={allListings} user={user} onBlock={handleBlockUser} />} />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/blocked-users" element={<BlockedUsersPage lang={lang} user={user} onUnblock={handleUnblockUser} />} />
                <Route path="/pro-dashboard" element={user?.subscription?.tier ? <ProfessionalDashboardPage lang={lang} user={user} /> : <Navigate to="/subscription" />} />
              </>
            )}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
        {user && <Footer lang={lang} />}
      </div>
    </HashRouter>
  );
};

export default App;

