          </div>

          <div className="mb-10 text-left">
            <h2 className="text-lg font-black dark:text-white uppercase tracking-tighter mb-4 px-2">Listings</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {userSpecificListings.length > 0 ? userSpecificListings.map(l => (
                <div key={l.id} className="relative group">
                   <Link to={`/item/${l.id}`} className="block p-4 bg-gray-50 dark:bg-gray-800 rounded-[2rem] border dark:border-gray-700">
                      <img src={l.images[0]} className="w-full aspect-square object-cover rounded-[1.5rem] mb-3" />
                      <h3 className="font-black text-xs uppercase dark:text-white truncate">{l.title}</h3>
                      <p className="text-brand font-black text-sm">{l.price} {l.currency}</p>
                   </Link>
                </div>
              )) : (
                <div className="col-span-2 py-10 text-center opacity-20">
                   <p className="text-[9px] font-black uppercase">No Listings</p>
                </div>
              )}
            </div>
          </div>

          {isSelf && (
            <button onClick={() => { setUser(null); localStorage.clear(); window.location.reload(); }} className="w-full mt-2 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline">
              {t.logout}
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200 flex flex-col`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} onLangChange={setLang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} onCurrencyChange={handleCurrencyChange} />}
        <main className={`flex-1 ${user ? 'pb-20' : ''}`}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage lang={lang} onSignUp={handleSignUp} /> : <HomePage lang={lang} user={user} userListings={allListings} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => { setAllListings(prev => [...prev, l]); addPoints(50); }} />} />
                <Route path="/discovery" element={<DiscoveryPage lang={lang} user={user} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} onForcePublish={() => {}} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
                <Route path="/chat/:otherId?" element={<ChatPage lang={lang} onAddPoints={addPoints} listings={allListings} user={user} onBlock={handleBlockUser} groups={groups} onCreateGroup={handleCreateGroup} />} />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/blocked-users" element={<BlockedUsersPage lang={lang} user={user} onUnblock={handleUnblockUser} />} />
                <Route path="/settings" element={<SettingsPage lang={lang} user={user} onUpdate={setUser} />} />
                <Route path="/notifications" element={<NotificationsPage lang={lang} notifications={notifications} onClear={() => setNotifications([])} />} />
                <Route path="/my-rentals" element={<MyRentalsPage lang={lang} user={user} listings={allListings} />} />
                <Route path="/pro-dashboard" element={user?.subscription?.tier ? <ProfessionalDashboardPage lang={lang} user={user} listings={allListings} /> : <Navigate to="/subscription" />} />
              </>
            )}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
        {user && <Footer lang={lang} />}
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { User, Gender } from '../types';
import { 
  ArrowLeft, Camera, MapPin, Navigation, Edit3, Save, 
  CreditCard, Wallet, ShieldCheck, Globe, Loader2 
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface SettingsPageProps {
  lang: string;
  user: User;
  onUpdate: (user: User) => void;
}

const SettingsPage: React.FC<SettingsPageProps> = ({ lang, user, onUpdate }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isManualLocation, setIsManualLocation] = useState(false);

  const [formData, setFormData] = useState({
    ...user,
    manualAddress: user.location.address
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setFormData({
            ...formData,
            location: { 
              lat: pos.coords.latitude, 
              lng: pos.coords.longitude, 
              address: lang === 'ar' ? 'موقعي المحدث (GPS)' : 'Updated Location (GPS)' 
            },
            manualAddress: lang === 'ar' ? 'موقعي المحدث (GPS)' : 'Updated Location (GPS)'
          });
          setIsLocating(false);
          setIsManualLocation(false);
        },
        () => {
          alert(lang === 'ar' ? 'فشل جلب الموقع' : 'Location failed');
          setIsLocating(false);
          setIsManualLocation(true);
        }
      );
    }
  };

  const handleSave = () => {
    setLoading(true);
    const updatedUser: User = {
      ...formData,
      location: isManualLocation 
        ? { ...formData.location, address: formData.manualAddress } 
        : formData.location
    };

    setTimeout(() => {
      onUpdate(updatedUser);
      setLoading(false);
      alert(lang === 'ar' ? 'تم حفظ التغييرات بنجاح!' : 'Changes saved successfully!');
    }, 1000);
  };

  return (
    <div className="max-w-3xl mx-auto p-4 pt-10 pb-24 animate-in fade-in duration-500">
      <div className="flex items-center gap-4 mb-10">
        <button onClick={() => navigate(-1)} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm dark:text-white">
          <ArrowLeft className={lang === 'ar' ? 'rotate-180' : ''} />
        </button>
        <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic">{t.settings}</h1>
      </div>

      <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-8 md:p-12 border dark:border-gray-800 shadow-xl space-y-10">
        {/* Avatar section */}
        <div className="flex flex-col items-center gap-4">
          <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-brand/20 overflow-hidden flex items-center justify-center cursor-pointer group relative">
            <img src={formData.avatar} className="w-full h-full object-cover group-hover:opacity-50 transition-opacity" />
            <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 text-brand">
              <Camera size={24} />
            </div>
            <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
          </label>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{lang === 'ar' ? 'تغيير الصورة الشخصية' : 'Change Avatar'}</p>
        </div>

        {/* Info section */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase ml-2">{t.fullName}</label>
            <input type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase ml-2">{t.email}</label>
            <input type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
          </div>
        </div>

        {/* Location Section */}
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-xs font-black text-brand uppercase tracking-widest flex items-center gap-2"><MapPin size={16}/> {t.location}</h3>
            <button onClick={() => setIsManualLocation(!isManualLocation)} className="text-[9px] font-black uppercase text-gray-400 hover:text-brand flex items-center gap-1">
              {isManualLocation ? <Navigation size={12}/> : <Edit3 size={12}/>}
              {isManualLocation ? t.useGPS : t.enterManually}
            </button>
          </div>

          {!isManualLocation ? (
            <button onClick={handleGetLocation} disabled={isLocating} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-center justify-between text-xs font-bold dark:text-white border-2 border-transparent hover:border-brand transition-all">
              <div className="flex items-center gap-3">
                <Navigation size={18} className="text-brand" />
                <span>{formData.location.address}</span>
              </div>
              {isLocating && <Loader2 className="animate-spin" size={16} />}
            </button>
          ) : (
            <input type="text" value={formData.manualAddress} onChange={e => setFormData({...formData, manualAddress: e.target.value})} className="w-full p-5 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-2xl outline-none font-bold border-2 border-brand" />
          )}
        </div>

        {/* Payout Section */}
        <div className="space-y-6">
          <h3 className="text-xs font-black text-brand uppercase tracking-widest flex items-center gap-2"><Wallet size={16}/> {lang === 'ar' ? 'إعدادات الصرف' : 'Payout Settings'}</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl border dark:border-gray-700">
                <div className="flex items-center gap-2 mb-2 text-gray-400">
                  <Globe size={14}/> <span className="text-[9px] font-black uppercase">{t.local}</span>
                </div>
                <input type="text" placeholder="PayPal Email" value={formData.payoutMethods.paypal || ''} onChange={e => setFormData({...formData, payoutMethods: {...formData.payoutMethods, paypal: e.target.value}})} className="w-full bg-transparent outline-none font-bold text-xs dark:text-white" />
             </div>
             <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl border dark:border-gray-700">
                <div className="flex items-center gap-2 mb-2 text-gray-400">
                  <ShieldCheck size={14}/> <span className="text-[9px] font-black uppercase">Solana (Crypto)</span>
                </div>
                <input type="text" placeholder="SOL Wallet Address" value={formData.payoutMethods.solana || ''} onChange={e => setFormData({...formData, payoutMethods: {...formData.payoutMethods, solana: e.target.value}})} className="w-full bg-transparent outline-none font-bold text-xs dark:text-white" />
             </div>
          </div>
        </div>

        <button 
          onClick={handleSave} 
          disabled={loading}
          className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 flex items-center justify-center gap-3 transition-all active:scale-95"
        >
          {loading ? <Loader2 className="animate-spin" /> : <Save />}
          {t.saveChanges}
        </button>
      </div>
    </div>
  );
};

export default SettingsPage;

import React from 'react';
import { translations } from '../i18n';
import { Bell, ArrowLeft, Heart, MessageCircle, Star, Package, Trash2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface NotificationsPageProps {
  lang: string;
  notifications: any[];
  onClear: () => void;
}

const NotificationsPage: React.FC<NotificationsPageProps> = ({ lang, notifications, onClear }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();

  const getIcon = (type: string) => {
    switch (type) {
      case 'LIKE': return <Heart className="text-red-500" size={18} />;
      case 'MESSAGE': return <MessageCircle className="text-brand" size={18} />;
      case 'RENTAL': return <Package className="text-blue-500" size={18} />;
      case 'RATE': return <Star className="text-yellow-500" size={18} />;
      default: return <Bell className="text-gray-400" size={18} />;
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 pt-10 pb-24 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-10">
        <div className="flex items-center gap-4">
          <button onClick={() => navigate(-1)} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm dark:text-white">
            <ArrowLeft className={lang === 'ar' ? 'rotate-180' : ''} />
          </button>
          <h1 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{t.notifications}</h1>
        </div>
        {notifications.length > 0 && (
          <button onClick={onClear} className="p-3 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 rounded-2xl transition-colors">
            <Trash2 size={20} />
          </button>
        )}
      </div>

      <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-4 border dark:border-gray-800 shadow-sm overflow-hidden">
        {notifications.length === 0 ? (
          <div className="py-32 text-center opacity-20 flex flex-col items-center">
            <Bell size={64} className="mb-4" />
            <p className="text-[10px] font-black uppercase tracking-widest">{t.noNotifications}</p>
          </div>
        ) : (
          <div className="divide-y dark:divide-gray-800">
            {notifications.map((n, i) => (
              <div key={i} className="p-6 flex items-start gap-4 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors cursor-pointer">
                <div className="w-12 h-12 rounded-2xl bg-gray-50 dark:bg-gray-800 flex items-center justify-center shrink-0 shadow-sm">
                  {getIcon(n.type)}
                </div>
                <div className="flex-1">
                   <p className="text-sm font-bold dark:text-white mb-1 leading-snug">{n.text}</p>
                   <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">{new Date(n.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                </div>
                {n.image && (
                  <img src={n.image} className="w-10 h-10 rounded-lg object-cover ml-auto" />
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default NotificationsPage;

