import React, { useState, useEffect } from 'react';
import { Heart, MapPin, Eye, Share2, MessageCircle, Trash2, MessageSquare, ShieldCheck, PlayCircle, Flag } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { POINTS_SYSTEM } from '../constants';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
  onAddPoints?: (a: number) => void;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete, onAddPoints, isFavorite, onToggleFavorite }) => {
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];

  const [views, setViews] = useState(() => {
    const key = `views_${listing.id}`;
    return parseInt(localStorage.getItem(key) || '0') + listing.views;
  });

  const incrementViews = () => {
    const key = `views_${listing.id}`;
    const newViews = views + 1;
    setViews(newViews);
    localStorage.setItem(key, newViews.toString());
  };

  const handleFavorite = (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();
    onToggleFavorite?.(listing.id);
    if (!isFavorite) onAddPoints?.(POINTS_SYSTEM.LIKE);
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (navigator.share) {
      try {
        await navigator.share({ title: listing.title, text: listing.description, url: window.location.href });
        onAddPoints?.(POINTS_SYSTEM.SHARE);
      } catch (err) {}
    }
  };

  const handleReport = (e: React.MouseEvent) => {
    e.stopPropagation();
    alert(lang === 'ar' ? 'تم استلام بلاغك. سيقوم نظام AI my rents بإعادة فحص المنتج.' : 'Report received. AI my rents will re-examine the product.');
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-xl transition-all border dark:border-gray-800 flex flex-col h-full relative group">
      {/* Header with User Info */}
      <div className="p-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <img src={listing.ownerAvatar} className="w-10 h-10 rounded-full border-2 border-brand/20 object-cover" />
          <div className="flex flex-col">
            <span className="text-[11px] font-black dark:text-white uppercase leading-none">{listing.ownerName}</span>
            <span className="text-[9px] font-bold text-[#CCCCCC]">@{listing.ownerUsername}</span>
          </div>
        </div>
        <div className="flex gap-1">
          <button onClick={handleFavorite} className={`p-2 rounded-xl transition-all ${isFavorite ? 'text-pink-500 bg-pink-50 dark:bg-pink-900/10' : 'text-gray-400 hover:text-brand'}`}>
             <Heart size={18} fill={isFavorite ? 'currentColor' : 'none'} />
          </button>
          {isOwner && (
            <button onClick={() => onDelete?.(listing.id)} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 rounded-xl">
              <Trash2 size={16} />
            </button>
          )}
        </div>
      </div>

      <Link to={`/item/${listing.id}`} onClick={incrementViews} className="block px-3">
        <div className="aspect-square overflow-hidden rounded-[2rem] relative">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
          {listing.video && (
             <div className="absolute top-3 left-3 bg-brand/90 backdrop-blur-sm text-white p-1.5 rounded-xl shadow-lg">
                <PlayCircle size={16} />
             </div>
          )}
          <div className="absolute bottom-3 right-3 bg-white/95 dark:bg-gray-900/95 backdrop-blur-sm px-3 py-1.5 rounded-2xl shadow-xl">
             <span className="text-xs font-black text-brand tracking-tighter">{listing.price} {listing.currency}</span>
             <span className="text-[7px] font-black text-gray-400 block uppercase text-center">{t.periods[listing.rentalPeriod]}</span>
          </div>
        </div>
      </Link>

      <div className="p-4 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-1">
          <h3 className="font-black dark:text-white uppercase truncate flex-1 tracking-tighter text-xs">{listing.title}</h3>
          <span className="text-[8px] font-black text-gray-400 bg-gray-50 dark:bg-gray-800 px-2 py-0.5 rounded-lg ml-2">{listing.category}</span>
        </div>

        <div className="flex items-center gap-1 text-gray-300 text-[9px] font-bold uppercase mb-4">
          <MapPin size={10} className="text-brand" /> {listing.location.address.split(',')[0]}
        </div>

        <div className="mt-auto grid grid-cols-3 gap-1 pt-3 border-t dark:border-gray-800">
          <button className="flex flex-col items-center gap-1 p-2 text-gray-400">
            <MessageSquare size={16} />
            <span className="text-[7px] font-black uppercase">{t.comments}</span>
          </button>
          <button onClick={handleShare} className="flex flex-col items-center gap-1 p-2 text-gray-400">
            <Share2 size={16} />
            <span className="text-[7px] font-black uppercase">{t.share}</span>
          </button>
          <button onClick={(e) => { e.preventDefault(); navigate(`/chat/${listing.ownerId}?item=${listing.id}`); }} className="flex flex-col items-center gap-1 p-2 text-brand bg-brand/5 rounded-xl hover:bg-brand hover:text-white transition-all">
            <MessageCircle size={16} />
            <span className="text-[7px] font-black uppercase">{lang === 'ar' ? 'دردشة' : 'Chat'}</span>
          </button>
        </div>

        <div className="mt-3 flex items-center justify-between text-[8px] font-black uppercase border-t dark:border-gray-800 pt-2">
           <div className="flex items-center gap-1 text-gray-400">
              <Eye size={10} /> {views} {t.views}
           </div>
           <div className="text-brand flex items-center gap-1">
              <ShieldCheck size={10} /> AI SECURE
           </div>
        </div>
      </div>
    </div>
  );
};

