import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useParams, useNavigate, useLocation as useRouteLocation } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing, GroupChat } from '../types';
import { 
  Trash2, MapPin, Flag, Send, UserPlus, ShieldCheck, Camera, 
  Loader2, MessageSquareOff, Mic, ShieldBan, Settings, X, Video, ChevronLeft, StopCircle, Play, Pause, Users
} from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ChatMessage {
  id: number;
  text?: string;
  sender: 'me' | 'other';
  type: 'text' | 'image' | 'video' | 'location' | 'voice';
  data?: string; 
  timestamp: number;
}

interface ChatPageProps {
  lang: string;
  listings: Listing[];
  user: any;
  onBlock: (id: string) => void;
  onAddPoints?: (a: number) => void;
  groups: GroupChat[];
  onCreateGroup: (g: GroupChat) => void;
}

const ChatPage: React.FC<ChatPageProps> = ({ lang, listings, user, onBlock, onAddPoints, groups, onCreateGroup }) => {
  const t = translations[lang] || translations['en'];
  const { otherId } = useParams();
  const routeLocation = useRouteLocation();
  const navigate = useNavigate();
  const queryParams = new URLSearchParams(routeLocation.search);
  const itemId = queryParams.get('item');

  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem(`chat_${user.id}_${otherId || 'global'}`);
    return saved ? JSON.parse(saved) : [];
  });
  const [input, setInput] = useState('');

  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [showGroupCreate, setShowGroupCreate] = useState(false);
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });
  const [isLocating, setIsLocating] = useState(false);

  const discussedItem = useMemo(() => itemId ? listings.find(l => l.id === itemId) : null, [itemId, listings]);

  useEffect(() => {
    localStorage.setItem(`chat_${user.id}_${otherId || 'global'}`, JSON.stringify(messages));
  }, [messages, user.id, otherId]);

  const handleSend = (type: ChatMessage['type'] = 'text', data?: string) => {
    if (type === 'text' && !input.trim()) return;
    const msg: ChatMessage = { id: Date.now(), text: type === 'text' ? input : undefined, sender: 'me', type, data, timestamp: Date.now() };
    setMessages(prev => [...prev, msg]);
    if (type === 'text') setInput('');
    onAddPoints?.(POINTS_SYSTEM.MESSAGE);

    // Auto-reply for demo if it's the first message
    if (messages.length === 0) {
      setTimeout(() => {
        const reply: ChatMessage = { 
          id: Date.now() + 1, 
          text: lang === 'ar' ? 'أهلاً بك! كيف يمكنني مساعدتك بخصوص هذا الغرض؟' : 'Hello! How can I help you with this item?', 
          sender: 'other', 
          type: 'text', 
          timestamp: Date.now() + 1 
        };
        setMessages(prev => [...prev, reply]);
      }, 1500);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.onloadend = () => handleSend('voice', reader.result as string);
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) { alert(lang === 'ar' ? 'يرجى السماح بالوصول للميكروفون' : 'Please allow microphone access'); }
  };

  const stopRecording = () => { if (mediaRecorderRef.current && isRecording) { mediaRecorderRef.current.stop(); setIsRecording(false); } };

  const shareLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(pos => {
        handleSend('location', `${pos.coords.latitude},${pos.coords.longitude}`);
        setIsLocating(false);
      }, () => {
        alert(lang === 'ar' ? 'فشل جلب الموقع' : 'Location access denied');
        setIsLocating(false);
      }, { enableHighAccuracy: true });
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'video') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => handleSend(type, ev.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleCreateGroupSubmit = () => {
    if (!groupData.name || !groupData.image) return;
    const newGroup: GroupChat = {
      id: 'g_' + Date.now(),
      name: groupData.name,
      description: groupData.description,
      image: groupData.image,
      adminId: user.id,
      members: [user.id]
    };
    onCreateGroup(newGroup);
    setShowGroupCreate(false);
    setGroupData({ name: '', description: '', image: '' });
  };

  return (
    <div className="max-w-7xl mx-auto flex h-[calc(100vh-140px)] mt-2 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 animate-in fade-in">
      {/* Sidebar */}
      <div className="w-80 border-r dark:border-gray-800 flex flex-col bg-gray-50/20 dark:bg-gray-950/20 shrink-0 hidden md:flex">
        <div className="p-6">
          <h1 className="text-xl font-black text-brand lowercase italic tracking-tighter mb-6">my rents chat</h1>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>Private</button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.groups}</button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto px-4 space-y-3">
           {activeTab === 'GROUPS' ? (
             <>
               <button onClick={() => setShowGroupCreate(true)} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl text-[10px] font-black uppercase text-gray-400 mb-4 hover:border-brand hover:text-brand transition-all flex items-center justify-center gap-2">
                 <UserPlus size={16} /> {t.createGroup}
               </button>
               {groups.map(g => (
                 <div key={g.id} className="p-3 bg-white dark:bg-gray-800 rounded-2xl border dark:border-gray-700 flex items-center gap-3 cursor-pointer hover:border-brand transition-all">
                    <img src={g.image} className="w-10 h-10 rounded-xl object-cover" />
                    <div className="flex-1 truncate">
                       <p className="text-[10px] font-black dark:text-white uppercase truncate">{g.name}</p>
                       <p className="text-[8px] text-gray-400 font-bold uppercase">{g.members.length} Members</p>
                    </div>
                 </div>
               ))}
             </>
           ) : (
             <div className="space-y-2">
               <div className="p-4 bg-brand/5 border border-brand/10 rounded-2xl flex items-center gap-3 cursor-pointer">
                  <div className="w-10 h-10 rounded-full bg-brand text-white flex items-center justify-center font-bold">M</div>
                  <div className="flex-1 truncate">
                     <p className="text-xs font-black dark:text-white uppercase">My Rents Support</p>
                     <p className="text-[9px] text-brand font-bold uppercase">Always Online</p>
                  </div>
               </div>
             </div>
           )}
        </div>
      </div>

      {/* Main Chat View */}
      <div className="flex-1 flex flex-col bg-white dark:bg-gray-900 relative">
        <div className="p-4 border-b dark:border-gray-800 flex justify-between items-center bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm z-10">
           <div className="flex items-center gap-3">
              <button onClick={() => navigate(-1)} className="md:hidden p-2"><ChevronLeft /></button>
              <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand"><ShieldCheck size={24} /></div>
              <div><h2 className="font-black dark:text-white text-xs uppercase tracking-tighter italic">AI SECURE</h2><span className="text-[8px] text-green-500 font-black uppercase">Live Encryption Active</span></div>
        </div>
           <div className="flex gap-1">
              <button onClick={() => { if(confirm(t.clearChat)) setMessages([]) }} className="p-2.5 text-gray-400 hover:text-red-500 rounded-xl transition-all" title="Clear Chat"><Trash2 size={20} /></button>
              <button onClick={() => alert('Report Submitted')} className="p-2.5 text-gray-400 hover:text-brand rounded-xl" title="Report"><Flag size={20} /></button>
              <button onClick={() => { if(otherId) onBlock(otherId); navigate('/'); }} className="p-2.5 text-gray-400 hover:text-brand" title="Block"><ShieldBan size={20} /></button>
           </div>
        </div>

        {discussedItem && (
          <div className="p-3 bg-brand/5 border-b border-brand/10 flex items-center justify-between animate-in slide-in-from-top">
             <div className="flex items-center gap-2">
                <img src={discussedItem.images[0]} className="w-10 h-10 rounded-lg object-cover" />
                <p className="text-[10px] font-black dark:text-white uppercase truncate max-w-[150px]">{discussedItem.title}</p>
             </div>
             <button onClick={() => alert(t.confirmRental)} className="px-5 py-2 bg-brand text-white rounded-xl text-[9px] font-black uppercase shadow-lg">RENT NOW</button>
          </div>
        )}

        <div className="flex-1 p-6 overflow-y-auto space-y-4 bg-gray-50/10 dark:bg-transparent">
           {messages.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-20 text-center px-10">
                <ShieldCheck size={64} className="text-brand mb-4" />
                <p className="text-[10px] font-black dark:text-white uppercase tracking-widest leading-relaxed">
                  {lang === 'ar' ? 'ابدأ الحديث بشكل آمن تماماً.' : 'End-to-end secured chat started.'}
                </p>
             </div>
           ) : (
             messages.map(m => (
             <div key={m.id} className={`flex ${m.sender === 'me' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                <div className={`p-4 rounded-[1.8rem] shadow-sm text-xs font-bold max-w-[85%] ${m.sender === 'me' ? 'bg-brand text-white rounded-tr-none shadow-brand/10' : 'bg-gray-100 dark:bg-gray-800 dark:text-white rounded-tl-none'}`}>
                   {m.type === 'image' && <img src={m.data} className="rounded-2xl mb-2 max-w-full h-auto shadow-md" alt="Attachment" />}
                   {m.type === 'video' && <video src={m.data} controls className="rounded-2xl mb-2 max-w-full shadow-md" />}
                   {m.type === 'voice' && (
                     <div className="flex items-center gap-3 p-2 bg-black/5 dark:bg-white/5 rounded-2xl min-w-[200px]">
                        <audio src={m.data} controls className="h-8 w-full scale-90" />
                     </div>
                   )}
                   {m.type === 'location' ? (
                     <a href={`https://maps.google.com?q=${m.data}`} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 underline uppercase text-[10px] bg-white/10 p-2 rounded-xl">
                       <MapPin size={16} /> {lang === 'ar' ? 'عرض موقعي على الخريطة' : 'View Shared Location'}
                     </a>
                   ) : m.text}
                   <div className={`text-[7px] mt-2 font-black uppercase opacity-40 text-right ${m.sender === 'me' ? 'text-white' : 'text-gray-400'}`}>
                     {new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                   </div>
                </div>
             </div>
           ))
           )}
        </div>

        {/* Input Controls */}
        <div className="p-6 border-t dark:border-gray-800 bg-white/95 dark:bg-gray-900/95 backdrop-blur-md">
           <div className="flex gap-2 mb-4 overflow-x-auto pb-1 scrollbar-hide">
              <button 
                onMouseDown={startRecording} onMouseUp={stopRecording} onTouchStart={startRecording} onTouchEnd={stopRecording}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-2xl text-[9px] font-black uppercase transition-all shadow-sm ${isRecording ? 'bg-red-500 text-white animate-pulse scale-105' : 'bg-gray-50 dark:bg-gray-800 text-gray-400 hover:text-brand'}`}
              >
                {isRecording ? <StopCircle size={16} /> : <Mic size={16} />}
                {isRecording ? t.voiceRecording : t.voice}
              </button>
              <label className="flex items-center gap-2 px-5 py-2.5 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand transition-all shadow-sm">
                <Camera size={16} /> {lang === 'ar' ? 'صور' : 'Photos'}
                <input type="file" className="hidden" accept="image/*" onChange={e => handleFileUpload(e, 'image')} />
              </label>
              <label className="flex items-center gap-2 px-5 py-2.5 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 cursor-pointer hover:text-brand transition-all shadow-sm">
                <Video size={16} /> {lang === 'ar' ? 'فيديو' : 'Video'}
                <input type="file" className="hidden" accept="video/*" onChange={e => handleFileUpload(e, 'video')} />
              </label>
              <button onClick={shareLocation} disabled={isLocating} className="flex items-center gap-2 px-5 py-2.5 bg-gray-50 dark:bg-gray-800 rounded-2xl text-[9px] font-black uppercase text-gray-400 hover:text-brand transition-all shadow-sm">
                {isLocating ? <Loader2 size={16} className="animate-spin" /> : <MapPin size={16} />} {t.location}
              </button>
           </div>
           <div className="flex gap-3">
              <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} className="flex-1 bg-gray-100 dark:bg-gray-800 dark:text-white px-8 py-5 rounded-[2.2rem] outline-none font-bold text-sm shadow-inner focus:ring-2 focus:ring-brand transition-all" placeholder={lang === 'ar' ? 'اكتب رسالتك هنا...' : 'Type your message...'} />
              <button onClick={() => handleSend()} className="w-16 h-16 bg-brand text-white rounded-[1.8rem] flex items-center justify-center shadow-xl shadow-brand/30 active:scale-90 hover:scale-105 transition-all"><Send size={28} /></button>
           </div>
        </div>
      </div>

      {/* Group Creation Overlay */}
      {showGroupCreate && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-300">
           <div className="bg-white dark:bg-gray-900 w-full max-w-md rounded-[3rem] p-8 shadow-2xl animate-in zoom-in-95">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-black dark:text-white italic uppercase tracking-tighter italic">Launch Community</h3>
                <button onClick={() => setShowGroupCreate(false)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl"><X /></button>
              </div>

              <label className="w-32 h-32 mx-auto mb-6 bg-gray-100 dark:bg-gray-800 rounded-[2.5rem] border-4 border-dashed border-brand/20 flex flex-col items-center justify-center cursor-pointer overflow-hidden relative group">
                 {groupData.image ? <img src={groupData.image} className="w-full h-full object-cover" /> : <Camera className="text-gray-400" />}
                 <input type="file" className="hidden" accept="image/*" onChange={e => {
                   const f = e.target.files?.[0];
                   if (f) { const r = new FileReader(); r.onload = (ev) => setGroupData({...groupData, image: ev.target?.result as string}); r.readAsDataURL(f); }
                 }} />
              </label>

              <div className="space-y-4">
                 <input type="text" placeholder="Community Name*" value={groupData.name} onChange={e => setGroupData({...groupData, name: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
                 <textarea placeholder="Purpose / Description*" value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-24 outline-none font-bold" />
                 <button onClick={handleCreateGroupSubmit} disabled={!groupData.name || !groupData.image} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl shadow-brand/20 disabled:opacity-30">Create Community</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default ChatPage;

