import React, { useState } from 'react';
import { translations } from '../i18n';
import { User, PayoutMethods } from '../types';
import { 
  ArrowLeft, Camera, MapPin, Navigation, Edit3, Save, 
  CreditCard, Wallet, ShieldCheck, Globe, Loader2, CheckCircle2, Circle
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { CURRENCIES } from '../constants';

interface SettingsPageProps {
  lang: string;
  user: User;
  onUpdate: (user: User) => void;
}

const SettingsPage: React.FC<SettingsPageProps> = ({ lang, user, onUpdate }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isManualLocation, setIsManualLocation] = useState(false);

  const [formData, setFormData] = useState<User>({
    ...user,
    payoutMethods: user.payoutMethods || {}
  });

  const [manualAddress, setManualAddress] = useState(user.location.address);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const updatePayout = (method: keyof PayoutMethods, value: string) => {
    setFormData({
      ...formData,
      payoutMethods: { ...formData.payoutMethods, [method]: value }
    });
  };

  const handleSave = () => {
    setLoading(true);
    const updatedUser: User = {
      ...formData,
      location: isManualLocation 
        ? { ...formData.location, address: manualAddress } 
        : formData.location
    };

    setTimeout(() => {
      onUpdate(updatedUser);
      setLoading(false);
      alert(lang === 'ar' ? 'تم حفظ كافة الإعدادات المالية والمدفوعات بنجاح!' : 'All financial and payout settings saved successfully!');
    }, 1200);
  };

  const payoutOptions = [
    { key: 'paypal', label: 'PayPal', icon: <CreditCard size={18} />, placeholder: 'Email Address' },
    { key: 'solana', label: 'Solana', icon: <Wallet size={18} />, placeholder: 'SOL Wallet' },
    { key: 'ethereum', label: 'Ethereum', icon: <Wallet size={18} />, placeholder: 'ETH Address' },
    { key: 'monad', label: 'Monad', icon: <ShieldCheck size={18} />, placeholder: 'Monad Address' },
    { key: 'base', label: 'Base', icon: <Globe size={18} />, placeholder: 'Base L2 Address' },
    { key: 'sui', label: 'Sui', icon: <Wallet size={18} />, placeholder: 'Sui Wallet' },
    { key: 'polygon', label: 'Polygon', icon: <Wallet size={18} />, placeholder: 'MATIC Address' },
    { key: 'bitcoin', label: 'Bitcoin', icon: <Wallet size={18} />, placeholder: 'BTC Address' },
  ];

  return (
    <div className="max-w-4xl mx-auto p-4 pt-10 pb-24 animate-in fade-in duration-500">
      <div className="flex items-center gap-4 mb-10">
        <button onClick={() => navigate(-1)} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm dark:text-white hover:scale-105 transition-transform">
          <ArrowLeft className={lang === 'ar' ? 'rotate-180' : ''} />
        </button>
        <div>
          <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic">{t.settings}</h1>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{lang === 'ar' ? 'إدارة الحساب والمدفوعات' : 'Manage Account & Payouts'}</p>
        </div>
      </div>

      <div className="space-y-6">
        <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 border dark:border-gray-800 shadow-xl">
           <div className="flex flex-col items-center mb-10">
              <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-brand/20 overflow-hidden flex items-center justify-center cursor-pointer group relative shadow-2xl">
                <img src={formData.avatar} className="w-full h-full object-cover group-hover:opacity-50 transition-opacity" />
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 text-brand">
                  <Camera size={24} />
                </div>
                <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
              </label>
              <h2 className="mt-4 text-xl font-black dark:text-white uppercase italic">{formData.fullName}</h2>
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest">@{formData.username}</p>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Display Name</label>
                <input type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Preferred Currency</label>
                <select 
                  value={formData.currencyPreference} 
                  onChange={e => setFormData({...formData, currencyPreference: e.target.value})}
                  className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold appearance-none border-2 border-transparent focus:border-brand"
                >
                  {CURRENCIES.map(c => <option key={c.code} value={c.code}>{c.label} ({c.symbol})</option>)}
                </select>
              </div>
           </div>
        </div>

        <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 border dark:border-gray-800 shadow-xl">
           <h3 className="text-xl font-black text-brand uppercase tracking-tighter italic mb-8 flex items-center gap-3">
             <CreditCard size={24} /> {lang === 'ar' ? 'إعدادات صرف الأرباح' : 'Payout Configuration'}
           </h3>
           <p className="text-xs text-gray-400 font-bold uppercase mb-8 leading-relaxed">
             {lang === 'ar' ? 'قم بتفعيل العناوين التي ترغب باستلام أرباح التأجير عليها. يمكنك تفعيل أكثر من خيار في نفس الوقت.' : 'Enable the addresses where you want to receive rental earnings. You can enable multiple options simultaneously.'}
           </p>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {payoutOptions.map(opt => {
                const isEnabled = !!formData.payoutMethods[opt.key as keyof PayoutMethods];
                return (
                  <div key={opt.key} className={`p-6 rounded-[2rem] border-2 transition-all ${isEnabled ? 'border-brand bg-brand/5' : 'border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-gray-950/50'}`}>
                    <div className="flex items-center justify-between mb-4">
                       <div className="flex items-center gap-3">
                          <div className={`p-2 rounded-lg ${isEnabled ? 'bg-brand text-white' : 'bg-gray-200 text-gray-400'}`}>
                             {opt.icon}
                          </div>
                          <span className="font-black text-xs uppercase dark:text-white">{opt.label}</span>
                       </div>
                       <button 
                        onClick={() => updatePayout(opt.key as keyof PayoutMethods, isEnabled ? '' : ' ')}
                        className={`transition-all ${isEnabled ? 'text-brand' : 'text-gray-300'}`}
                       >
                         {isEnabled ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                       </button>
                    </div>
                    {isEnabled && (
                      <div className="animate-in slide-in-from-top-2">
                        <input 
                          type="text" 
                          value={formData.payoutMethods[opt.key as keyof PayoutMethods] || ''}
                          onChange={(e) => updatePayout(opt.key as keyof PayoutMethods, e.target.value)}
                          placeholder={opt.placeholder}
                          className="w-full bg-white dark:bg-gray-900 p-4 rounded-xl text-xs font-bold outline-none border-2 border-brand/20 focus:border-brand dark:text-white"
                        />
                      </div>
                    )}
                  </div>
                );
              })}
           </div>
        </div>

        <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 border dark:border-gray-800 shadow-xl">
           <div className="flex items-center justify-between mb-8">
              <h3 className="text-xl font-black text-brand uppercase tracking-tighter italic flex items-center gap-3">
                <MapPin size={24}/> {t.location}
              </h3>
              <button 
                onClick={() => setIsManualLocation(!isManualLocation)}
                className="text-[10px] font-black uppercase text-gray-400 hover:text-brand flex items-center gap-2"
              >
                {isManualLocation ? <Navigation size={14}/> : <Edit3 size={14}/>}
                {isManualLocation ? t.useGPS : t.enterManually}
              </button>
           </div>

           {!isManualLocation ? (
              <button 
                onClick={() => {
                  setIsLocating(true);
                  navigator.geolocation.getCurrentPosition((pos) => {
                    setFormData({ ...formData, location: { ...formData.location, lat: pos.coords.latitude, lng: pos.coords.longitude, address: 'Live GPS Location' }});
                    setManualAddress('Live GPS Location');
                    setIsLocating(false);
                  });
                }}
                disabled={isLocating}
                className="w-full p-6 bg-gray-50 dark:bg-gray-800 rounded-[2rem] flex items-center justify-between group hover:border-brand border-2 border-transparent transition-all"
              >
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-brand/10 text-brand rounded-2xl flex items-center justify-center">
                    <Navigation size={24} className={isLocating ? 'animate-spin' : ''} />
                  </div>
                  <div className="text-left">
                    <p className="text-xs font-black dark:text-white uppercase">{formData.location.address}</p>
                    <p className="text-[9px] text-gray-400 font-bold uppercase">Click to refresh GPS</p>
                  </div>
                </div>
              </button>
           ) : (
              <input 
                type="text" 
                value={manualAddress} 
                onChange={e => setManualAddress(e.target.value)}
                placeholder={t.addressPlaceholder}
                className="w-full p-6 bg-gray-50 dark:bg-gray-800 rounded-[2rem] outline-none font-bold dark:text-white border-2 border-brand shadow-inner"
              />
           )}
        </div>

        <div className="pt-6">
          <button 
            onClick={handleSave} 
            disabled={loading}
            className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-4 transition-all active:scale-95 disabled:opacity-50"
          >
            {loading ? <Loader2 className="animate-spin" size={24} /> : <Save size={24} />}
            {t.saveChanges}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsPage;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing, PayoutMethods } from '../types';
import { checkListingContent, estimateRentalPrice } from '../services/geminiService';
import { Camera, ShieldCheck, Sparkles, Loader2, ArrowRight, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { useNavigate, Link } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const [images, setImages] = useState<string[]>([]);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);

  const userPayouts = user.payoutMethods || {};
  const enabledPayouts = Object.entries(userPayouts).filter(([_, val]) => val && (val as string).trim() !== '');

  const [selectedPayout, setSelectedPayout] = useState<string>(enabledPayouts[0]?.[0] || '');

  const handleEstimate = async () => {
    if (!title || !description) return;
    setEstimating(true);
    const est = await estimateRentalPrice(title, description, user.currencyPreference || 'USD');
    setPrice(est.toString());
    setEstimating(false);
  };

  const handlePublish = async () => {
    if (images.length < 2) { alert(t.minImages); return; }
    if (!selectedPayout) { alert(lang === 'ar' ? 'يرجى اختيار وسيلة دفع من القائمة' : 'Please select a payout method'); return; }

    setLoading(true);
    const moderation = await checkListingContent(title, description);
    if (moderation.status === 'REJECTED') { 
      alert(moderation.reason); 
      setLoading(false); 
      return; 
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: selectedPayout === 'paypal' ? CurrencyType.LOCAL : CurrencyType.CRYPTO,
      payoutMethod: selectedPayout === 'paypal' ? 'PAYPAL' : 'CRYPTO',
      cryptoCurrency: selectedPayout !== 'paypal' ? selectedPayout : undefined,
      payoutAddress: userPayouts[selectedPayout as keyof PayoutMethods] || '',
      category,
      location: user.location,
      images,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: true,
      unavailableDates: [],
      status: 'PUBLISHED',
      visibility: 'PUBLIC',
      review_state: 'APPROVED',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(6);
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-8 shadow-2xl border dark:border-gray-800">
      <div className="flex gap-2 mb-8">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-xl font-black dark:text-white uppercase italic text-center">{lang === 'ar' ? 'الصور' : 'Photos'}</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-[1.5rem] overflow-hidden shadow-md">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-2 right-2 bg-red-500 text-white p-1 rounded-full">×</button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[1.5rem] border-4 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400 cursor-pointer hover:border-brand">
                <Camera size={32} />
                <span className="text-[9px] font-black uppercase mt-1">{images.length}/5</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={e => {
                  const files = Array.from(e.target.files || []);
                  files.forEach((f: any) => {
                    const r = new FileReader();
                    r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
                    r.readAsDataURL(f);
                  });
                }} />
              </label>
            )}
          </div>
          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30">Continue</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-xl font-black dark:text-white uppercase italic text-center">Item Details</h2>
          <input type="text" placeholder="Title*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none font-bold shadow-inner" />
          <textarea placeholder="Description*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none h-32 font-bold shadow-inner" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl font-bold">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Continue</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-xl font-black dark:text-white uppercase italic text-center">{lang === 'ar' ? 'وسيلة استلام الأرباح' : 'Payout Method'}</h2>

          {enabledPayouts.length === 0 ? (
            <div className="p-10 bg-red-50 dark:bg-red-900/10 rounded-[2.5rem] border-2 border-red-100 text-center">
              <AlertTriangle size={48} className="text-red-500 mx-auto mb-4" />
              <p className="text-sm font-black text-red-700 uppercase mb-6 leading-relaxed">
                {lang === 'ar' ? 'يجب عليك إعداد وسيلة صرف أرباح واحدة على الأقل في الإعدادات قبل النشر' : 'You must set up at least one payout method in settings before publishing'}
              </p>
              <Link to="/settings" className="px-8 py-4 bg-brand text-white rounded-2xl font-black uppercase text-xs inline-block shadow-lg">Go to Settings</Link>
            </div>
          ) : (
            <>
              <p className="text-[10px] text-gray-400 font-bold uppercase text-center">Select which method to link to this item</p>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {enabledPayouts.map(([key, val]) => (
                  <button 
                    key={key} 
                    onClick={() => setSelectedPayout(key)}
                    className={`p-6 rounded-[2rem] border-4 transition-all flex items-center justify-between ${selectedPayout === key ? 'border-brand bg-brand/5' : 'border-gray-50 bg-gray-50'}`}
                  >
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-brand text-white rounded-xl flex items-center justify-center font-black uppercase italic text-xs">{key.slice(0, 1)}</div>
                      <div className="text-left">
                         <p className="text-xs font-black dark:text-white uppercase">{key}</p>
                         <p className="text-[9px] text-gray-400 truncate w-32 font-mono">{val as string}</p>
                      </div>
                    </div>
                    {selectedPayout === key && <CheckCircle2 className="text-brand" />}
                  </button>
                ))}
              </div>
            </>
          )}

          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(4)} disabled={!selectedPayout} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Continue</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 animate-in slide-in-from-right text-center">
          <h2 className="text-xl font-black dark:text-white uppercase italic">Pricing & Duration</h2>
          <div className="flex items-center justify-center gap-3">
            <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-4 border-brand text-4xl font-black text-center dark:text-white outline-none" placeholder="0" />
            <span className="text-xl font-black text-brand">{user.currencyPreference || 'USD'}</span>
          </div>
          <button onClick={handleEstimate} disabled={estimating} className="px-6 py-2 bg-brand/10 text-brand rounded-xl font-black text-[9px] uppercase flex items-center gap-2 mx-auto">
            {estimating ? <Loader2 className="animate-spin" size={14} /> : <Sparkles size={14} />} AI Estimate
          </button>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
            {Object.values(RentalPeriod).map(p => (
              <button key={p} onClick={() => setPeriod(p)} className={`py-3 rounded-xl font-black text-[8px] uppercase ${period === p ? 'bg-brand text-white' : 'bg-gray-100 text-gray-400'}`}>{t.periods[p]}</button>
            ))}
          </div>
          <div className="flex gap-4">
            <button onClick={() => setStep(3)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(5)} disabled={!price} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Finalize</button>
          </div>
        </div>
      )}

      {step === 5 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <ShieldCheck size={64} className="text-brand mx-auto animate-bounce" />
          <h2 className="text-2xl font-black dark:text-white uppercase italic">AI Verification</h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase max-w-xs mx-auto">AI my rents is checking your listing for safety and community compliance.</p>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} {t.securePublish}
          </button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center py-12 animate-in fade-in">
           <div className="w-24 h-24 bg-green-500 text-white rounded-[2rem] flex items-center justify-center mx-auto shadow-xl mb-6"><CheckCircle2 size={40} /></div>
           <h2 className="text-3xl font-black dark:text-white uppercase italic">Published!</h2>
           <button onClick={() => navigate('/')} className="mt-8 px-12 py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl">Back Home</button>
        </div>
      )}
    </div>
  );
};

