import React, { useState } from 'react';
import { Camera, MapPin, Mail, Lock, User as UserIcon, ShieldCheck, Loader2, Edit3, Navigation, CheckSquare } from 'lucide-react';
import { Link } from 'react-router-dom';
import { translations } from '../i18n';
import { Gender, User } from '../types';

interface SignUpPageProps {
  lang: string;
  onSignUp: (user: User) => void;
}

const SignUpPage: React.FC<SignUpPageProps> = ({ lang, onSignUp }) => {
  const t = translations[lang] || translations['en'];
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isManualLocation, setIsManualLocation] = useState(false);

  const [formData, setFormData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    email: '',
    password: '',
    location: null as { lat: number, lng: number, address: string } | null,
    manualAddress: '',
    agreed: false
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setFormData({
            ...formData,
            location: { 
              lat: pos.coords.latitude, 
              lng: pos.coords.longitude, 
              address: lang === 'ar' ? 'موقعي الحي (GPS)' : 'My Live GPS Location' 
            }
          });
          setIsLocating(false);
          setIsManualLocation(false);
        },
        () => {
          alert(lang === 'ar' ? 'فشل جلب الموقع، يرجى تفعيل الـ GPS أو الإدخال يدوياً' : 'GPS failed, please enable location or enter manually');
          setIsLocating(false);
          setIsManualLocation(true);
        },
        { timeout: 10000, enableHighAccuracy: true }
      );
    } else {
      setIsManualLocation(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalLocation = formData.location;
    if (isManualLocation) {
      if (!formData.manualAddress.trim()) {
        alert(lang === 'ar' ? 'يرجى إدخال الموقع يدوياً (مطلوب)' : 'Manual location is required');
        return;
      }
      finalLocation = { lat: 0, lng: 0, address: formData.manualAddress };
    }

    if (!formData.avatar || !finalLocation || !formData.agreed || !formData.fullName || !formData.username || !formData.email || !formData.password) {
      alert(lang === 'ar' ? 'يرجى إكمال جميع الخطوات المطلوبة' : 'Please complete all mandatory steps');
      return;
    }

    setLoading(true);
    setTimeout(() => {
      const newUser: User = {
        id: 'u_' + Date.now(),
        fullName: formData.fullName,
        username: formData.username,
        email: formData.email,
        avatar: formData.avatar,
        gender: Gender.OTHER,
        birthDate: '2000-01-01',
        location: finalLocation!,
        status: 'Member',
        points: 100,
        listingsCount: 0,
        walletBalance: 0,
        currencyPreference: 'USD',
        trustScore: 85,
        badges: ['Verified'],
        payoutMethods: {},
        blockedUsers: [],
        isVerified: true
      };
      onSignUp(newUser);
      setLoading(false);
    }, 2000);
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-950 flex flex-col items-center justify-center p-4 py-20">
      <div className="w-full max-w-lg bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-2xl border dark:border-gray-800 animate-in fade-in zoom-in-95 duration-500 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-brand opacity-20" />

        <div className="text-center mb-10">
          <h1 className="text-5xl font-black text-brand italic tracking-tighter lowercase mb-2">my rents</h1>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">{lang === 'ar' ? 'نظام تأجير آمن بنسبة 100%' : '100% Secure Rental System'}</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="flex flex-col items-center gap-4">
            <label className="w-32 h-32 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 border-4 border-dashed border-gray-200 dark:border-gray-700 overflow-hidden flex items-center justify-center cursor-pointer group transition-all hover:border-brand relative shadow-inner">
              {formData.avatar ? (
                <img src={formData.avatar} className="w-full h-full object-cover" alt="Preview" />
              ) : (
                <Camera size={40} className="text-gray-300 group-hover:text-brand" />
              )}
              <input type="file" accept="image/*" required className="hidden" onChange={handleImageUpload} />
              {!formData.avatar && <span className="absolute bottom-3 text-[7px] font-black text-brand uppercase tracking-widest animate-pulse">Required</span>}
            </label>
            <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">{lang === 'ar' ? 'ارفع صورتك الشخصية*' : 'Upload Profile Picture*'}</p>
          </div>

          <div className="grid grid-cols-1 gap-4">
            <div className="relative">
              <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="text" required placeholder={t.fullName + '*'} value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner transition-all" />
            </div>

            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-black">@</span>
              <input type="text" required placeholder={t.username + '*'} value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner transition-all" />
            </div>

            <div className="space-y-3">
              {!isManualLocation ? (
                <button 
                  type="button" 
                  onClick={handleGetLocation}
                  disabled={isLocating}
                  className={`w-full py-5 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-[10px] tracking-widest transition-all border-2 ${formData.location ? 'bg-brand/5 text-brand border-brand shadow-lg' : 'bg-gray-50 dark:bg-gray-800 text-gray-400 border-transparent hover:border-brand'}`}
                >
                  {isLocating ? <Loader2 className="animate-spin" size={18} /> : <MapPin size={18} />}
                  {formData.location ? (lang === 'ar' ? 'تم جلب الموقع بنجاح 📍' : 'Location Captured 📍') : (lang === 'ar' ? 'تحديد موقعي الحي 📍 (مطلوب)' : 'Capture My GPS Location 📍 (Required)')}
                </button>
              ) : (
                <div className="relative animate-in slide-in-from-top-2">
                  <MapPin className="absolute left-5 top-1/2 -translate-y-1/2 text-brand" size={18} />
                  <input 
                    type="text" 
                    required
                    placeholder={t.addressPlaceholder + '*'} 
                    value={formData.manualAddress} 
                    onChange={e => setFormData({...formData, manualAddress: e.target.value})} 
                    className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-brand shadow-inner" 
                  />
                </div>
              )}

              <button 
                type="button" 
                onClick={() => setIsManualLocation(!isManualLocation)}
                className="w-full text-center text-[9px] font-black text-brand uppercase tracking-widest hover:underline flex items-center justify-center gap-1 transition-all"
              >
                {isManualLocation ? <Navigation size={12}/> : <Edit3 size={12}/>}
                {isManualLocation ? t.useGPS : t.enterManually}
              </button>
            </div>

            <div className="relative">
              <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="email" required placeholder={t.email + '*'} value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner transition-all" />
            </div>

            <div className="relative">
              <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="password" required placeholder={t.password + '*'} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full pl-14 pr-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold border-2 border-transparent focus:border-brand shadow-inner transition-all" />
            </div>

            <div className="p-5 bg-brand/5 border border-brand/10 rounded-2xl">
              <div className="flex items-start gap-3">
                <input type="checkbox" id="agreed" checked={formData.agreed} onChange={e => setFormData({...formData, agreed: e.target.checked})} className="w-5 h-5 accent-brand mt-1 shrink-0 cursor-pointer" />
                <label htmlFor="agreed" className="text-[10px] font-bold text-gray-500 uppercase leading-relaxed cursor-pointer">
                  {t.acceptTerms}*
                  <div className="mt-2 flex gap-4">
                    <Link to="/privacy" className="text-brand underline">{t.privacyPolicy}</Link>
                    <Link to="/terms" className="text-brand underline">{t.termsOfUse}</Link>
                  </div>
                </label>
              </div>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading || !formData.agreed || (!formData.location && !formData.manualAddress) || !formData.avatar || !formData.fullName || !formData.username || !formData.email || !formData.password}
            className="w-full py-6 bg-brand text-white rounded-[2.2rem] font-black uppercase tracking-widest shadow-2xl shadow-brand/40 disabled:opacity-30 active:scale-95 transition-all flex items-center justify-center gap-3 group"
          >
            {loading ? <Loader2 className="animate-spin" /> : <ShieldCheck className="group-hover:rotate-12 transition-transform" />}
            {lang === 'ar' ? 'إطلاق حسابي الفعلي' : 'Launch My Real Account'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default SignUpPage;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { User, PayoutMethods } from '../types';
import { 
  ArrowLeft, Camera, MapPin, Navigation, Edit3, Save, 
  CreditCard, Wallet, ShieldCheck, Globe, Loader2, CheckCircle2, Circle, Mail
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { CURRENCIES } from '../constants';

interface SettingsPageProps {
  lang: string;
  user: User;
  onUpdate: (user: User) => void;
}

const SettingsPage: React.FC<SettingsPageProps> = ({ lang, user, onUpdate }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isManualLocation, setIsManualLocation] = useState(false);

  const [formData, setFormData] = useState<User>({
    ...user,
    payoutMethods: user.payoutMethods || {}
  });

  const [manualAddress, setManualAddress] = useState(user.location.address);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const updatePayout = (method: keyof PayoutMethods, value: string) => {
    setFormData({
      ...formData,
      payoutMethods: { ...formData.payoutMethods, [method]: value }
    });
  };

  const handleSave = () => {
    setLoading(true);
    const updatedUser: User = {
      ...formData,
      location: isManualLocation 
        ? { ...formData.location, address: manualAddress } 
        : formData.location
    };

    setTimeout(() => {
      onUpdate(updatedUser);
      setLoading(false);
