             <div className="mt-10 pt-10 border-t dark:border-gray-800">
                <h3 className="text-xl font-black text-blue-500 uppercase tracking-tighter italic mb-8 flex items-center gap-3"><CreditCard size={24}/> PayPal Payment</h3>
