            <div className="flex items-start gap-3 p-4 bg-brand/5 rounded-2xl">
              <input type="checkbox" id="agreed" checked={formData.agreed} onChange={e => setFormData({...formData, agreed: e.target.checked})} className="mt-1 accent-brand w-5 h-5" />
              <label htmlFor="agreed" className="text-[10px] font-bold text-gray-500 uppercase leading-tight">
