import React, { useState } from 'react';
import { Heart, MapPin, Eye, Share2, MessageCircle, Trash2, ShieldCheck, PlayCircle, MessageSquare } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { POINTS_SYSTEM } from '../constants';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
  onAddPoints?: (a: number) => void;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete, onAddPoints, isFavorite, onToggleFavorite }) => {
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];

  const [views, setViews] = useState(() => {
    const key = `views_${listing.id}`;
    return parseInt(localStorage.getItem(key) || '0') + listing.views;
  });

  const incrementViews = () => {
    const key = `views_${listing.id}`;
    const newViews = views + 1;
    setViews(newViews);
    localStorage.setItem(key, newViews.toString());
  };

  const handleFavorite = (e: React.MouseEvent) => {
    e.stopPropagation(); e.preventDefault();
    onToggleFavorite?.(listing.id);
    if (!isFavorite) onAddPoints?.(POINTS_SYSTEM.LIKE);
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all border dark:border-gray-800 flex flex-col h-full group">
      {/* Header with User Info */}
      <div className="p-4 flex items-center justify-between border-b dark:border-gray-800">
        <div className="flex items-center gap-2">
          <img src={listing.ownerAvatar} className="w-9 h-9 rounded-full border-2 border-brand/20 object-cover" />
          <div className="flex flex-col">
            <span className="text-[10px] font-black dark:text-white uppercase leading-none">{listing.ownerName}</span>
            <span className="text-[9px] font-bold text-[#CCCCCC]">@{listing.ownerUsername}</span>
          </div>
        </div>
        <div className="flex gap-1">
          <button onClick={handleFavorite} className={`p-2 rounded-xl transition-all ${isFavorite ? 'text-brand bg-brand/5' : 'text-gray-400 hover:text-brand'}`}>
             <Heart size={16} fill={isFavorite ? 'currentColor' : 'none'} />
          </button>
          {isOwner && (
            <button onClick={() => onDelete?.(listing.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-xl">
              <Trash2 size={16} />
            </button>
          )}
        </div>
      </div>

      <Link to={`/item/${listing.id}`} onClick={incrementViews} className="block px-3 pt-3">
        <div className="aspect-square overflow-hidden rounded-[2rem] relative">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
          {listing.video && <div className="absolute top-4 left-4 bg-brand text-white p-2 rounded-xl shadow-lg"><PlayCircle size={16} /></div>}
          <div className="absolute bottom-4 right-4 bg-white/95 dark:bg-gray-900/95 px-4 py-2 rounded-2xl shadow-xl flex flex-col items-center">
             <span className="text-xs font-black text-brand italic tracking-tighter">{listing.price} {listing.currency}</span>
             <span className="text-[6px] font-black text-gray-400 uppercase">{t.periods[listing.rentalPeriod]}</span>
          </div>
        </div>
      </Link>

      <div className="p-5 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-1">
          <h3 className="font-black dark:text-white uppercase text-xs truncate max-w-[140px] tracking-tighter italic">{listing.title}</h3>
          <span className="text-[7px] font-black text-gray-400 bg-gray-50 dark:bg-gray-800 px-2 py-1 rounded-lg uppercase">{listing.category}</span>
        </div>

        <div className="flex items-center gap-1 text-[#CCCCCC] text-[8px] font-black uppercase mb-4">
          <MapPin size={10} className="text-brand" /> {listing.location.city}, {listing.location.district}
        </div>

        <div className="mt-auto grid grid-cols-3 gap-2 pt-4 border-t dark:border-gray-800">
          <button onClick={(e) => {e.preventDefault(); e.stopPropagation();}} className="flex flex-col items-center gap-1 text-gray-400 hover:text-brand">
            <MessageSquare size={16} />
            <span className="text-[7px] font-black uppercase">Comments</span>
          </button>
          <button className="flex flex-col items-center gap-1 text-gray-400 hover:text-brand">
            <Share2 size={16} />
            <span className="text-[7px] font-black uppercase">Share</span>
          </button>
          <button onClick={(e) => { e.preventDefault(); navigate(`/chat/${listing.ownerId}?item=${listing.id}`); }} className="flex flex-col items-center gap-1 text-brand bg-brand/5 p-2 rounded-xl transition-all active:scale-90">
            <MessageCircle size={16} />
            <span className="text-[7px] font-black uppercase">Rent & Chat</span>
          </button>
        </div>

        <div className="mt-3 flex items-center justify-between text-[7px] font-black uppercase pt-2 opacity-50">
           <div className="flex items-center gap-1"><Eye size={10} /> {views} Views</div>
           <div className="text-brand flex items-center gap-1"><ShieldCheck size={10} /> AI VERIFIED</div>
        </div>
      </div>
    </div>
  );
};

