import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { Listing } from '../types';
import { MapPin, Share2, Heart, MessageCircle, ArrowLeft, Flag, Eye, ShieldCheck, Trash2, Clock, PlayCircle, MessageSquare } from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ItemDetailPageProps {
  lang: string;
  user?: any;
  listings: Listing[];
  onDelete?: (id: string) => void;
  onAddPoints: (a: number) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const ItemDetailPage: React.FC<ItemDetailPageProps> = ({ lang, user, listings, onDelete, onAddPoints, favorites, onToggleFavorite }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [showFullDesc, setShowFullDesc] = useState(false);

  const item = listings.find(l => l.id === id);
  if (!item) return <div className="p-20 text-center font-black">Item Not Found</div>;

  const isOwner = user?.id === item.ownerId;
  const isFavorite = favorites.includes(item.id);

  const handleReport = () => {
    alert(lang === 'ar' ? 'تم استلام بلاغك. نظام AI my rents سيعيد فحص المنتج فوراً.' : 'Report received. AI my rents will re-examine the product immediately.');
  };

  return (
    <div className="max-w-6xl mx-auto p-4 pt-10 pb-20 animate-in fade-in">
      <div className="flex items-center justify-between mb-8">
        <button onClick={() => navigate(-1)} className="p-4 bg-white dark:bg-gray-900 rounded-2xl shadow-xl dark:text-white">
          <ArrowLeft className={lang === 'ar' ? 'rotate-180' : ''} />
        </button>
        <div className="flex gap-2">
          {isOwner && <button onClick={() => {onDelete?.(id!); navigate('/')}} className="p-4 text-red-500 bg-red-50 dark:bg-red-900/20 rounded-2xl"><Trash2 size={20} /></button>}
          <button onClick={handleReport} className="p-4 text-gray-400 bg-gray-100 dark:bg-gray-800 rounded-2xl" title="Report"><Flag size={20} /></button>
          <button onClick={() => onToggleFavorite(item.id)} className={`p-4 rounded-2xl shadow-xl transition-all ${isFavorite ? 'bg-brand text-white' : 'bg-white dark:bg-gray-800 text-gray-400'}`}>
            <Heart size={20} fill={isFavorite ? 'currentColor' : 'none'} />
          </button>
          <button className="p-4 bg-brand text-white rounded-2xl shadow-2xl shadow-brand/30"><Share2 size={20} /></button>
        </div>
