        <button onClick={() => navigate(-1)} className="p-4 bg-white dark:bg-gray-800 rounded-2xl shadow-sm dark:text-white hover:scale-105 transition-transform">
          <ArrowLeft className={lang === 'ar' ? 'rotate-180' : ''} />
