      return;
    }

    const address = payoutType === CurrencyType.LOCAL ? user.payoutMethods?.paypal : user.payoutMethods?.[selectedCrypto];
    if (!address) {
      alert(lang === 'ar' ? `يرجى إدخال عنوان ${payoutType === CurrencyType.LOCAL ? 'PayPal' : selectedCrypto} في الإعدادات أولاً.` : `Please set your ${payoutType === CurrencyType.LOCAL ? 'PayPal' : selectedCrypto} address in settings.`);
      navigate('/settings');
      return;
    }

    setLoading(true);
    const moderation = await checkListingContent(title, description);
    if (moderation.status === 'REJECTED') {
      alert(moderation.reason);
      setLoading(false);
      return;
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: payoutType,
      payoutMethod: payoutType === CurrencyType.LOCAL ? 'PAYPAL' : 'CRYPTO',
      payoutAddress: address,
      cryptoCurrency: payoutType === CurrencyType.CRYPTO ? selectedCrypto : undefined,
      category,
      location: user.location,
      images,
      video: video || undefined,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: true,
      unavailableDates: [],
      status: 'PUBLISHED',
      visibility: 'PUBLIC',
      review_state: 'APPROVED',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(5);
    setLoading(false);
  };

  const handleVideoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) {
      // Use URL.createObjectURL for better performance with video files
      const videoUrl = URL.createObjectURL(f);
      setVideo(videoUrl);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach(f => {
      const r = new FileReader();
      r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
      r.readAsDataURL(f);
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-10 shadow-2xl border dark:border-gray-800">
      <div className="flex gap-2 mb-10">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand shadow-sm' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter">Media Assets</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">Images (2-5) & Optional Video</p>
          </div>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="aspect-square rounded-2xl overflow-hidden relative border shadow-sm">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 bg-red-500 text-white w-5 h-5 rounded-full text-[10px]">×</button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-2xl border-4 border-dashed border-gray-200 dark:border-gray-700 flex flex-col items-center justify-center text-gray-400 cursor-pointer hover:border-brand transition-all">
                <Camera size={24} />
                <span className="text-[8px] font-black uppercase mt-1">Photo</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={handleImageChange} />
              </label>
            )}

            {!video && (
              <label className={`aspect-square bg-gray-50 dark:bg-gray-800 rounded-2xl border-4 border-dashed border-gray-200 dark:border-gray-700 flex flex-col items-center justify-center text-gray-400 cursor-pointer hover:border-brand transition-all ${currentPlan === 'Starter Tier' ? 'opacity-50' : ''}`}>
                <Video size={24} />
                <div className="flex flex-col items-center">
                   <span className="text-[8px] font-black uppercase mt-1">Video</span>
                   {currentPlan === 'Starter Tier' && <span className="text-[6px] text-brand font-black">Pro Only</span>}
                </div>
                <input type="file" className="hidden" accept="video/*" onChange={handleVideoChange} />
              </label>
            )}
          </div>

          {video && (
            <div className="relative rounded-[2.5rem] overflow-hidden aspect-video border-4 border-brand/10 bg-black shadow-2xl animate-in zoom-in-95">
               <video src={video} className="w-full h-full" controls />
               <button onClick={() => setVideo(null)} className="absolute top-4 right-4 bg-brand text-white w-10 h-10 rounded-full shadow-lg flex items-center justify-center font-black">×</button>
            </div>
          )}

          <div className="p-4 bg-brand/5 rounded-2xl border border-brand/10 flex items-center gap-3">
             <AlertTriangle size={20} className="text-brand shrink-0" />
             <p className="text-[9px] font-bold text-gray-500 uppercase leading-relaxed">
                {lang === 'ar' ? 'ملاحظة: الفيديوهات تجذب مستأجرين أكثر بنسبة 40%. تأكد من جودة الإضاءة.' : 'Note: Videos attract 40% more renters. Ensure good lighting.'}
             </p>
          </div>

          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30 tracking-widest text-[10px] active:scale-95 transition-all">
             Continue to Details
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter text-center">Rental Info</h2>
          <input type="text" placeholder="Item Name*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none font-bold shadow-inner" />
          <textarea placeholder="Full Description*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl outline-none h-40 font-bold shadow-inner" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 bg-gray-50 dark:bg-gray-800 rounded-2xl font-bold appearance-none">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Set Pricing</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter text-center">Payout Logic</h2>

          <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-[2rem]">
            <button onClick={() => setPayoutType(CurrencyType.LOCAL)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>
              <CreditCard size={18} /> PayPal
            </button>
            <button onClick={() => setPayoutType(CurrencyType.CRYPTO)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>
              <Wallet size={18} /> Crypto
            </button>
          </div>

          {payoutType === CurrencyType.CRYPTO && (
            <div className="grid grid-cols-2 gap-2 animate-in slide-in-from-top-2">
              {cryptos.map(c => (
                <button key={c} onClick={() => setSelectedCrypto(c)} className={`p-3 rounded-xl border-2 font-black text-[9px] uppercase transition-all ${selectedCrypto === c ? 'border-brand bg-brand/5 text-brand' : 'border-gray-100 dark:border-gray-800 text-gray-400'}`}>
                  {c}
                </button>
              ))}
            </div>
          )}

          <div className="text-center pt-4">
            <div className="flex items-center justify-center gap-3">
              <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-4 border-brand text-4xl font-black text-center dark:text-white outline-none" placeholder="0" />
              <span className="text-xl font-black text-brand">{user.currencyPreference || 'USD'}</span>
            </div>
            <button onClick={async () => { setEstimating(true); const p = await estimateRentalPrice(title, description, user.currencyPreference); setPrice(p.toString()); setEstimating(false); }} className="mt-4 px-6 py-2 bg-brand/10 text-brand rounded-xl font-black text-[9px] uppercase flex items-center gap-2 mx-auto shadow-sm">
              {estimating ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />} AI Smart Price
            </button>
          </div>

          <div className="grid grid-cols-4 gap-2">
            {Object.values(RentalPeriod).map(p => (
              <button key={p} onClick={() => setPeriod(p)} className={`py-3 rounded-xl font-black text-[8px] uppercase ${period === p ? 'bg-brand text-white' : 'bg-gray-100 text-gray-400'}`}>{t.periods[p]}</button>
            ))}
          </div>

          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(4)} disabled={!price} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Review</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-brand/10 text-brand rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl animate-bounce">
             <ShieldCheck size={48} />
          </div>
          <h2 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter">AI Verification</h2>
          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border-2 border-dashed border-gray-200 text-left">
             <p className="text-[10px] font-bold text-gray-500 uppercase leading-relaxed mb-4">
               {lang === 'ar' ? 'يقوم نظام الذكاء الاصطناعي الآن بفحص المنتج للتأكد من أنه مخصص للتأجير فقط ولا يحتوي على مواد محظورة.' : 'The AI is currently scanning your listing to ensure it is rental-only and contains no prohibited items.'}
             </p>
             <div className="flex items-center gap-3 text-[10px] font-black text-brand uppercase">
                <CheckCircle2 size={16} /> End-to-End Encryption
             </div>
          </div>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 group tracking-widest text-[10px]">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles className="group-hover:rotate-12 transition-transform" />} Securely Launch
          </button>
