          <div className="grid grid-cols-4 gap-2">
            {Object.values(RentalPeriod).map(p => (
              <button key={p} onClick={() => setPeriod(p)} className={`py-3 rounded-xl font-black text-[8px] uppercase ${period === p ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-400'}`}>{t.periods[p]}</button>
            ))}
          </div>

          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(4)} disabled={!price} className="flex-[2] py-4 bg-red-500 text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Review</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-red-500/10 text-red-500 rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl animate-bounce">
             <ShieldCheck size={48} />
          </div>
          <h2 className="text-2xl font-black uppercase italic tracking-tighter">AI Verification</h2>
          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border-2 border-dashed border-gray-200 text-left">
