            onClick={handlePublish} 
            disabled={loading} 
            className="w-full py-6 bg-red-500 text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 group tracking-widest text-[10px] hover:scale-[1.02] active:scale-95 transition-all"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles className="group-hover:rotate-12 transition-transform" />} 
            {t.securelyLaunch}
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-16 animate-in fade-in">
           <div className="w-24 h-24 bg-green-500 text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl mb-8 rotate-3"><CheckCircle2 size={48} /></div>
           <h2 className="text-3xl font-black uppercase italic tracking-tighter">Rental Active!</h2>
           <p className="text-[10px] font-black uppercase tracking-widest mt-2">Verified & Securely Published</p>
           <button onClick={() => navigate('/')} className="mt-10 px-12 py-5 bg-red-500 text-white rounded-[2rem] font-black uppercase shadow-xl transition-all active:scale-95 tracking-widest text-[10px]">Back Home</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useEffect } from 'react';
