    files.forEach(f => {
      const r = new FileReader();
      r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
      r.readAsDataURL(f);
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-10 shadow-2xl border dark:border-gray-800">
      <div className="flex gap-2 mb-10">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-red-500' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-2xl font-black uppercase italic tracking-tighter">Media Assets</h2>
            <p className="text-[10px] font-bold uppercase tracking-widest mt-1">Images (2-5) & Optional Video</p>
          </div>
          <div className="grid grid-cols-3 gap-3">
