                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center shadow-lg"><X size={14} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-red-50 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-red-200 dark:border-gray-700 flex flex-col items-center justify-center text-red-500 cursor-pointer hover:bg-red-100 transition-all">
                <Camera size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Add Photo</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={handleImageChange} />
              </label>
