            {!video && (
              <label className={`aspect-square bg-red-50 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-red-200 dark:border-gray-700 flex flex-col items-center justify-center text-red-500 cursor-pointer hover:bg-red-100 transition-all ${currentPlan === 'Starter Tier' ? 'opacity-30 grayscale cursor-not-allowed' : ''}`}>
                <VideoIcon size={28} />
                <div className="flex flex-col items-center">
                   <span className="text-[8px] font-black uppercase mt-1">Add Video</span>
