          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30 tracking-widest text-[10px] active:scale-95 transition-all">
