           Upgrade My Plan Now
         </button>
      </div>
    );
  }

  const handlePublish = async () => {
    if (images.length < 2) { 
      alert(t.minImages); 
      return; 
    }

    if (video && currentPlan === 'Starter Tier') {
      alert(lang === 'ar' ? 'باقة المبتدئين لا تدعم نشر الفيديوهات. يرجى الترقية أو إزالة الفيديو.' : 'Starter Tier does not support video publishing. Please upgrade or remove the video.');
