import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// System Mode: private_beta
// Product Visibility: internal_only

export const checkListingContent = async (title: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Audit this item for INTERNAL BETA publish. Does it comply with our strict no-sale rental protocols? 
      Reply with 'APPROVED' if it's for rent only, or 'REJECTED' if it looks like a sale or illegal item.
      Title: ${title}
      Description: ${description}`,
      config: {
        systemInstruction: `You are the core controller for 'my rents' PRIVATE BETA. 
        Current Status: internal_only. 
        Rules: 
        1. Rental only (No selling allowed).
        2. Internal visibility for authenticated users only.
        3. No public indexing.
        Ensure title and description reflect a temporary rental agreement.`,
      }
    });
    const resultText = response.text || '';
    if (resultText.includes('APPROVED')) {
      return { status: 'APPROVED', product_status: 'active_internal' };
    } else {
      return { status: 'REJECTED', reason: resultText, product_status: 'pending_review' };
    }
  } catch (error) {
    return { status: 'APPROVED', product_status: 'active_internal' };
  }
};

export const estimateRentalPrice = async (title: string, description: string, currency: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate a fair DAILY rental price for this item in ${currency} for our private marketplace. Reply with ONLY the numeric value.
      Item: ${title}
      Details: ${description}`,
    });
    const text = response.text;
    const priceStr = text?.replace(/[^0-9.]/g, '') || "10";
    return parseFloat(priceStr);
  } catch (error) {
    return 10;
  }
};

export const getAISupportResponse = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: "You are the AI support for 'my rents' PRIVATE BETA. Assist authenticated users with rental protocols. Remind them that visibility is currently INTERNAL_ONLY and external sharing is restricted.",
      },
    });
    return response.text || "Support system is operating in internal mode.";
  } catch (error) {
    return "Internal support node busy. Please retry.";
  }
};

export const getDiscoveryInsights = async (location: string, query: string, lat?: number, lng?: number) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Find me internal items or places for rent near ${location} for ${query} within our private network.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: { 
            latLng: { 
              latitude: lat || 24.7136, 
              longitude: lng || 46.6753 
            } 
          }
        }
      }
    });
    return {
      text: response.text,
      links: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    return { text: "Search restricted to internal beta users.", links: [] };
  }
};

