import { Camera, Video as VideoIcon, ShieldCheck, Sparkles, Loader2, CreditCard, Wallet, CheckCircle2, AlertTriangle, Lock, X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const cryptos = Object.keys(WALLETS).map(k => k.toLowerCase());

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [payoutType, setPayoutType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [selectedCrypto, setSelectedCrypto] = useState<string>('solana');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);

  useEffect(() => {
    return () => {
      if (video && video.startsWith('blob:')) {
        URL.revokeObjectURL(video);
      }
    };
  }, [video]);

  const currentPlan = user.subscription?.tier || 'Starter Tier';
  const limit = currentPlan === 'Premium Tier' ? Infinity : (currentPlan === 'Standard Tier' ? 50 : 10);
  const currentCount = user.listingsCount || 0;

  if (currentCount >= limit) {
    return (
      <div className="max-w-2xl mx-auto p-12 bg-white dark:bg-gray-900 rounded-[3.5rem] my-20 shadow-2xl text-center border-4 border-dashed border-red-500/20">
         <div className="w-24 h-24 bg-red-500 text-white rounded-full flex items-center justify-center mx-auto mb-8 shadow-xl"><Lock size={48} /></div>
         <h2 className="text-3xl font-black uppercase italic tracking-tighter mb-4 text-red-600">{lang === 'ar' ? 'وصلت للحد الأقصى!' : 'Listing Limit Reached!'}</h2>
         <p className="text-sm font-bold uppercase tracking-widest mb-10 leading-relaxed px-10 text-red-500">
           {lang === 'ar' ? `باقة ${currentPlan} تتيح لك ${limit} منتجات نشطة فقط. يرجى الترقية لزيادة الحد.` : `Your ${currentPlan} allows only ${limit} active listings. Please upgrade to increase your limit.`}
         </p>
         <button onClick={() => navigate('/subscription')} className="w-full py-6 bg-red-500 text-white rounded-[2.5rem] font-black uppercase shadow-2xl shadow-red-500/40 active:scale-95 transition-all text-xs tracking-widest">
           Upgrade My Plan Now
         </button>
      </div>
    );
  }

  const handlePublish = async () => {
    if (images.length < 2) { 
      alert(t.minImages); 
      return; 
    }

    setLoading(true);

    // Core Override: Private Beta Implementation
    let aiStatus = 'active_internal';
    try {
      const moderation = await checkListingContent(title, description);
      if (moderation.status === 'REJECTED') {
        alert(moderation.reason);
        setLoading(false);
        return;
      }
      // @ts-ignore
      aiStatus = moderation.product_status || 'active_internal';
    } catch (e) {
      console.warn("AI Moderation signal weak, using default pending_review status");
      aiStatus = 'pending_review';
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: payoutType,
      payoutMethod: payoutType === CurrencyType.LOCAL ? 'PAYPAL' : 'CRYPTO',
      payoutAddress: (payoutType === CurrencyType.LOCAL ? user.payoutMethods?.paypal : user.payoutMethods?.[selectedCrypto]) || '',
      cryptoCurrency: payoutType === CurrencyType.CRYPTO ? selectedCrypto : undefined,
      category,
      location: user.location,
      images,
      video: video || undefined,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: aiStatus === 'active_internal',
      unavailableDates: [],
      // @ts-ignore
      status: aiStatus === 'active_internal' ? 'PUBLISHED' : 'AI_REVIEW',
      visibility: 'PRIVATE', // Private Beta: Internal only
      review_state: aiStatus === 'active_internal' ? 'APPROVED' : 'PENDING',
      published_at: aiStatus === 'active_internal' ? now : null,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(5);
    setLoading(false);
  };

  const handleVideoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) {
      if (video && video.startsWith('blob:')) URL.revokeObjectURL(video);
      const videoUrl = URL.createObjectURL(f);
      setVideo(videoUrl);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach(f => {
      const r = new FileReader();
      r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
      r.readAsDataURL(f);
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-10 shadow-2xl border dark:border-gray-800">
      <div className="flex gap-2 mb-10">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-red-500' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-2xl font-black uppercase italic tracking-tighter text-red-600">Beta Asset Intake</h2>
            <p className="text-[10px] font-bold uppercase tracking-widest mt-1 text-red-400">Internal visibility enabled</p>
          </div>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="aspect-square rounded-2xl overflow-hidden relative border-2 border-red-500/10 shadow-sm">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center shadow-lg"><X size={14} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-red-50 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-red-200 dark:border-gray-700 flex flex-col items-center justify-center text-red-500 cursor-pointer hover:bg-red-100 transition-all">
                <Camera size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Photo</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={handleImageChange} />
              </label>
            )}
            {!video && (
              <label className={`aspect-square bg-red-50 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-red-200 dark:border-gray-700 flex flex-col items-center justify-center text-red-500 cursor-pointer hover:bg-red-100 transition-all`}>
                <VideoIcon size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Video</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleVideoChange} />
              </label>
            )}
          </div>
          {video && (
            <div className="relative rounded-[2.5rem] overflow-hidden aspect-video border-4 border-red-500 bg-black shadow-2xl animate-in zoom-in-95">
               <video src={video} className="w-full h-full" controls />
               <button onClick={() => setVideo(null)} className="absolute top-4 right-4 bg-red-500 text-white w-10 h-10 rounded-full shadow-lg flex items-center justify-center font-black transition-transform hover:scale-110"><X size={20} /></button>
            </div>
          )}
          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30 tracking-widest text-[10px] active:scale-95 transition-all">
             Set Internal Details
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-center text-red-600">Rental Context</h2>
          <input type="text" placeholder="Item Name*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-5 bg-red-50/30 dark:bg-gray-800 rounded-2xl outline-none font-bold border-2 border-transparent focus:border-red-500" />
          <textarea placeholder="Full Description (Rental protocols required)*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-5 bg-red-50/30 dark:bg-gray-800 rounded-2xl outline-none h-40 font-bold border-2 border-transparent focus:border-red-500" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 bg-red-50/30 dark:bg-gray-800 rounded-2xl font-bold appearance-none cursor-pointer">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-4 bg-red-500 text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Pricing Logic</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-center text-red-600">Settlement</h2>
          <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-[2rem]">
            <button onClick={() => setPayoutType(CurrencyType.LOCAL)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.LOCAL ? 'bg-red-500 text-white shadow-lg' : 'text-gray-400'}`}>
              <CreditCard size={18} /> PayPal
            </button>
            <button onClick={() => setPayoutType(CurrencyType.CRYPTO)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.CRYPTO ? 'bg-red-500 text-white shadow-lg' : 'text-gray-400'}`}>
              <Wallet size={18} /> Crypto
            </button>
          </div>
          {payoutType === CurrencyType.CRYPTO && (
            <div className="grid grid-cols-2 gap-2">
              {cryptos.map(c => (
                <button key={c} onClick={() => setSelectedCrypto(c)} className={`p-3 rounded-xl border-2 font-black text-[9px] uppercase transition-all ${selectedCrypto === c ? 'border-red-500 bg-red-50 text-red-500' : 'border-gray-100 dark:border-gray-800 text-gray-400'}`}>{c}</button>
              ))}
            </div>
          )}
          <div className="text-center">
            <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-4 border-red-500 text-4xl font-black text-center outline-none text-red-500" placeholder="0" />
            <button onClick={async () => { setEstimating(true); const p = await estimateRentalPrice(title, description, user.currencyPreference); setPrice(p.toString()); setEstimating(false); }} className="mt-4 px-6 py-2 bg-red-500 text-white rounded-xl font-black text-[9px] uppercase flex items-center gap-2 mx-auto shadow-lg">
              {estimating ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />} AI Price
            </button>
          </div>
          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(4)} disabled={!price} className="flex-[2] py-4 bg-red-500 text-white rounded-2xl font-black shadow-xl uppercase text-[10px]">Audit Publish</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-red-500 text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl animate-bounce">
             <ShieldCheck size={48} />
          </div>
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-red-600">Beta Integrity Check</h2>
          <div className="p-6 bg-red-50 dark:bg-gray-800 rounded-[2.5rem] border-2 border-dashed border-red-200 text-left">
             <p className="text-[10px] font-black uppercase leading-relaxed text-red-600">
               Mode: private_beta. Item will be visible to internal users only. Public indexing and external sharing are disabled.
             </p>
          </div>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-red-500 text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 tracking-widest text-[10px] active:scale-95 transition-all">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} 
            Execute Internal Launch
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-16 animate-in fade-in">
           <div className="w-24 h-24 bg-red-500 text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl mb-8 rotate-3"><CheckCircle2 size={48} /></div>
           <h2 className="text-3xl font-black uppercase italic tracking-tighter text-red-600">Active Internal!</h2>
           <p className="text-[10px] font-black uppercase tracking-widest mt-2 text-red-400">Node Synchronized within Private Beta</p>
           <button onClick={() => navigate('/')} className="mt-10 px-12 py-5 bg-red-500 text-white rounded-[2rem] font-black uppercase shadow-xl transition-all active:scale-95 tracking-widest text-[10px]">Back to Feed</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useMemo } from 'react';
import { translations } from '../i18n';
import ListingCard from '../components/ListingCard';
import { Listing, CurrencyType } from '../types';
import { Box, Search, Package, Users, ShoppingCart, Sparkles, CheckCircle, Zap, Star, ArrowRight, ShieldCheck } from 'lucide-react';
import { PLANS } from '../constants';
import { useNavigate } from 'react-router-dom';

interface HomePageProps {
  lang: string;
  user: any;
  userListings: Listing[];
  onDeleteListing: (id: string) => void;
  onAddPoints: (a: number, reason: string) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const HomePage: React.FC<HomePageProps> = ({ lang, user, userListings, onDeleteListing, onAddPoints, favorites, onToggleFavorite }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [filterType, setFilterType] = useState<'ALL' | CurrencyType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  const filteredItems = useMemo(() => {
    return userListings
      .filter(item => {
        // Internal Beta Logic: Only show approved items or draft items owned by user
        const isInternalVisible = item.status === 'PUBLISHED' || item.ownerId === user?.id;
        if (!isInternalVisible || item.is_deleted) return false;

        const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesType = filterType === 'ALL' || item.currencyType === filterType;

        return matchesSearch && matchesType;
      })
      .sort((a, b) => {
        const timeA = a.published_at ? new Date(a.published_at).getTime() : 0;
        const timeB = b.published_at ? new Date(b.published_at).getTime() : 0;
        return timeB - timeA;
      });
  }, [searchQuery, filterType, userListings, user.id]);

  return (
    <div className="pb-24 pt-8 px-4 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="mb-12 flex flex-col md:flex-row justify-between items-end gap-6">
        <div>
          <div className="flex items-center gap-2 text-brand font-black uppercase text-[10px] tracking-[0.3em] mb-4">
            <ShieldCheck size={14} /> {lang === 'ar' ? 'وضع البيتا الخاصة' : 'Private Beta Mode'}
          </div>
          <h1 className="text-4xl md:text-5xl font-black dark:text-white uppercase tracking-tighter italic leading-none">
            {lang === 'ar' ? 'خلاصة الإيجارات' : 'Internal Rental'} <br/>
            <span className="text-brand">{lang === 'ar' ? 'الداخلية فقط' : 'Feed Only'}</span>
          </h1>
        </div>
        <div className="bg-red-500 text-white px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl">
          Platform Mode: private_beta
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4 mb-10">
        <div className="flex-1 relative">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text" 
            placeholder={t.searchPlaceholder} 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
            className="w-full pl-14 pr-6 py-5 bg-white dark:bg-gray-900 border-2 border-gray-100 dark:border-gray-800 rounded-[2rem] outline-none focus:border-brand font-bold shadow-sm" 
          />
        </div>
        <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-[2rem] w-fit">
          {['ALL', CurrencyType.CRYPTO, CurrencyType.LOCAL].map(f => (
            <button key={f} onClick={() => setFilterType(f as any)} className={`px-8 py-3 rounded-[1.8rem] text-[9px] font-black uppercase tracking-widest transition-all ${filterType === f ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>
              {f === 'ALL' ? (lang === 'ar' ? 'الكل' : 'All') : t[f.toLowerCase()]}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mb-24">
        {filteredItems.map(item => (
          <ListingCard 
            key={item.id} 
            listing={item} 
            lang={lang} 
            isOwner={item.ownerId === user?.id} 
            onDelete={onDeleteListing} 
            onAddPoints={(a) => onAddPoints(a, 'Listing Engagement')}
            isFavorite={favorites.includes(item.id)}
            onToggleFavorite={onToggleFavorite}
          />
        ))}
      </div>

      {filteredItems.length === 0 && (
        <div className="py-20 text-center mb-24">
          <Box size={80} className="mx-auto mb-6 text-gray-100 dark:text-gray-800" />
          <h3 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter">No internal assets found</h3>
          <p className="text-[10px] text-gray-400 mt-2 font-bold uppercase tracking-widest">Visibility restricted to authenticated beta users</p>
        </div>
      )}
    </div>
  );
};

export default HomePage;

import React, { useState, useMemo } from 'react';
import { translations } from '../i18n';
import ListingCard from '../components/ListingCard';
import { Listing, CurrencyType } from '../types';
import { Box, Search, ShieldCheck } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface HomePageProps {
  lang: string;
  user: any;
  userListings: Listing[];
  onDeleteListing: (id: string) => void;
  onAddPoints: (a: number, reason: string) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const HomePage: React.FC<HomePageProps> = ({ lang, user, userListings, onDeleteListing, onAddPoints, favorites, onToggleFavorite }) => {
  const t = translations[lang] || translations['en'];
  const [filterType, setFilterType] = useState<'ALL' | CurrencyType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  const filteredItems = useMemo(() => {
    return userListings
      .filter(item => {
        // Private Beta Logic: Show Published items OR items owned by user (even if pending)
        // Ensure we check for both 'PUBLISHED' and 'active_internal'
        const isPublished = item.status === 'PUBLISHED' || (item as any).product_status === 'active_internal';
        const isOwner = item.ownerId === user?.id;

        if (!(isPublished || isOwner) || item.is_deleted) return false;

        const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                             item.description.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesType = filterType === 'ALL' || item.currencyType === filterType;

        return matchesSearch && matchesType;
      })
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [searchQuery, filterType, userListings, user?.id]);

  return (
    <div className="pb-24 pt-8 px-4 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="mb-12 flex flex-col md:flex-row justify-between items-end gap-6">
        <div>
          <div className="flex items-center gap-2 text-brand font-black uppercase text-[10px] tracking-[0.3em] mb-4">
            <ShieldCheck size={14} /> {lang === 'ar' ? 'خلاصة الإصدار التجريبي الخاص' : 'PRIVATE BETA INTERNAL FEED'}
          </div>
          <h1 className="text-4xl md:text-5xl font-black dark:text-white uppercase tracking-tighter italic leading-none">
            {lang === 'ar' ? 'سوق الإيجارات' : 'RENTAL'} <br/>
            <span className="text-brand">{lang === 'ar' ? 'الداخلي' : 'MARKETPLACE'}</span>
          </h1>
        </div>
        <div className="bg-brand text-white px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-brand/20">
          MODE: INTERNAL_ONLY
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4 mb-10">
        <div className="flex-1 relative">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-brand/40" size={20} />
          <input 
            type="text" 
            placeholder={t.searchPlaceholder} 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
            className="w-full pl-14 pr-6 py-5 bg-brand/5 dark:bg-gray-900 border-2 border-transparent focus:border-brand rounded-[2rem] outline-none font-bold shadow-sm transition-all" 
          />
        </div>
        <div className="flex gap-2 p-1 bg-brand/5 dark:bg-gray-800 rounded-[2rem] w-fit">
          {['ALL', CurrencyType.CRYPTO, CurrencyType.LOCAL].map(f => (
            <button key={f} onClick={() => setFilterType(f as any)} className={`px-8 py-3 rounded-[1.8rem] text-[9px] font-black uppercase tracking-widest transition-all ${filterType === f ? 'bg-brand text-white shadow-lg' : 'text-brand/60'}`}>
              {f === 'ALL' ? (lang === 'ar' ? 'الكل' : 'All') : t[f.toLowerCase()]}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mb-24">
        {filteredItems.map(item => (
          <ListingCard 
            key={item.id} 
            listing={item} 
            lang={lang} 
            isOwner={item.ownerId === user?.id} 
            onDelete={onDeleteListing} 
            onAddPoints={(a) => onAddPoints(a, 'Listing Interaction')}
            isFavorite={favorites.includes(item.id)}
            onToggleFavorite={onToggleFavorite}
          />
        ))}
      </div>

      {filteredItems.length === 0 && (
        <div className="py-32 text-center mb-24 bg-brand/5 rounded-[4rem] border-2 border-dashed border-brand/10">
          <Box size={80} className="mx-auto mb-6 text-brand/20" />
          <h3 className="text-2xl font-black dark:text-white uppercase italic tracking-tighter">{lang === 'ar' ? 'لا توجد منتجات منشورة' : 'NO INTERNAL ASSETS'}</h3>
          <p className="text-[10px] text-brand/40 mt-2 font-bold uppercase tracking-widest">Visibility is limited to private beta members</p>
        </div>
      )}
    </div>
  );
};

export default HomePage;

import React, { useState } from 'react';
import { Heart, MapPin, Eye, Share2, MessageCircle, Trash2, ShieldCheck, PlayCircle, MessageSquare, Check } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { POINTS_SYSTEM } from '../constants';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
  onAddPoints?: (a: number) => void;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete, onAddPoints, isFavorite, onToggleFavorite }) => {
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [copied, setCopied] = useState(false);

  const [views, setViews] = useState(() => {
    const key = `views_${listing.id}`;
    return parseInt(localStorage.getItem(key) || '0') + listing.views;
  });

  const incrementViews = () => {
    const key = `views_${listing.id}`;
    const newViews = views + 1;
    setViews(newViews);
    localStorage.setItem(key, newViews.toString());
  };

  const handleFavorite = (e: React.MouseEvent) => {
    e.stopPropagation(); e.preventDefault();
    onToggleFavorite?.(listing.id);
    if (!isFavorite) onAddPoints?.(POINTS_SYSTEM.LIKE);
  };

  const handleShare = (e: React.MouseEvent) => {
    e.stopPropagation(); e.preventDefault();
    const shareUrl = `${window.location.origin}/#/item/${listing.id}`;
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    onAddPoints?.(POINTS_SYSTEM.SHARE);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all border border-brand/5 dark:border-gray-800 flex flex-col h-full group">
      {/* Header with User Info */}
      <div className="p-4 flex items-center justify-between border-b border-brand/5 dark:border-gray-800">
        <div className="flex items-center gap-2">
          <img src={listing.ownerAvatar} className="w-9 h-9 rounded-full border-2 border-brand/20 object-cover" />
          <div className="flex flex-col">
            <span className="text-[10px] font-black dark:text-white uppercase leading-none">{listing.ownerName}</span>
            <span className="text-[9px] font-bold text-brand/40">@{listing.ownerUsername}</span>
          </div>
        </div>
        <div className="flex gap-1">
          <button onClick={handleFavorite} className={`p-2 rounded-xl transition-all ${isFavorite ? 'text-white bg-brand shadow-lg' : 'text-brand/40 hover:text-brand bg-brand/5'}`}>
             <Heart size={14} fill={isFavorite ? 'currentColor' : 'none'} />
          </button>
          {isOwner && (
            <button onClick={() => onDelete?.(listing.id)} className="p-2 text-brand bg-brand/5 rounded-xl hover:bg-brand hover:text-white transition-all">
              <Trash2 size={14} />
            </button>
          )}
        </div>
      </div>

      <Link to={`/item/${listing.id}`} onClick={incrementViews} className="block px-3 pt-3">
        <div className="aspect-square overflow-hidden rounded-[2rem] relative bg-brand/5">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
          {listing.video && <div className="absolute top-4 left-4 bg-brand text-white p-2 rounded-xl shadow-lg"><PlayCircle size={16} /></div>}
          <div className="absolute bottom-4 right-4 bg-white/95 dark:bg-gray-900/95 px-4 py-2 rounded-2xl shadow-xl flex flex-col items-center border border-brand/10">
             <span className="text-xs font-black text-brand italic tracking-tighter">{listing.price} {listing.currency}</span>
             <span className="text-[6px] font-black text-brand/40 uppercase">{t.periods[listing.rentalPeriod]}</span>
          </div>
        </div>
      </Link>

      <div className="p-5 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-1">
          <h3 className="font-black dark:text-white uppercase text-xs truncate max-w-[140px] tracking-tighter italic">{listing.title}</h3>
          <span className="text-[7px] font-black text-brand bg-brand/5 px-2 py-1 rounded-lg uppercase">{listing.category}</span>
        </div>

        <div className="flex items-center gap-1 text-brand/40 text-[8px] font-black uppercase mb-4">
          <MapPin size={10} className="text-brand" /> {listing.location.city}, {listing.location.district}
        </div>

        <div className="mt-auto grid grid-cols-3 gap-2 pt-4 border-t border-brand/5 dark:border-gray-800">
          <button onClick={(e) => {e.preventDefault(); e.stopPropagation();}} className="flex flex-col items-center gap-1 text-brand/40 hover:text-brand transition-colors">
            <MessageSquare size={16} />
            <span className="text-[7px] font-black uppercase">Comments</span>
          </button>
          <button onClick={handleShare} className={`flex flex-col items-center gap-1 transition-all ${copied ? 'text-green-500' : 'text-brand/40 hover:text-brand'}`}>
            {copied ? <Check size={16} /> : <Share2 size={16} />}
            <span className="text-[7px] font-black uppercase">{copied ? 'Copied' : 'Share'}</span>
          </button>
          <button onClick={(e) => { e.preventDefault(); navigate(`/chat/${listing.ownerId}?item=${listing.id}`); }} className="flex flex-col items-center gap-1 text-white bg-brand p-2 rounded-xl transition-all active:scale-90 shadow-lg shadow-brand/20">
            <MessageCircle size={16} />
            <span className="text-[7px] font-black uppercase">Rent & Chat</span>
          </button>
        </div>

        <div className="mt-3 flex items-center justify-between text-[7px] font-black uppercase pt-2 opacity-50">
           <div className="flex items-center gap-1 text-brand"><Eye size={10} /> {views} Views</div>
           <div className="text-brand flex items-center gap-1"><ShieldCheck size={10} /> AI VERIFIED</div>
        </div>
      </div>
    </div>
  );
};

export default ListingCard;

import React, { useState, useEffect } from 'react';
import { translations } from '../i18n';
import { CATEGORIES, WALLETS } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent, estimateRentalPrice } from '../services/geminiService';
import { Camera, Video as VideoIcon, ShieldCheck, Sparkles, Loader2, CreditCard, Wallet, CheckCircle2, AlertTriangle, Lock, X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const cryptos = Object.keys(WALLETS).map(k => k.toLowerCase());

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [payoutType, setPayoutType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [selectedCrypto, setSelectedCrypto] = useState<string>('solana');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);

  useEffect(() => {
    return () => {
      if (video && video.startsWith('blob:')) {
        URL.revokeObjectURL(video);
      }
    };
  }, [video]);

  const currentPlan = user.subscription?.tier || 'Starter Tier';
  const limit = currentPlan === 'Premium Tier' ? Infinity : (currentPlan === 'Standard Tier' ? 50 : 10);
  const currentCount = user.listingsCount || 0;

  if (currentCount >= limit) {
    return (
      <div className="max-w-2xl mx-auto p-12 bg-white dark:bg-gray-900 rounded-[3.5rem] my-20 shadow-2xl text-center border-4 border-dashed border-brand/20">
         <div className="w-24 h-24 bg-brand text-white rounded-full flex items-center justify-center mx-auto mb-8 shadow-xl"><Lock size={48} /></div>
         <h2 className="text-3xl font-black uppercase italic tracking-tighter mb-4 text-brand">{lang === 'ar' ? 'وصلت للحد الأقصى!' : 'Listing Limit Reached!'}</h2>
         <p className="text-sm font-bold uppercase tracking-widest mb-10 leading-relaxed px-10 text-brand/60">
           {lang === 'ar' ? `باقة ${currentPlan} تتيح لك ${limit} منتجات نشطة فقط.` : `Your ${currentPlan} allows only ${limit} active listings.`}
         </p>
         <button onClick={() => navigate('/subscription')} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl shadow-brand/40 active:scale-95 transition-all text-xs tracking-widest">
           Upgrade Plan
         </button>
      </div>
    );
  }

  const handlePublish = async () => {
    if (images.length < 2) { 
      alert(t.minImages); 
      return; 
    }

    setLoading(true);

    // Core Override: Private Beta Implementation
    let aiStatus = 'active_internal';
    try {
      const moderation = await checkListingContent(title, description);
      if (moderation.status === 'REJECTED') {
        alert(moderation.reason);
        setLoading(false);
        return;
      }
      aiStatus = moderation.product_status || 'active_internal';
    } catch (e) {
      aiStatus = 'pending_review';
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: payoutType,
      payoutMethod: payoutType === CurrencyType.LOCAL ? 'PAYPAL' : 'CRYPTO',
      payoutAddress: (payoutType === CurrencyType.LOCAL ? user.payoutMethods?.paypal : user.payoutMethods?.[selectedCrypto]) || '',
      cryptoCurrency: payoutType === CurrencyType.CRYPTO ? selectedCrypto : undefined,
      category,
      location: user.location,
      images,
      video: video || undefined,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: aiStatus === 'active_internal',
      unavailableDates: [],
      // Ensure status is PUBLISHED to appear in HomePage
      status: aiStatus === 'active_internal' ? 'PUBLISHED' : 'AI_REVIEW',
      visibility: 'PRIVATE', 
      review_state: aiStatus === 'active_internal' ? 'APPROVED' : 'PENDING',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(5);
    setLoading(false);
  };

  const handleVideoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) {
      if (video && video.startsWith('blob:')) URL.revokeObjectURL(video);
      const videoUrl = URL.createObjectURL(f);
      setVideo(videoUrl);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach(f => {
      const r = new FileReader();
      r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
      r.readAsDataURL(f);
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-10 shadow-2xl border border-brand/5 dark:border-gray-800">
      <div className="flex gap-2 mb-10">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-brand/10 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-2xl font-black uppercase italic tracking-tighter text-brand">Beta Asset Intake</h2>
            <p className="text-[10px] font-bold uppercase tracking-widest mt-1 text-brand/40">Internal visibility enabled</p>
          </div>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="aspect-square rounded-2xl overflow-hidden relative border-2 border-brand/10 shadow-sm">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 bg-brand text-white w-6 h-6 rounded-full flex items-center justify-center shadow-lg"><X size={14} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-brand/5 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-brand/20 flex flex-col items-center justify-center text-brand cursor-pointer hover:bg-brand/10 transition-all">
                <Camera size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Photo</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={handleImageChange} />
              </label>
            )}
            {!video && (
              <label className={`aspect-square bg-brand/5 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-brand/20 flex flex-col items-center justify-center text-brand cursor-pointer hover:bg-brand/10 transition-all`}>
                <VideoIcon size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Video</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleVideoChange} />
              </label>
            )}
          </div>
          {video && (
            <div className="relative rounded-[2.5rem] overflow-hidden aspect-video border-4 border-brand bg-black shadow-2xl animate-in zoom-in-95">
               <video src={video} className="w-full h-full" controls />
               <button onClick={() => setVideo(null)} className="absolute top-4 right-4 bg-brand text-white w-10 h-10 rounded-full shadow-lg flex items-center justify-center font-black transition-transform hover:scale-110"><X size={20} /></button>
            </div>
          )}
          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30 tracking-widest text-[10px] active:scale-95 transition-all shadow-brand/20">
             Set Internal Details
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-center text-brand">Rental Context</h2>
          <input type="text" placeholder="Item Name*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-5 bg-brand/5 dark:bg-gray-800 rounded-2xl outline-none font-bold border-2 border-transparent focus:border-brand" />
          <textarea placeholder="Full Description (Rental protocols required)*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-5 bg-brand/5 dark:bg-gray-800 rounded-2xl outline-none h-40 font-bold border-2 border-transparent focus:border-brand" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 bg-brand/5 dark:bg-gray-800 rounded-2xl font-bold appearance-none cursor-pointer">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-4 bg-brand/5 text-brand rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px] shadow-brand/20">Pricing Logic</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-center text-brand">Settlement</h2>
          <div className="flex gap-2 p-1 bg-brand/5 dark:bg-gray-800 rounded-[2rem]">
            <button onClick={() => setPayoutType(CurrencyType.LOCAL)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.LOCAL ? 'bg-brand text-white shadow-lg' : 'text-brand/40'}`}>
              <CreditCard size={18} /> PayPal
            </button>
            <button onClick={() => setPayoutType(CurrencyType.CRYPTO)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.CRYPTO ? 'bg-brand text-white shadow-lg' : 'text-brand/40'}`}>
              <Wallet size={18} /> Crypto
            </button>
          </div>
          {payoutType === CurrencyType.CRYPTO && (
            <div className="grid grid-cols-2 gap-2">
              {cryptos.map(c => (
                <button key={c} onClick={() => setSelectedCrypto(c)} className={`p-3 rounded-xl border-2 font-black text-[9px] uppercase transition-all ${selectedCrypto === c ? 'border-brand bg-brand/10 text-brand' : 'border-transparent bg-brand/5 text-brand/40'}`}>{c}</button>
              ))}
            </div>
          )}
          <div className="text-center">
            <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-4 border-brand text-4xl font-black text-center outline-none text-brand" placeholder="0" />
            <button onClick={async () => { setEstimating(true); const p = await estimateRentalPrice(title, description, user.currencyPreference); setPrice(p.toString()); setEstimating(false); }} className="mt-4 px-6 py-2 bg-brand text-white rounded-xl font-black text-[9px] uppercase flex items-center gap-2 mx-auto shadow-lg shadow-brand/20">
              {estimating ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />} AI Price
            </button>
          </div>
          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-brand/5 text-brand rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(4)} disabled={!price} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px] shadow-brand/20">Audit Publish</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-brand text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl animate-bounce">
             <ShieldCheck size={48} />
          </div>
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-brand">Beta Integrity Check</h2>
          <div className="p-6 bg-brand/5 dark:bg-gray-800 rounded-[2.5rem] border-2 border-dashed border-brand/20 text-left">
             <p className="text-[10px] font-black uppercase leading-relaxed text-brand">
               Mode: private_beta. Item will be visible to internal users only. Public indexing and external sharing are disabled.
             </p>
          </div>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 tracking-widest text-[10px] active:scale-95 transition-all shadow-brand/20">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} 
            Execute Internal Launch
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-16 animate-in fade-in">
           <div className="w-24 h-24 bg-brand text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl mb-8 rotate-3"><CheckCircle2 size={48} /></div>
           <h2 className="text-3xl font-black uppercase italic tracking-tighter text-brand">Active Internal!</h2>
           <p className="text-[10px] font-black uppercase tracking-widest mt-2 text-brand/40">Node Synchronized within Private Beta</p>
           <button onClick={() => navigate('/')} className="mt-10 px-12 py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl transition-all active:scale-95 tracking-widest text-[10px]">Back to Feed</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState } from 'react';
import { Heart, MapPin, Eye, Share2, MessageCircle, Trash2, ShieldCheck, PlayCircle, MessageSquare, Check } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { POINTS_SYSTEM } from '../constants';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
  onAddPoints?: (a: number) => void;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete, onAddPoints, isFavorite, onToggleFavorite }) => {
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [copied, setCopied] = useState(false);

  const [views, setViews] = useState(() => {
    const key = `views_${listing.id}`;
    return parseInt(localStorage.getItem(key) || '0') + listing.views;
  });

  const incrementViews = () => {
    const key = `views_${listing.id}`;
    const newViews = views + 1;
    setViews(newViews);
    localStorage.setItem(key, newViews.toString());
  };

  const handleFavorite = (e: React.MouseEvent) => {
    e.stopPropagation(); e.preventDefault();
    onToggleFavorite?.(listing.id);
    if (!isFavorite) onAddPoints?.(POINTS_SYSTEM.LIKE);
  };

  const handleShare = (e: React.MouseEvent) => {
    e.stopPropagation(); e.preventDefault();
    const shareUrl = `${window.location.origin}/#/item/${listing.id}`;
    if (navigator.share) {
      navigator.share({ title: listing.title, url: shareUrl }).catch(() => {
        navigator.clipboard.writeText(shareUrl);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      });
    } else {
      navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
    onAddPoints?.(POINTS_SYSTEM.SHARE);
  };

  const handleCommentsClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    navigate(`/item/${listing.id}`);
    // Scroll logic or simple alert for beta
    setTimeout(() => alert(lang === 'ar' ? 'السجل العام قيد المزامنة...' : 'Public Ledger syncing...'), 500);
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all border border-brand/5 dark:border-gray-800 flex flex-col h-full group">
      {/* Header with User Info */}
      <div className="p-4 flex items-center justify-between border-b border-brand/5 dark:border-gray-800">
        <div className="flex items-center gap-2">
          <img src={listing.ownerAvatar} className="w-9 h-9 rounded-full border-2 border-brand/20 object-cover" />
          <div className="flex flex-col">
            <span className="text-[10px] font-black dark:text-white uppercase leading-none">{listing.ownerName}</span>
            <span className="text-[9px] font-bold text-brand/40">@{listing.ownerUsername}</span>
          </div>
        </div>
        <div className="flex gap-1">
          <button onClick={handleFavorite} className={`p-2 rounded-xl transition-all ${isFavorite ? 'text-white bg-brand shadow-lg' : 'text-brand/40 hover:text-brand bg-brand/5'}`}>
             <Heart size={14} fill={isFavorite ? 'currentColor' : 'none'} />
          </button>
          {isOwner && (
            <button onClick={(e) => { e.preventDefault(); onDelete?.(listing.id); }} className="p-2 text-brand bg-brand/5 rounded-xl hover:bg-brand hover:text-white transition-all">
              <Trash2 size={14} />
            </button>
          )}
        </div>
      </div>

      <Link to={`/item/${listing.id}`} onClick={incrementViews} className="block px-3 pt-3">
        <div className="aspect-square overflow-hidden rounded-[2rem] relative bg-brand/5">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
