      isAiApproved: aiStatus === 'active_internal',
      unavailableDates: [],
      // Ensure status is PUBLISHED to appear in HomePage
      status: aiStatus === 'active_internal' ? 'PUBLISHED' : 'AI_REVIEW',
      visibility: 'PRIVATE', 
      review_state: aiStatus === 'active_internal' ? 'APPROVED' : 'PENDING',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(5);
    setLoading(false);
  };

  const handleVideoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) {
      if (video && video.startsWith('blob:')) URL.revokeObjectURL(video);
      const videoUrl = URL.createObjectURL(f);
      setVideo(videoUrl);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach(f => {
      const r = new FileReader();
      r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
      r.readAsDataURL(f);
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-10 shadow-2xl border border-brand/5 dark:border-gray-800">
      <div className="flex gap-2 mb-10">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-brand/10 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-2xl font-black uppercase italic tracking-tighter text-brand">Asset Intake</h2>
            <p className="text-[10px] font-bold uppercase tracking-widest mt-1 text-brand/40">Internal visibility enabled</p>
          </div>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="aspect-square rounded-2xl overflow-hidden relative border-2 border-brand/10 shadow-sm">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 bg-brand text-white w-6 h-6 rounded-full flex items-center justify-center shadow-lg"><X size={14} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square bg-brand/5 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-brand/20 flex flex-col items-center justify-center text-brand cursor-pointer hover:bg-brand/10 transition-all">
                <Camera size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Photo</span>
                <input type="file" multiple className="hidden" accept="image/*" onChange={handleImageChange} />
              </label>
            )}
            {!video && (
              <label className={`aspect-square bg-brand/5 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-brand/20 flex flex-col items-center justify-center text-brand cursor-pointer hover:bg-brand/10 transition-all`}>
                <VideoIcon size={28} />
                <span className="text-[8px] font-black uppercase mt-1">Video</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleVideoChange} />
              </label>
            )}
          </div>
          {video && (
            <div className="relative rounded-[2.5rem] overflow-hidden aspect-video border-4 border-brand bg-black shadow-2xl animate-in zoom-in-95">
               <video src={video} className="w-full h-full" controls />
               <button onClick={() => setVideo(null)} className="absolute top-4 right-4 bg-brand text-white w-10 h-10 rounded-full shadow-lg flex items-center justify-center font-black transition-transform hover:scale-110"><X size={20} /></button>
            </div>
          )}
          <button onClick={() => setStep(2)} disabled={images.length < 2} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl disabled:opacity-30 tracking-widest text-[10px] active:scale-95 transition-all shadow-brand/20">
             Set Internal Details
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-center text-brand">Rental Context</h2>
          <input type="text" placeholder="Item Name*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-5 bg-brand/5 dark:bg-gray-800 rounded-2xl outline-none font-bold border-2 border-transparent focus:border-brand" />
          <textarea placeholder="Full Description (Rental protocols required)*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-5 bg-brand/5 dark:bg-gray-800 rounded-2xl outline-none h-40 font-bold border-2 border-transparent focus:border-brand" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 bg-brand/5 dark:bg-gray-800 rounded-2xl font-bold appearance-none cursor-pointer">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-4 bg-brand/5 text-brand rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(3)} disabled={!title || !description} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px] shadow-brand/20">Pricing Logic</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-center text-brand">Settlement</h2>
          <div className="flex gap-2 p-1 bg-brand/5 dark:bg-gray-800 rounded-[2rem]">
