            <button onClick={() => setPayoutType(CurrencyType.CRYPTO)} className={`flex-1 py-4 rounded-[1.8rem] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${payoutType === CurrencyType.CRYPTO ? 'bg-brand text-white shadow-lg' : 'text-brand/40'}`}>
