            <div className="grid grid-cols-2 gap-2">
              {cryptos.map(c => (
                <button key={c} onClick={() => setSelectedCrypto(c)} className={`p-3 rounded-xl border-2 font-black text-[9px] uppercase transition-all ${selectedCrypto === c ? 'border-brand bg-brand/10 text-brand' : 'border-transparent bg-brand/5 text-brand/40'}`}>{c}</button>
              ))}
            </div>
          )}
          <div className="text-center">
            <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-4 border-brand text-4xl font-black text-center outline-none text-brand" placeholder="0" />
            <button onClick={async () => { setEstimating(true); const p = await estimateRentalPrice(title, description, user.currencyPreference); setPrice(p.toString()); setEstimating(false); }} className="mt-4 px-6 py-2 bg-brand text-white rounded-xl font-black text-[9px] uppercase flex items-center gap-2 mx-auto shadow-lg shadow-brand/20">
              {estimating ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />} AI Price
            </button>
          </div>
          <div className="flex gap-4">
            <button onClick={() => setStep(2)} className="flex-1 py-4 bg-brand/5 text-brand rounded-2xl font-black uppercase text-[10px]">Back</button>
            <button onClick={() => setStep(4)} disabled={!price} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black shadow-xl uppercase text-[10px] shadow-brand/20">Audit Publish</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <div className="w-24 h-24 bg-brand text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl animate-bounce">
             <ShieldCheck size={48} />
          </div>
          <h2 className="text-2xl font-black uppercase italic tracking-tighter text-brand">Security Integrity Check</h2>
          <div className="p-6 bg-brand/5 dark:bg-gray-800 rounded-[2.5rem] border-2 border-dashed border-brand/20 text-left">
             <p className="text-[10px] font-black uppercase leading-relaxed text-brand">
               Mode: private_access. Item will be visible to internal network users only. Public indexing and external sharing are disabled.
             </p>
          </div>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-2xl flex items-center justify-center gap-3 tracking-widest text-[10px] active:scale-95 transition-all shadow-brand/20">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} 
            Execute Secure Launch
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-16 animate-in fade-in">
           <div className="w-24 h-24 bg-brand text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl mb-8 rotate-3"><CheckCircle2 size={48} /></div>
           <h2 className="text-3xl font-black uppercase italic tracking-tighter text-brand">Active Internal!</h2>
           <p className="text-[10px] font-black uppercase tracking-widest mt-2 text-brand/40">Node Synchronized within Private Network</p>
           <button onClick={() => navigate('/')} className="mt-10 px-12 py-5 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl transition-all active:scale-95 tracking-widest text-[10px]">Back to Feed</button>
        </div>
      )}
    </div>
  );
};

